/* =============================================================
 * 全球能源项目世界地图 —— 英文正文（双语详情卡）
 * -------------------------------------------------------------
 * window.ENERGY_EN = { <id>: { descEn, detailEn } }，由 util.buildProjects 按 id 合并进项目，
 * 仅在源数据未内联 descEn/detailEn 时填充（与 progress.js 的按 id 合并同一模式）。
 * 这样英文翻译与源数据分离、互不污染，可分批增量补全（再加 i18n-en2.js 等并用 Object.assign 续接即可）。
 * EN 模式下详情卡正文走 descBody → detailEn || descEn；本文件主供 detailEn（卡片正文）。
 *
 * 批次 1：js/data.js 核心地标项目（id 1–87，墨脱/Stargate/北方气田/Simandou 等）。
 * 翻译为中文 detail 的对应英文，力求与既有内联英文（id 1/14/17）同一简洁事实风格。
 * 注：id 1/14/17 已在 data.js 内联英文，合并时不覆盖，故此处不重复收录。
 * ============================================================= */
window.ENERGY_EN = Object.assign(window.ENERGY_EN || {}, {
  /* ===== 可再生能源发电 ===== */
  7: { descEn: "A deep-water offshore wind cluster off Guangdong.", detailEn: "Off the coast of Yangjiang in Guangdong, the Qingzhou cluster is a flagship of China's large-scale deep-water offshore wind development, with sections progressively approved, started and grid-connected toward a planned ~7 GW total. It uses large-megawatt turbines with flexible HVDC export and pilots an integrated \"offshore wind + marine ranching + hydrogen\" model." },
  8: { descEn: "Planned to be the world's largest offshore wind base.", detailEn: "Chaozhou in Guangdong plans an ~43.3 GW mega offshore wind base in the wind-rich waters west of the Taiwan Strait; if realised it would be the world's largest offshore wind project. The strait's \"funnel effect\" yields world-class wind resources, though deep-water construction, long-distance transmission and ecological coordination remain key challenges." },
  12: { descEn: "One of the world's largest CSP complexes.", detailEn: "On the edge of the Sahara near Ouarzazate, Morocco, this concentrated-solar-power complex combines parabolic-trough and tower units totalling ~580 MW with molten-salt storage, letting it keep supplying power for several hours after sunset. A benchmark for African clean energy, it has sharply cut Morocco's dependence on imported fossil fuels." },
  13: { descEn: "One of Africa's largest solar parks.", detailEn: "In Benban, Aswan Governorate, Egypt, this park comprises about 40 separate plants totalling ~1.65 GW, making it one of Africa's largest solar parks. Built with support from the World Bank and other multilateral lenders, it drew global developers, markedly boosted Egypt's power supply and created local jobs." },
  15: { descEn: "A large solar-plus-storage project in Nevada.", detailEn: "On federal land northeast of Las Vegas, Nevada, Gemini pairs 690 MW of solar with 380 MW/1.4 GWh of battery storage, fully commissioned in 2024. One of the largest solar-plus-storage projects in the US at the time, it supplies clean power to the Las Vegas metro area and provides night-time output support." },
  16: { descEn: "The first commercial-scale US offshore wind farm.", detailEn: "South of Martha's Vineyard, Massachusetts, the 806 MW Vineyard Wind 1 is the first commercial-scale offshore wind farm in the US, built by Avangrid and Copenhagen Infrastructure Partners (CIP). Generating since late 2023 and connecting in stages, it powers about 400,000 New England homes and marks the launch of the US offshore wind industry." },

  /* ===== 输变电 · 电网 ===== */
  21: { descEn: "A new UHV corridor energised in June 2025.", detailEn: "Running ~2,260 km from Barkol in Hami, Xinjiang to Chongqing at ±800 kV with 8 GW capacity, this UHVDC line was energised on 10 June 2025. It bundles Xinjiang's desert wind, solar and thermal power for export to the southwest, delivering ~36 TWh a year to Chongqing — a landmark artery for large-scale renewable export from China's northwest." },
  22: { descEn: "A new west-to-east power corridor commissioning in 2026.", detailEn: "This ±800 kV, 8 GW UHVDC line carries power from Gansu to Zhejiang, with key converter equipment supplied by Hitachi Energy and others, targeting commissioning in 2026. Once online it will deliver about 36 TWh a year to Zhejiang — a high share of it renewable — easing the power shortfall in the Yangtze River Delta load centre." },
  23: { descEn: "Ningxia renewables exported to Hunan.", detailEn: "The \"Ningxia-to-Hunan\" UHVDC link runs ~1,600 km from Zhongwei in Ningxia to Hengyang in Hunan at 8 GW, the first UHV corridor in China designed primarily to carry renewable power, paired with large wind and solar bases in the Tengger Desert. It will deliver about 36 TWh a year to Hunan, more than half of it renewable." },
  29: { descEn: "The world's longest land-and-subsea HVDC interconnector.", detailEn: "Linking Lincolnshire in the UK with western Denmark, the ~765 km, 1.4 GW Viking Link is the world's longest combined onshore-and-subsea HVDC interconnector, commissioned in 2024. It lets UK wind power trade with Danish and Nordic hydro and wind, boosting the flexibility and security of both grids." },
  31: { descEn: "The largest clean-energy transmission project in US history.", detailEn: "SunZia combines a 3.5 GW onshore wind farm in New Mexico with an ~885 km, ±525 kV HVDC line carrying the power to Arizona and into the California market — at about $11 billion the largest clean-energy infrastructure project in US history. By early 2026 all 674 turbines had been delivered and installed, with the project nearing completion." },
  32: { descEn: "Quebec hydropower delivered directly to New York City.", detailEn: "A ~545 km, 1.25 GW buried and underwater HVDC line running along Lake Champlain and the Hudson River to bring Quebec's hydropower into New York City, with power flows planned from May 2026. It will meet about 20% of the city's electricity demand, sharply cutting local fossil-fuel reliance and emissions." },
  33: { descEn: "The Middle East's first large-scale HVDC interconnector.", detailEn: "Connecting Saudi Arabia and Egypt at ±500 kV with 3 GW capacity, this is the first large-scale HVDC interconnector in the Middle East and North Africa. The two countries' demand peaks fall at different times (Saudi summer daytime, Egyptian evening), so the link lets them share peaks and reserves, improving regional grid economics and stability." },
  34: { descEn: "First link between the Texas grid and the US Southeast.", detailEn: "A ~320-mile, 525 kV, 3 GW bidirectional HVDC line that for the first time connects the relatively isolated Texas ERCOT grid with the US Southeast. Once built, the two grids can support each other during extreme weather, markedly improving supply reliability — a key US inter-regional interconnection project." },

  /* ===== 储能 ===== */
  35: { descEn: "The largest pumped-hydro storage in the Southern Hemisphere.", detailEn: "In the Snowy Mountains of New South Wales, tunnels and reversible turbines are being added between existing reservoirs for 2.2 GW of capacity and about 350 GWh of storage — the largest pumped-hydro scheme in the Southern Hemisphere. It will provide long-duration backstop balancing for Australia's high-renewables grid, in effect a giant \"water battery\"." },
  36: { descEn: "One of the Southern Hemisphere's largest battery storage systems.", detailEn: "On a former power-station site in New South Wales, the 850 MW/1,680 MWh Waratah Super Battery is one of the largest battery storage projects in the Southern Hemisphere. Acting as a grid \"shock absorber\", it rapidly absorbs and injects power during line faults to protect transmission corridors, letting existing lines carry more renewable energy." },
  38: { descEn: "The world's largest battery project by GWh to date.", detailEn: "Announced in February 2026 by Xcel Energy and Google using Form Energy's iron-air battery technology, this 300 MW/30 GWh system is the world's largest battery storage project by gigawatt-hours to date. Iron-air cells enable roughly 100 hours of long-duration storage, mainly providing multi-day reliable power to Minnesota's data centres and grid." },
  39: { descEn: "The world's first gigawatt-scale round-the-clock solar-plus-storage.", detailEn: "Developed by the UAE's Masdar with EWEC, this project pairs ~5.2 GW of solar with ~19 GWh of battery storage to deliver a steady 1 GW of round-the-clock (24/7) output — the world's first solar-plus-storage scheme at this scale. It aims to prove that solar plus batteries alone can supply near-baseload, reliable power." },
  40: { descEn: "A giant high-altitude battery storage system.", detailEn: "In India's high-altitude Ladakh region, this ~12 GWh system supports a large local renewable-energy base, smoothing output fluctuations and underpinning long-distance transmission. One of India's largest battery storage projects, it serves as a model for grid stability at high altitude." },
  41: { descEn: "A giant storage project in the Atacama Desert.", detailEn: "Built by Spain's Grenergy in Chile's Atacama Desert, this project deploys about 11 GWh of battery storage in phases alongside large-scale solar. Shifting abundant daytime sunshine to night-time release, it is one of Latin America's largest storage projects, helping Chile's grid wean off fossil-fuelled peaking plants." },
  43: { descEn: "The world's largest compressed-air energy storage.", detailEn: "In Yingcheng, Hubei, this plant uses a single 300 MW unit storing compressed air in underground salt caverns — at commissioning in 2024 the world's largest and most efficient non-combustion compressed-air energy storage station. It charts a new path for long-duration, high-capacity, low-cost storage and exemplifies the diversification of new storage technologies." },
  44: { descEn: "One of the world's largest single battery storage projects.", detailEn: "Large battery storage deployed by the Saudi Electricity Company across several sites including Bisha, with multi-GWh batches supplied by BYD and others — among the world's largest single battery storage projects. It absorbs Saudi Arabia's fast-growing solar capacity and underpins the high-renewables targets of Vision 2030." },

  /* ===== 工商业 · 配网大客户 ===== */
  46: { descEn: "The largest semiconductor investment in the US.", detailEn: "TSMC is building several advanced-process fabs in Phoenix, Arizona, with cumulative pledged investment raised to about $165 billion — the largest foreign semiconductor investment in US history. A single fab's power and water needs rival a mid-sized city, driving large-scale expansion of local grid and water systems and anchoring a full semiconductor supply chain." },
  47: { descEn: "A mega \"Silicon Heartland\" fab campus.", detailEn: "Near Columbus, Ohio, Intel plans a mega fab campus dubbed the \"Silicon Heartland\", with initial investment of about $28 billion. Its production timeline has slipped amid the semiconductor market downturn, but it remains a major project for domestic advanced-process manufacturing and grid capacity expansion." },
  49: { descEn: "India's first large-scale wafer fab.", detailEn: "The Tata Group, with Taiwan's PSMC, is building India's first large-scale wafer fab at Dholera, Gujarat, for about $11 billion. A flagship of India's chip self-reliance strategy, it comes with dedicated power, ultra-pure water and a new industrial city, creating huge new demand on the local grid and infrastructure." },

  /* ===== 数据中心 ===== */
  50: { descEn: "The largest AI infrastructure build in the US.", detailEn: "A joint venture of OpenAI, Oracle, SoftBank and MGX, Stargate plans to invest up to $500 billion by 2029 to build about 10 GW of AI computing. Its first flagship campus is in Abilene, Texas, and by 2025-2026 it had expanded to around 10 sites across Texas, New Mexico, Ohio and Michigan. Its staggering power demand (several GW per campus) is reshaping US power planning and spurring matching generation and storage investment." },
  51: { descEn: "An AI supercomputing centre in Memphis.", detailEn: "Elon Musk's xAI is building the \"Colossus\" supercomputing cluster in Memphis, Tennessee, deploying hundreds of thousands of GPUs to train large models and scaling toward gigawatt-class power demand. The project has drawn local scrutiny over temporary gas generation, power and water use — a microcosm of the grid pressure from rapid AI compute expansion." },
  52: { descEn: "The largest AI data-centre cluster outside the US.", detailEn: "In Abu Dhabi, the UAE's G42 is building this cluster with Nvidia, OpenAI, Cisco, Oracle and others, planning about 5 GW of compute — the largest AI data-centre cluster outside the US, entering service in phases from 2026. Leveraging cheap local energy and capital, the UAE aims to become the Middle East's artificial-intelligence and computing hub." },
  53: { descEn: "The world's densest concentration of data centres.", detailEn: "Around Ashburn in Loudoun County, Virginia lies the world's densest cluster of data centres, carrying a sizeable share of global internet traffic, with total power use already above 5 GW and still growing. AWS, Microsoft, Google and others are packed in here, and their power demand has forced major adjustments to local grid and generation planning." },
  54: { descEn: "Southeast Asia's fastest-growing data-centre hub.", detailEn: "Johor in Malaysia, next to Singapore, is absorbing data-centre demand spilling over from land- and power-constrained Singapore, with capacity under construction already reaching several GW — Southeast Asia's fastest-growing data-centre hub. Major cloud and AI firms are investing heavily here, driving rapid expansion of local power, solar and supporting infrastructure." },
  55: { descEn: "A Middle East AI computing centre.", detailEn: "Backed by Saudi Arabia's sovereign wealth fund, HUMAIN is building large-scale AI data centres in Riyadh and elsewhere with Nvidia, AMD and others, planning several GW of compute. Leveraging cheap energy and capital, Saudi Arabia aims to make computing a new pillar of its Vision 2030 economy." },

  /* ===== 大交通 · 轨交机场港口 ===== */
  59: { descEn: "A flagship China-CEE railway.", detailEn: "Connecting Budapest in Hungary with Belgrade in Serbia, this ~350 km electrified, upgraded-speed railway already has its Belgrade-Novi Sad section in service. A flagship of China-Central and Eastern Europe cooperation and the Belt and Road in Europe, it will improve the efficiency of the China-Europe Land-Sea Express route." },
  61: { descEn: "A new South America-Asia shipping hub.", detailEn: "North of Lima, Peru, and built and operated by COSCO Shipping, Chancay is the first smart, green deep-water mega-port on South America's west coast, opening in November 2024. Its direct route to Shanghai cuts shipping time from Peru to China by about 10 days, reshaping South America-Asia trade and driving green port infrastructure such as shore power." },
  62: { descEn: "Planned to be one of the world's largest airports.", detailEn: "Led by Saudi Arabia's PIF sovereign fund, this airport is planned with six runways and an eventual annual throughput of up to 185 million passengers, set to be one of the world's largest. It is core infrastructure for Riyadh's ambition to become a global aviation and logistics hub and to support the economic diversification of Vision 2030." },
  63: { descEn: "Vietnam's largest airport.", detailEn: "In Dong Nai Province east of Ho Chi Minh City, Long Thanh's first phase is due in 2026 with 25 million passengers a year, expanding to 100 million long term, making it Vietnam's largest airport. It will relieve pressure on Tan Son Nhat, strengthen Vietnam's position as a regional aviation hub and spur surrounding industry and power supply." },
  64: { descEn: "Sydney's second airport.", detailEn: "In Sydney's western suburbs, Western Sydney Airport is due to open in the second half of 2026 with an initial 10 million passengers a year, becoming Sydney's second international airport. It comes with a dedicated metro line, roads and power networks, easing the capacity bottleneck at Kingsford Smith Airport and driving development of Western Sydney." },
  65: { descEn: "Europe's largest air-rail hub under construction.", detailEn: "Between Warsaw and Łódź, the Central Communication Port (CPK) is planned with two parallel runways integrated with a high-speed-rail hub and motorway network, at about €30 billion, with construction from 2026, serving a catchment of some 21 million people. It is set to be Central and Eastern Europe's largest combined aviation and high-speed-rail hub, with rail offering an \"air-to-rail\" alternative." },
  66: { descEn: "The first true high-speed rail in the US.", detailEn: "Planned to link San Francisco and Los Angeles, California High-Speed Rail is under full construction along a 119-mile segment in the Central Valley, with most structures built or under way — the first true high-speed railway in the US. Repeatedly challenged on schedule and budget, it is seen as a pivotal attempt to modernise US passenger rail." },
  68: { descEn: "The China-Pakistan Economic Corridor's sea gateway.", detailEn: "On the Arabian Sea coast of Balochistan, Pakistan, Gwadar is the sea gateway of the China-Pakistan Economic Corridor (CPEC), with a free-trade zone, power plant and desalination facilities. Once complete it offers western China a shorter route to the Indian Ocean and drives local energy and infrastructure development." },

  /* ===== 石油化工 · LNG ===== */
  69: { descEn: "The world's largest LNG expansion project.", detailEn: "Drawing on the world's largest single gas field — the North Field — Qatar is lifting LNG output from about 77 million tonnes a year to roughly 142 million tonnes before 2030 via its East and South phases and further expansion. It is the world's largest LNG expansion, further cementing Qatar's position as the leading global LNG exporter." },
  70: { descEn: "A large export LNG terminal in Louisiana.", detailEn: "A large export LNG project by Venture Global in Calcasieu, Louisiana; in March 2026 its second phase reached final investment decision with about $8.6 billion of financing secured. It is emblematic of the 2025-2026 wave of new US LNG investment, further expanding US gas export capacity to Europe and Asia." },
  71: { descEn: "A large export LNG terminal in Louisiana.", detailEn: "Near the mouth of the Mississippi River in Louisiana, Plaquemines LNG has capacity of about 24 million tonnes a year, using modular construction for fast start-up and beginning phased LNG output in 2024-2025. One of Venture Global's flagship export terminals, it is helping make the US the world's largest LNG exporter." },
  72: { descEn: "A Gulf Coast LNG terminal advancing toward FID.", detailEn: "Energy Transfer is converting its existing import terminal at Lake Charles, Louisiana into an export terminal of about 16.5 million tonnes a year, advancing toward a final investment decision in early 2026 after locking in several long-term supply agreements. It is another important reserve of US LNG export capacity." },
  73: { descEn: "North Slope gas liquefied for export.", detailEn: "Led by Glenfarne, Alaska LNG would pipe abundant North Slope gas about 800 miles to Nikiski on the Kenai Peninsula for liquefaction and export, at a total cost of about $44 billion. With gas supply secured from major oil-and-gas players and a final investment decision advancing in 2026, it could offer shorter-haul LNG to Asian markets." },
  74: { descEn: "An LNG capacity expansion at Kitimat.", detailEn: "At Kitimat, British Columbia, operated by a Shell-led joint venture, the first phase is already producing and exporting LNG to Asia, with the phase-2 expansion advancing toward a final investment decision in 2026. Thanks to Canada's shorter west-coast route to Asia, it is an important addition to North American LNG supply to Asia." },
  76: { descEn: "The world's largest single-train refinery.", detailEn: "In the Lekki Free Trade Zone near Lagos, Nigeria, the Dangote Refinery processes 650,000 barrels a day — the world's largest single-train refinery — starting up from 2024. It reverses West Africa's long reliance on imported fuels, positioning Nigeria to shift from a crude exporter to a net exporter of refined products, with its own captive power plant and jetty." },
  77: { descEn: "The core of Saudi Arabia's \"gas-for-oil\" strategy.", detailEn: "In eastern Saudi Arabia, Jafurah is the Middle East's largest unconventional (shale) gas field, which Saudi Aramco plans to develop in phases for about $100 billion. The added gas will go to power, industry and blue-hydrogen production, freeing up more crude for export — the centrepiece of Saudi Arabia's \"gas-for-oil\" energy strategy." },
  78: { descEn: "A gravity-based LNG plant in the Arctic Circle.", detailEn: "On the Gydan Peninsula inside Russia's Arctic Circle and led by Novatek, Arctic LNG 2 uses modular liquefaction trains built on gravity-based structures (GBS), with planned capacity of about 20 million tonnes a year. Hit by Western sanctions, it has struggled with equipment, shipping and sales — a textbook case of geopolitics' impact on energy projects." },

  /* ===== 矿业 ===== */
  80: { descEn: "The largest high-grade iron-ore mine under development.", detailEn: "In the mountains of south-eastern Guinea, Simandou grades about 65.8% iron — one of the largest and highest-grade undeveloped iron-ore deposits in the world. Blocks 1-2 are led by the Chinese-backed WCS consortium and Blocks 3-4 by a Rio Tinto-Chinalco venture, served by the ~620 km TransGuinéen heavy-haul railway and a new port. The first ore shipped in December 2025 and reached Zhejiang in January 2026, with output ramping toward ~120 million tonnes a year, reshaping global iron-ore supply." },
  81: { descEn: "The world's highest-output copper mine.", detailEn: "In Chile's Atacama Desert, operated by BHP with Rio Tinto and others as partners, Escondida is the world's highest-output copper mine. Recent years have seen about $13 billion invested in expansion, desalination and processing upgrades, and it now runs on 100% renewable power — vital to the copper supply needed for the global energy transition." },
  86: { descEn: "The hub of global iron-ore supply.", detailEn: "The Pilbara region of Western Australia is the hub of global iron-ore supply, where Rio Tinto, BHP, FMG and others run multiple super-large mines exporting over a billion tonnes a year, mostly to China. The region's extensive use of autonomous haul trucks, driverless heavy-haul trains and remote operations centres makes it a benchmark for mining automation." },
  87: { descEn: "A frontier of new global lithium supply.", detailEn: "The \"Lithium Triangle\" where Argentina, Chile and Bolivia meet holds over half the world's lithium resources, with relatively low-cost brine extraction. Chinese firms such as Zijin and Ganfeng, together with international miners, are building brine lithium projects intensively in Argentina, making the region a leading frontier of new global lithium supply." },
});

/* ===== 批次2：全库投资额 TOP（约 ≥175 亿美元）===== */
Object.assign(window.ENERGY_EN, {
  1033: { descEn: "The largest semiconductor project in US history.", detailEn: "Micron is building a mega-campus of four DRAM fabs at the White Pine Business Park in Clay, New York, with about $100 billion of investment — the largest semiconductor manufacturing project in US history — plus the first publicly owned High-NA EUV lithography centre in the country. Groundbreaking was held in January 2026, with first output targeted for 2030 and the full campus by the 2040s, driving city-scale grid and water expansion in central New York." },
  2047: { descEn: "A trans-isthmus land bridge bypassing the Strait of Malacca.", detailEn: "Thailand's Land Bridge would build deep-water ports at Chumphon and Ranong, linked by an 89 km six-lane expressway plus standard- and metre-gauge rail to bypass the Strait of Malacca. Costing about 1 trillion baht under a single 50-year PPP concession, it aims to start tendering and construction in 2026 with the first phase open by 2030 (internal rate of return ~17.4%)." },
  1539: { descEn: "Rosneft's Arctic flagship, with phase 1 targeted for 2026.", detailEn: "Vostok Oil is Rosneft's Arctic super-cluster of oilfields on the Taymyr Peninsula, valued at about $85 billion with planned investment of over 12 trillion roubles. Trial production began in early 2025 at fields such as Payakhskoye, with an export port, oil terminal and field pipelines under construction (over 80% done by September 2025); phase 1 is slated for 2026 and output is targeted at ~67 million tonnes a year by 2030." },
  1138: { descEn: "The UK's largest railway project.", detailEn: "HS2 is Britain's largest post-war rail infrastructure project, with phase 1 linking London's Old Oak Common to Birmingham at 330 km/h. Several tunnels broke through in 2025 — including the Bromford, Northolt and the line's longest Chiltern tunnel — and all deep bored tunnels between London and Birmingham were completed by October; civil works are about two-thirds done, with services planned for the early 2030s." },
  2933: { descEn: "Four AP1000 reactors anchoring an 11 GW AI campus in Texas.", detailEn: "Dubbed the 'Trump Advanced Energy and Intelligence Campus', this project beside the DOE Pantex plant near Amarillo, Texas plans up to 11 GW of gas, solar, storage and nuclear to power 18 million sq ft of AI computing. In 2025 the NRC accepted a combined licence for four AP1000 units, with the first targeted to start construction in 2026 and operate by April 2031." },
  2934: { descEn: "Westinghouse's plan for 10 US AP1000 units (~11.5 GW).", detailEn: "In July 2025 Westinghouse announced 10 AP1000 reactors in the US to help quadruple US nuclear capacity to 400 GW by 2050. In October 2025 the US government, Brookfield and Cameco signed a framework to invest at least $80 billion, and in April 2026 a Vogtle-4-standardised AP1000 design revision was filed. (Located at the Vogtle plant, Georgia.)" },
  3152: { descEn: "Transmission master plan for ~76 GW of Brahmaputra-basin hydropower.", detailEn: "Led by India's CEA, this ~6.4 trillion-rupee plan adds over 31,400 circuit-km of lines, ~68 GVA of substation capacity and 42 GW of HVDC to evacuate some 76 GW of hydro and pumped storage across 12 sub-basins including Siang (18.7 GW), Subansiri (12.3 GW) and Dibang (8.8 GW), in two phases around 2035." },
  3014: { descEn: "Canada's first true high-speed rail.", detailEn: "Announced by the Prime Minister in February 2025, Alto is a ~1,000 km dedicated electrified line at 300 km/h linking Toronto, Ottawa, Montreal and Quebec City. The private Cadence consortium (including SNCF and Air Canada) will design, build, finance and operate it; the design phase is ~C$3.9 billion and the whole network is estimated at C$60-90 billion, with main works around 2030." },
  162: { descEn: "The world's largest planned green-hydrogen export hub.", detailEn: "Spanning ~2.26 million hectares in Western Australia, this hub plans 70 GW of wind and solar to produce ~3.5 million tonnes of green hydrogen and 20 million tonnes of green ammonia a year. It won federal 'Major Project' status in March 2025, with a ~6 GW first phase tied to feasibility deals with China's SANY and Korean firms; fully built it would generate more than Australia's entire current output." },
  1161: { descEn: "Vietnam's 1,541 km north-south high-speed railway.", detailEn: "Vietnam's North-South high-speed railway links Hanoi and Ho Chi Minh City over 1,541 km through 15 provinces with 23 stations at 350 km/h. Approved by the National Assembly in November 2024 at about $67.5 billion across 17 sub-projects, construction was brought forward to December 2025 with a 2035 target, cutting Hanoi-HCMC travel to ~5.5 hours — the largest infrastructure project in Vietnam's history." },
  2938: { descEn: "Up to 4,800 MW added at the world's largest operating nuclear site.", detailEn: "Bruce C would add up to 4,800 MW within the existing Bruce site — Ontario's first major new-build nuclear in over 30 years. It has cleared the federal impact-assessment planning phase and entered the impact-statement stage, with Bruce Power signing a C$300 million pre-development deal; lifetime economic contribution is estimated at ~C$238 billion." },
  1546: { descEn: "A giant Baltic gas-processing, LNG and petrochemical complex.", detailEn: "The Ust-Luga complex, built by RusKhimAlliance (a 50/50 JV of Gazprom and RusGazDobycha), is designed to process 45 bcm of ethane-rich gas a year into 13 million tonnes of LNG, 3.6 million tonnes of ethane and up to 1.8 million tonnes of LPG, feeding an adjacent cracker producing over 3 million tonnes of polymers. Costing about 4.9 trillion roubles, it has been delayed by Western sanctions, with Linde withdrawing in 2022." },
  521: { descEn: "A 1.8 GW AI campus in Cheyenne, Wyoming.", detailEn: "Announced by Crusoe and Tallgrass in July 2025 in Laramie County southeast of Cheyenne, Project Jade plans 1.8 GW — expandable to 10 GW long term — with Tallgrass supplying a gas power plant. With total project cost potentially reaching $50 billion, it is one of the largest AI data centres under discussion in the US interior." },
  2800: { descEn: "The UK's first new nuclear plant in decades (2×EPR).", detailEn: "In Somerset, England, Hinkley Point C is two 1.6 GW EPR reactors led by EDF (with CGN as a partner) — the UK's first new nuclear station in decades. The second reactor dome was lifted in 2025 and its pressure vessel arrived in January 2026; with costs risen to about £46 billion, the first unit is due to operate in the early 2030s." },
  2803: { descEn: "France's nuclear restart: the first six EPR2 reactors.", detailEn: "EDF's next-generation EPR2 programme will build a first batch of six 1.67 GW reactors at Penly (2), Gravelines (2) and Bugey (2). Public consultation and early works advanced in 2025, with Penly 1/2 aiming for the mid-2030s — a national flagship to restart French nuclear and secure low-carbon baseload power." },
  3002: { descEn: "Anthropic's $50 billion compute build, starting in Texas and New York.", detailEn: "Announced on 12 November 2025, Anthropic's $50 billion US AI-infrastructure plan will build custom data centres with the UK's Fluidstack in Texas and New York, coming online from 2026 and creating about 800 long-term jobs, running alongside AWS, Google TPU and Microsoft Azure capacity." },
  2801: { descEn: "Sizewell C: FID taken in July 2025, UK government holds 44.9%.", detailEn: "In Suffolk, England, Sizewell C is two 1.6 GW EPR reactors replicating Hinkley Point C to cut costs. A final investment decision was taken in July 2025 at over £38 billion, with the UK government the largest shareholder at 44.9% and a regulated-asset-base (RAB) model bringing in private investment — a centrepiece of Britain's energy-security strategy." },
  1528: { descEn: "Kazakhstan's largest oilfield expansion, with a third processing train online.", detailEn: "Chevron-led Tengizchevroil's Future Growth Project (FGP) and Wellhead Pressure Management Project (WPMP) added a third-generation processing plant with enhanced sour-gas reinjection at the Tengiz field in western Kazakhstan. WPMP finished in 2024 and FGP started up in January 2025, ramping Tengiz to about 1 million barrels a day; at ~$46.7 billion it is Kazakhstan's largest single industrial investment." },
  1459: { descEn: "One of the world's largest green-hydrogen projects (40 GW + 20 GW electrolysis).", detailEn: "Sweden's Svevind, through Hyrasia One, plans about 40 GW of wind and solar in Kazakhstan's Mangystau region — ~120 TWh a year — feeding a 20 GW electrolyser park on the Caspian coast for up to 2 million tonnes of green hydrogen annually. Costing $40-50 billion, output is planned from 2030 with full capacity around 2032 and a final investment decision expected in 2026." },
  3562: { descEn: "The world's most challenging railway; over 84% bridges and tunnels.", detailEn: "The 1,019 km Ya'an-Nyingchi section of the Sichuan-Tibet Railway includes 72 new tunnels totalling 838 km (the 42.5 km Yigong tunnel the longest), at an estimated ~320 billion yuan. Early works such as key tunnels and bridges have begun, with completion targeted for 2030 and high-standard advancement set out in the 15th Five-Year Plan." },
  2418: { descEn: "A $42 billion LNG plant at Lindi, fed by Shell and Equinor offshore gas.", detailEn: "At Likong'o in Lindi, this plant would produce about 10 million tonnes of LNG a year from Shell (Blocks 1 and 4) and Equinor (Block 2) offshore reserves, at about $42 billion — Tanzania's largest single energy project. Parties are pushing to finalise the legal framework and FID by late 2025/early 2026, though FID risks slipping to 2028 with start-up after 2032." },
  158: { descEn: "One of the world's largest planned green-hydrogen projects.", detailEn: "This project plans 30 GW of wind and solar in Mauritania's desert to produce 1.7 million tonnes of green hydrogen a year, led by Australia's CWP Global. Geological, hydrological and marine surveys were completed in 2025 (pre-FEED stage), and once built it is expected to lift Mauritania's GDP by 40-50%." },
  513: { descEn: "Three new Google data-centre campuses in West Texas ($40 billion).", detailEn: "In November 2025 Google announced a $40 billion investment (through 2027) in three data centres in West Texas and the Panhandle — two in Haskell County (one a solar-plus-storage industrial park with Intersect) and one in Armstrong County — alongside contracts for 6,200+ MW of new power." },
  1027: { descEn: "A new 12-inch fab mega-site in Texas.", detailEn: "Texas Instruments is building a mega-site of up to four connected 12-inch fabs in Sherman, Texas, with potential total investment of ~$40 billion. The first fab, SM1, started production on 17 December 2025 — in just three and a half years — ramping toward tens of millions of analog and embedded chips a day, with SM2's shell topped out; the site is a city-scale new load on the local grid." },
  1518: { descEn: "Eastern expansion of the BAM and Trans-Siberian railways.", detailEn: "Russia approved a third phase of its Eastern rail network (the 'Eastern Polygon') to 2035 at over 3.7 trillion roubles (~$40 billion), aiming to lift eastbound capacity to 270 million tonnes a year within a decade. Works include new passing loops, tunnels, an Amur River bridge and spurs to Far East ports — a key corridor for exports to Asia-Pacific." },
  2374: { descEn: "Storage and grid infrastructure for the 30 GW AMAN green-hydrogen project.", detailEn: "CWP Global's flagship AMAN project in Mauritania plans 30 GW of wind and solar (18 GW wind + 12 GW solar) generating ~110 TWh a year to make 1.7 million tonnes of green hydrogen and 10 million tonnes of green ammonia, worth about $40 billion. It includes large-scale desalination, storage and transmission aimed at clean-energy export to Europe (this entry focuses on the renewables-and-storage build-out)." },
  2804: { descEn: "Poland's first nuclear power station (3×AP1000).", detailEn: "On Poland's Baltic coast, the state company PEJ is building three 1.25 GW AP1000 reactors with Westinghouse and Bechtel — Poland's first nuclear plant. It won site-preparation and survey permits in August-September 2025, and in December the EU approved state aid (including a 40-year contract for difference); the first unit is due to start construction in 2028 and operate in 2036." },
  3013: { descEn: "A Dallas-Houston high-speed line using Japanese Shinkansen technology.", detailEn: "This ~386 km, 330 km/h line lost federal planning funding and Amtrak's involvement in April 2025, returning to private leadership under Fort Worth investor John Kleinheinz. Station sites are bought and about 500 of ~2,000 parcels acquired, with cost estimated at over $40 billion." },
  3129: { descEn: "The world's largest planned nuclear plant (6×EPR).", detailEn: "At Madban in Ratnagiri, Maharashtra, NPCIL leads with EDF supplying six EPR reactors (~1,650 MW each, ~9.9 GW total), which would make it the world's largest planned nuclear station. President Macron's February 2026 visit to India confirmed advancing the six-EPR process with accompanying small-reactor cooperation." },
  3275: { descEn: "A giant west-coast refining-petrochemical complex, now being split up.", detailEn: "RRPCL — formed by IOCL/BPCL/HPCL (50:25:25) with Saudi Aramco and ADNOC to hold 50% — originally planned 60 million tonnes/year of refining plus 18 million tonnes of petrochemicals. Hit by land and environmental protests, the centre is from 2025 considering splitting it into three dispersed 20-million-tonne refineries, but it remains central to India's refining expansion." },
  565: { descEn: "The Wuhu cluster of China's 'east-data-west-compute' Yangtze Delta hub.", detailEn: "Since approval in 2022 the Wuhu cluster has attracted 15 major projects from Huawei Cloud, ByteDance, China Mobile and others totalling over 270 billion yuan, with 21,000 racks built and over 100,000 under construction. China Mobile's first nationwide 'four-compute-in-one' scheduling platform is here, targeting over 45,000 PFLOPS of AI computing by 2027." },
  588: { descEn: "Spain's largest-ever foreign investment, across three Aragon provinces.", detailEn: "In March 2026 Spain announced that Amazon will invest a cumulative €33.7 billion in the Aragon region, building large-scale data centres and server-manufacturing facilities across Zaragoza, Huesca and Teruel, expected to add €31.7 billion in GDP and an average 29,900 full-time jobs a year." },
  288: { descEn: "The world's largest planned single AI data centre.", detailEn: "South Jeolla Province in Korea has attracted a 3 GW, ~$35 billion AI data centre able to house 200,000 GPUs, breaking ground in winter 2025 with completion targeted for 2028, backed by Korea's 65-trillion-won national AI strategy." },
  1129: { descEn: "Planned to be the world's largest airport (150M pax phase 1).", detailEn: "Dubai's Al Maktoum International Airport phase-2 expansion, approved in 2024 at about AED 128 billion (~$35 billion), will build a central terminal and four concourses for 150 million passengers a year initially, rising to five runways, ~400 gates and 260 million passengers — the world's largest airport. A ~$272 million second-runway contract and early works were awarded in 2025, with phase 1 targeted for 2032." },
  2251: { descEn: "Six green hydrogen/ammonia/steel projects worth $32.8 billion.", detailEn: "In March 2025 Morocco approved a green-hydrogen package in which consortia led by Ortus (US)/Acciona/Nordex, TAQA/Cepsa, Morocco's Nareva, Saudi ACWA Power and a Chinese UEAG/Three Gorges group will produce green ammonia, fuels and green steel. Concentrated in the south (Guelmim, Tan-Tan, Boujdour), it adds ~6 GW of wind and solar, targeting 10 TWh of exports by 2030." },
  2983: { descEn: "Intel's 18A flagship fab at Chandler, now in production.", detailEn: "Fab 52, the fifth high-volume fab at Intel's Ocotillo campus in Chandler, Arizona, began carrying 18A wafers in October 2025 and entered high-volume manufacturing by year-end, producing the first 18A Panther Lake processors that launched in late 2025 with broad availability in early 2026." },
  1409: { descEn: "Jeddah airport expanded to one of the world's largest (114M pax by 2031).", detailEn: "Jeddah Airports Company's 115 billion-riyal (~$31 billion) plan will make King Abdulaziz International one of the world's largest airports, reaching 114 million passengers a year by 2031. It includes a T1 expansion, a new T2 (construction from 2026, over $10 billion), a fourth runway (2025-2029), a new logistics zone and a Hajj terminal." },
  161: { descEn: "The world's largest planned solar-plus-storage, with a 4,300 km cable to Singapore.", detailEn: "SunCable's project would deploy 17-20 GW of solar and 36-42 GWh of storage on the Barkly Tableland in Australia's Northern Territory, sending power to Singapore via Indonesia through a ~4,300 km subsea cable. It renewed 'Major Project' status in July 2025 and won Indonesian approval, targeting cross-border supply in the mid-2030s — among the largest single renewable projects ever planned." },
  1500: { descEn: "Central Asia's largest compute park (1 GW long term).", detailEn: "In Ekibastuz, Pavlodar region, this aims to be Central Asia's largest data-centre park, with power capacity of 300 MW initially rising to 1 GW and total investment of ~$30 billion. Run by Kazakhtelecom's KT-Telecom and powered by the Ekibastuz GRES plants, it launched in January 2026 with full construction due to start in June 2026; the government is in talks with Microsoft, OpenAI, G42 and Mubadala." },
  2825: { descEn: "The Arab world's first nuclear plant (4×APR1400, all online).", detailEn: "At Barakah in western Abu Dhabi, KEPCO built four 1.4 GW APR1400 reactors — the Arab world's first nuclear plant, at about $30 billion. The fourth unit was commissioned in 2025; with all four in commercial operation they supply about a quarter of the UAE's electricity, a Middle East nuclear benchmark." },
  2827: { descEn: "Egypt and Africa's first large nuclear plant (4×VVER).", detailEn: "At El Dabaa on Egypt's Mediterranean coast in Matrouh, Russia's Rosatom is building four 1.2 GW VVER-1200 reactors — Egypt and Africa's first large nuclear plant, at about $30 billion, with all four units built concurrently. Main works advanced rapidly in 2025, with the first unit targeted to operate around 2028." },
  2984: { descEn: "Micron's second advanced DRAM fab at Boise, with HBM packaging.", detailEn: "Micron is building a second advanced DRAM fab (ID2) next to R&D at its Boise headquarters campus — part of a ~$200 billion US expansion with ~$30 billion added here. Idaho and New York together won ~$6.1 billion in CHIPS grants, bringing advanced packaging to support the HBM that AI requires." },
  3130: { descEn: "An India-US flagship nuclear plant (6×AP1000).", detailEn: "At Kovvada in Srikakulam, Andhra Pradesh, India plans six Westinghouse AP1000 reactors (~1,100 MW each); about 2,080 acres have been acquired and transferred to NPCIL and surveys completed. In 2025 NPCIL continued technical-commercial talks with Westinghouse — a flagship of India-US civil-nuclear cooperation." },
  3577: { descEn: "Shenzhen's largest-ever metro build (phase 5, 13 lines).", detailEn: "Shenzhen's fifth-phase metro plan (2023-2028) covers 13 projects totalling 185.6 km at about 195.2 billion yuan, including lines 15, 17-22, 25, 27, 29 and 32 plus extensions of lines 10 and 11. On completion Shenzhen's rail network will reach 25 lines and about 843.6 km." },
  1514: { descEn: "Russia's first dedicated high-speed railway.", detailEn: "This 679 km line with 16 stations is designed for 400 km/h (360 km/h in service), linking Moscow and St Petersburg, at over 2.3 trillion roubles (~$26 billion) including low-interest National Wealth Fund loans. Approved by Putin in March 2024, construction began in summer 2025 with the first section due in 2028, cutting travel time from ~4 hours to 2h15." },
  506: { descEn: "AWS AI cloud data centres across several Mississippi counties.", detailEn: "AWS is building data centres in Madison County (Project Atlas, $11 billion), Vicksburg in Warren County ($3 billion) and sites in Hinds County, Mississippi, announced through 2025-2026 for a cumulative $25 billion — the largest AWS expansion in the US Southeast." },
  508: { descEn: "The second-largest Stargate site, in Shackelford County, Texas.", detailEn: "Vantage Data Centers is building the Frontier campus in Shackelford County north of Abilene, Texas — 1,200 acres, 10 buildings totalling 3.7 million sq ft and 1.4 GW of compute, using a gas microgrid and water-saving closed-loop cooling. Construction began in September 2025 and it is officially confirmed as a Stargate site." },
  580: { descEn: "One of the world's largest AI data-centre plans, with gigawatt-scale green power.", detailEn: "Reliance plans up to 3 GW of AI data centres at Jamnagar, Gujarat, using Nvidia's latest Blackwell GPUs and powered entirely by on-site solar, wind and green hydrogen, at an estimated $20-30 billion. Targeting a first phase within 24 months, it would be one of the world's largest green AI computing bases." },
  1547: { descEn: "A giant LNG base on the Kola Peninsula with a 1,300 km feed pipeline.", detailEn: "Novatek's Murmansk LNG on the Kola Peninsula has capacity of about 20.4 MTPA, with a cost edge because it needs no icebreakers for year-round export. In January 2025 completion was brought forward from 2033 to 2030, with phase 1 in 2027-2029, fed by a ~1,300 km Volkhov-Murmansk pipeline (4.12 bcm/year) that Putin ordered finished by 2030." },
  2302: { descEn: "A 5,000 km trans-Atlantic gas pipeline from West Africa to Europe.", detailEn: "Nigeria and Morocco plan a 5,000 km coastal gas pipeline through 13 West African countries toward Europe. The two aim to sign an intergovernmental agreement in Q4 2026 — one of Africa's most ambitious cross-border energy infrastructure projects." },
  2810: { descEn: "The world's largest tokamak fusion experiment.", detailEn: "At Cadarache in southern France, ITER is built by China, the EU, the US, Russia, Japan, Korea and India — the world's largest magnetic-confinement tokamak, designed for 500 MW of fusion power. Key components such as superconducting magnets were completed in 2025, with first plasma targeted around 2034 and full operation by 2039 to prove fusion power feasible." },
  2935: { descEn: "A framework to deploy up to 6 GW of NuScale SMRs with TVA.", detailEn: "ENTRA1 and TVA reached a non-binding agreement to develop and own six energy plants across a seven-state service area, deploying up to 6 GW of NuScale modular reactors, part of ENTRA1's ~$25 billion power-infrastructure plan, at the planning stage. (Located in the central TVA service area.)" },
  3144: { descEn: "A reserve Westinghouse AP1000 site in Gujarat (long term).", detailEn: "At Chhaya-Mithi Virdi on the coast of Bhavnagar, Gujarat, India originally planned six Westinghouse AP1000 reactors (~6 GW). Blocked by land acquisition, the main effort moved to Kovvada in Andhra Pradesh, but Westinghouse says it still intends to build six AP1000 units here once Kovvada is done — a long-term reserve site." },
  3578: { descEn: "Guangzhou Metro phase 4 (8 lines, 175.5 km).", detailEn: "Guangzhou's fourth-phase plan (2025-2031) covers eight line segments totalling 175.5 km at about 172.1 billion yuan, reinforcing high-load central lines and strengthening the eastern centre and Nansha networks. Environmental review began in October 2024, with approval targeted for 2026." },
  1164: { descEn: "Thailand's first high-speed railway, linking to the China-Laos line.", detailEn: "The China-Thailand high-speed railway is Thailand's first, about 609 km at 250 km/h in two phases. Phase 1 (Bangkok-Nakhon Ratchasima, 251 km) was about 45% complete on civil works by June 2025, targeting 2027; phase 2 (357 km to Nong Khai) was approved in February 2025 at ~341 billion baht for 2025-2032. Connecting to the China-Laos railway, it opens the Pan-Asian central corridor from Bangkok via Vientiane to China." },
  1224: { descEn: "A large greenfield refinery in East Java.", detailEn: "At Tuban in East Java, the PRPP joint venture of Pertamina and Rosneft is designed for 300,000 barrels a day plus a large petrochemical complex, at about $24 billion. Although FID remains unsettled due to the Russian partner, the project launched EPCC prequalification tendering in May 2026 — an important reserve of Indonesian refining capacity." },
  3047: { descEn: "The Trans Mountain crude pipeline expansion, online in May 2024.", detailEn: "The Trans Mountain Expansion entered service on 1 May 2024 after 12 years and about C$34 billion, raising capacity from 300,000 to 890,000 barrels a day from Edmonton to the port of Burnaby. Since start-up China has overtaken the US as the largest buyer, sharply lifting Canadian crude exports." },
  2743: { descEn: "Europe's largest metro project: four new Paris lines.", detailEn: "The Grand Paris Express is an automated metro network around Paris, building about 200 km of new lines (15/16/17/18) and 68 new stations at ~€36 billion — Europe's largest urban rail project. Tunnelling and station works are advancing, with some lines opening after the 2024 Olympics and the main network targeted for around 2030." },
  1400: { descEn: "The world's largest single-phase driverless metro.", detailEn: "Riyadh Metro comprises 6 lines and 85 stations over 176 km — the largest metro network built in a single phase and the world's longest fully automated driverless system. The Blue, Yellow and Purple lines opened on 1 December 2024, the Red and Green on 15 December, and the Orange on 5 January 2025, completing the network." },
  3579: { descEn: "Chengdu Metro phase 5 (10 projects, ~199.8 km).", detailEn: "Chengdu's fifth-phase plan covers 10 projects totalling about 199.8 km, including extensions of lines 5, 9, 10, 12, 16, 18, 20, 22, 23 and 27. Several have entered tendering, with Sichuan's 15th Five-Year rail plan budgeting over 100 billion yuan." },
  876: { descEn: "India's first national green-hydrogen hub, inaugurated by Modi in 2025.", detailEn: "Near Visakhapatnam at Pudimadaka, Andhra Pradesh, NTPC Green Energy and the state government plan 20 GW of renewables producing 1,500 tonnes of green hydrogen a day plus green methanol, urea and SAF. PM Modi laid the foundation stone in January 2025, with core phase-1 infrastructure targeted for 2026." },
  2653: { descEn: "Melbourne's underground orbital rail, connecting radial lines.", detailEn: "The Suburban Rail Loop East (SRL East) is a ~26 km fully underground railway from Cheltenham to Box Hill, linking south-eastern radial lines with universities and medical centres. At about A$34 billion with tunnelling from 2025, it is the largest public-transport project in Victoria's history." },
  1982: { descEn: "The longest cross-border subsea HVDC for green power.", detailEn: "This link sends green power from a giant solar-plus-storage plant in Australia's Northern Territory to Singapore via a ~4,300 km subsea HVDC cable, able to supply ~1.75 GW — nearly a tenth of Singapore's demand. It won conditional Singapore EMA approval in October 2024 and an Indonesian route permit in 2025 (with a ~$2.5 billion Indonesian investment pledge), targeting power from 2035." },
  2950: { descEn: "A 3,631-mile 765 kV backbone across nine Midwest states.", detailEn: "Approved by MISO in December 2024, this package of 24 projects and 323 facilities builds a 3,631-mile 765 kV backbone across nine states, with benefits possibly exceeding $72 billion. Together with phase 1 it totals about $32 billion, with projects entering service in 2032-2034." },
  1189: { descEn: "A Saudi offshore mega-expansion, online in late 2025.", detailEn: "Marjan is a giant offshore field straddling the Saudi-Iran median line; its increment adds GOSP-4, 24 offshore platforms and export lines, raising capacity by 300,000 to about 800,000 barrels a day of Arabian Medium crude, with the Tanajib gas plant processing associated gas. Both started up together in December 2025 — a pillar of Saudi Arabia's 12-million-barrel maximum sustainable capacity." },
  2067: { descEn: "Indonesia's largest LNG project in development (Abadi).", detailEn: "INPEX's Abadi LNG in the Masela block, at about $21 billion, will build a 9.5 MTPA liquefaction plant. It received Indonesian environmental approval in February 2026, with FID set for 2026 and start-up targeted for 2030; it has signed LNG offtake heads of agreement with bp, PGN, PLN and Shell and is seeking up to $14 billion in project finance, with construction tenders from mid-2026." },
  281: { descEn: "France's largest single data-centre investment commitment.", detailEn: "In February 2025 Brookfield and Data4 announced over $20.7 billion over five years to develop AI data-centre infrastructure in France, covering several campuses around Paris in line with the French government's AI strategy." },
  361: { descEn: "A $20 billion landmark LNG project, fully restarting in 2026.", detailEn: "Taking FID in 2019 at Afungi in Cabo Delgado, Mozambique, this 13 MTPA project was about 40% complete when suspended in 2021 due to armed conflict. Full restart was announced on 29 January 2026, remobilising over 4,000 workers, with first LNG in 2029." },
  500: { descEn: "Meta's 5 GW Hyperion AI super-data-centre in Louisiana.", detailEn: "Meta is building the Hyperion AI super-data-centre in Richland Parish, Louisiana — over 4,000 acres planned for up to 5 GW (a 1.5 GW first phase by end-2027), with 10 gas plants and 2.5 GW of renewables. Built by Turner/DPR/Mortenson, it began construction in 2025." },
  585: { descEn: "Europe's largest planned AI campus, nuclear-powered.", detailEn: "Announced at the May 2025 'Choose France' summit, MGX, Bpifrance, Mistral AI and Nvidia formed a joint venture to build Europe's largest AI campus in the Paris region — a 1.4 GW first phase from late 2026, operating in 2028, expanded in June 2026 to 3 GW nationwide, running on low-carbon nuclear power." },
  592: { descEn: "A $20 billion Qatar sovereign-AI JV with Brookfield.", detailEn: "The Qatar Investment Authority's Qai, established in December 2025, formed a $20 billion joint venture with Brookfield to build integrated computing campuses in Qatar and strategic markets, leveraging Qatar's gas resources and its location at the crossroads of Europe, Asia and Africa." },
  1025: { descEn: "A new line at the world's largest fab campus.", detailEn: "Pyeongtaek is the world's largest semiconductor campus; its fourth fab P4 is being converted from foundry to a dedicated sixth-generation 1c DRAM line of about 80,000 wafers/month, also for HBM4. Conversion runs from late 2025 with production expected in 2026, plus some NAND lines switched to DRAM for AI servers; the campus consumes billions of kWh a year." },
  1028: { descEn: "A mega-expansion by China's leading DRAM maker.", detailEn: "CXMT is building a 12-inch DRAM mega-fab in Lingang, Shanghai, planned for 400,000-600,000 wafers/month — 2-3 times its Hefei headquarters — focused on high-end DDR5, LPDDR5X and HBM3 (a dedicated 50,000 wafers/month), advancing equipment localisation. It moved into substantive progress in March 2026, with tool install in the second half, mass production in 2027 and full capacity in 2028 — a huge new industrial load on the Lingang grid." },
  1761: { descEn: "A new 420 MW hyperscale campus in Jundiaí, São Paulo.", detailEn: "In October 2025 Scala announced a new data-centre campus in Jundiaí planned for 420 MW, with up to $20 billion including direct customer investment, separate from its Tamboré and Eldorado campuses. Creating about 2,500 construction jobs, it is positioned as a Latin American AI-computing and sustainability hub, phasing into service from 2027." },
  2652: { descEn: "A 1,700 km freight rail spine along Australia's east coast.", detailEn: "Inland Rail is a 1,700+ km freight network linking Melbourne and Brisbane at about A$31 billion, built in segments. Using an inland corridor to cut east-coast freight times and improve supply chains, some segments are open and the Melbourne-Parkes section continues — Australia's largest rail project." },
  2659: { descEn: "Australia's largest undeveloped gas field, backfilling the North West Shelf.", detailEn: "In the Browse Basin off Western Australia, this is one of Australia's largest undeveloped conventional gas resources, planned to backfill the existing North West Shelf (NWS) Karratha plant via a subsea pipeline to extend its LNG exports. Subject to environmental approval, it advanced assessment and commercial arrangements in 2025, targeting the 2030s." },
  2739: { descEn: "The EU's €20 billion plan for 4-5 AI 'gigafactories'.", detailEn: "The European Commission proposed in 2025 to invest €20 billion in 4-5 AI 'gigafactories' as an anchor to leverage €200 billion of AI investment. A call for interest drew 76 applications across 60 sites in 16 countries proposing over €230 billion; the formal tender slipped to early 2026, aiming to build a sovereign European AI computing base." },
  2826: { descEn: "Turkey's first nuclear power station (4×VVER-1200).", detailEn: "At Akkuyu in Mersin province, southern Turkey, Russia's Rosatom is building four 1.2 GW VVER-1200 reactors on a build-own-operate basis — Turkey's first nuclear plant, at about $20 billion. Russia added ~$9 billion of financing in 2025, with the first unit aiming to start generating in 2026, eventually supplying about 10% of Turkey's electricity." },
  3026: { descEn: "A 15.6 km new metro line across central Toronto.", detailEn: "The Ontario Line runs 15.6 km from Exhibition Place through downtown to Don Mills (connecting to Line 5), adding 15 stations, at about C$27 billion with over C$4 billion of federal funding. Twin tunnel boring in the downtown section launched in April 2026, with heavy works at four eastern stations, targeting completion in 2031." },
  3580: { descEn: "Chongqing Metro phase 5 (~200 km new lines).", detailEn: "Chongqing's fifth-phase plan adds about 200 km of new lines, with eight lines (including Line 16 phase 1 and several extensions) entering feasibility studies, aiming to bring lines under construction and operating to 850 km. Preliminary phase-5 research will be carried out during the 15th Five-Year period." },
  1542: { descEn: "The world's largest helium source, reaching full capacity in 2025.", detailEn: "The Amur Gas Processing Plant treats gas from the Power of Siberia pipeline across six 7-bcm trains; the fourth came online in 2024 and full design capacity of 42 bcm/year was reached in 2025. At capacity it yields 2.4 million tonnes of ethane, 1.5 million tonnes of LPG and 60 million m³ of helium a year — the world's largest helium base — feeding ethane to the neighbouring Amur GCC." },
  1191: { descEn: "South America's largest shale play, breaking output records in 2025.", detailEn: "In Argentina's Neuquén province, Vaca Muerta is the largest shale oil-and-gas play outside North America. In October 2025 Argentine crude output hit a record 859,500 barrels a day, with Vaca Muerta shale oil ~570,000 b/d, about two-thirds of the nation's total. With 38-40 rigs and over $18 billion of 2025-26 investment, it could top a million barrels a day before 2028, ranking among the world's top three shale plays." },
  2916: { descEn: "A 2,250 MW hydro plant on the Churchill River, Labrador.", detailEn: "On the Churchill River in Newfoundland and Labrador, Gull Island is a 2,250 MW plant with a financed total cost of about C$24.9 billion, a JV of Newfoundland Hydro (60%) and Hydro-Québec (40%) arising from the two provinces' landmark December 2024 memorandum, targeting operation in 2035." },
  2926: { descEn: "A 17-year, up-to-1,920 MW PPA from Talen to power AWS.", detailEn: "In June 2025 Talen and Amazon reached a 17-year, up-to-1,920 MW carbon-free power deal, shifting from a behind-the-meter to a front-of-meter grid structure, with Talen becoming a licensed retail supplier for AWS in Pennsylvania; the two also explore new on-site SMRs and uprates." },
  3499: { descEn: "CXMT Hefei phase-2 DRAM, China's bid for global #4.", detailEn: "CXMT is directing about 130 billion yuan of IPO proceeds into phase-2 wafer manufacturing, pushing its Hefei headquarters toward ~300,000 wafers/month by end-2025 (up ~50% year on year). The phase-2 building is under way and moving to the next process node, consolidating its position as the world's fourth-largest DRAM maker." },
  1179: { descEn: "The finale of Qatar's LNG expansion (North Field West).", detailEn: "The North Field West (NFW) project caps QatarEnergy's North Field expansions, with two 8-MTPA mega-trains adding ~16 million tonnes a year to push Qatar's total toward 142 million tonnes by the 2030s. In February 2026 the onshore liquefaction EPC was awarded to a Technip Energies-led consortium, with first cargo expected by end-2031." },
  1206: { descEn: "The world's largest coal-chemical project under construction.", detailEn: "In the Qingshui Industrial Park of Yulin, Shaanxi, this is the world's largest coal-chemical project under construction, with planned total investment of 126.2 billion yuan over ~13 km² converting 24+ million tonnes of coal a year. Phase 1 focuses on coal-to-ethylene-glycol and phase 2 (~175.9 billion yuan) on coal-to-olefins/aromatics and high-value materials; by September 2025 most phase-2 basic design and long-lead procurement were complete, aiming for a trillion-yuan coal-chemical cluster." },
  1403: { descEn: "Baghdad's first metro network (7 lines, 148 km).", detailEn: "In July 2024 an international consortium (Alstom, Systra, SNCF, Talgo, SENER and Deutsche Bank) won a $17.5 billion contract to build the Baghdad metro on a DBOMFT basis — 7 lines, 148 km and 64 stations, targeting May 2029. In July 2025 the government decided to reassess the financial and technical terms." },
  3220: { descEn: "Microsoft's largest India data-centre region (Hyderabad).", detailEn: "Microsoft announced in 2025 a $17.5 billion four-year (2026-2029) investment to expand AI and cloud infrastructure in India, on top of an earlier $3 billion pledge. Its new Hyderabad region has three availability zones and will be Microsoft's largest in India, due mid-2026, with more land bought in Pune." },
  248: { descEn: "Samsung's largest US investment: an advanced-process fab.", detailEn: "At Taylor, Texas, Samsung's first phase is about $17 billion (eventually up to $44 billion); the main structure was finished by late 2024, with EUV tools installed and risk production in 2026, and Tesla has contracted to use its AI-chip capacity." },
});

/* ===== 批次3：全库投资额 TOP（约 110–170 亿美元）===== */
Object.assign(window.ENERGY_EN, {
  1217: { descEn: "A large new refinery on Mexico's Gulf coast.", detailEn: "At the Dos Bocas port in Paraíso, Tabasco, Pemex's Olmeca refinery is designed for 340,000 barrels a day, producing gasoline and diesel in phases from 2024. By late 2025/early 2026 two crude trains were running at a combined ~320,000 b/d, nearing full capacity by end-2026 — a flagship of Mexico's drive for fuel self-sufficiency." },
  1401: { descEn: "A rail-and-road corridor from Faw port to the Turkish border.", detailEn: "The Development Road is a 1,200 km rail-plus-road corridor linking Iraq's southern Grand Faw Port to the Turkish border, at about $17 billion, intended as an alternative route from the Gulf to Europe. By December 2025 the rail design was ~87% and the road ~73% complete; in September 2025 Iraq said a first Basra-Baghdad high-speed section would be built by 2031." },
  2654: { descEn: "Victoria's largest road project, with a double-deck tunnel.", detailEn: "Melbourne's North East Link includes a ~6.5 km double-deck tunnel connecting the Eastern Freeway with the M80 Ring Road — the largest road project in Victoria's history at about A$26 billion. Tunnelling advanced in 2025, with opening planned for 2028 to ease north-eastern congestion." },
  2805: { descEn: "New Czech nuclear: Korea's KHNP wins two APR1000 units.", detailEn: "At Dukovany in the Czech Republic, Korea's KHNP won the contract to build two 1 GW APR1000 reactors, signed in June 2025 — a major breakthrough for Korean nuclear in Europe — with the first unit targeted around 2036 to strengthen low-carbon baseload supply." },
  3440: { descEn: "CNNC's fusion-industry platform, launched in Shanghai in 2025.", detailEn: "China National Nuclear Corporation renamed and restructured its former fuel arm into China Fusion Energy Co., listed in Shanghai in July 2025 as CNNC's fusion-industry vehicle and investment platform. CNNC, China National Nuclear Power, Zhejiang Energy and others injected about 11.5 billion yuan, accelerating fusion commercialisation by the national team." },
  3583: { descEn: "Yulong Island phase 2, toward a 40-million-tonne refining base.", detailEn: "The Yulong Island integrated refining-petrochemical base in Longkou, Shandong is planned at 40 million tonnes/year in two phases; phase 1 (20 million tonnes of refining + 3 million tonnes of ethylene) started up in 2024-2025. Phase 2 adds another ~20-million-tonne complex, part of Shandong's high-end chemical base, making Yulong Island China's largest single refining-petrochemical base." },
  1145: { descEn: "The core of New York's Gateway program; TBM contract awarded in 2025.", detailEn: "The Hudson Tunnel is the core of the Gateway program's phase 1, building a 3.8 km twin-track rail tunnel under the Hudson River and rehabilitating the century-old, hurricane-damaged existing tunnels, at about $16.1 billion — key to relieving the Northeast Corridor bottleneck. In February 2025 the Gateway Commission awarded a $1.29 billion Hudson River TBM contract (Traylor/Walsh/Skanska), completing all tunnelling contracts, with boring due to begin in spring 2026." },
  511: { descEn: "A Stargate site in Santa Teresa, New Mexico (up to 4.5 GW).", detailEn: "Project Jupiter in Doña Ana County, New Mexico (near El Paso) spans 1,400 acres and four buildings, developed by Stack Infrastructure, leased 18 years by Oracle and mainly used by OpenAI; the county approved $165 billion in industrial revenue bonds — the largest such authorisation for a single US AI data centre to date." },
  512: { descEn: "Stargate's newest site, in Saline Township, Michigan.", detailEn: "OpenAI, Oracle and Related Digital are developing the Stargate campus (codenamed The Barn) in Saline Township, Washtenaw County, Michigan — three 550,000 sq ft buildings exceeding 1 GW — breaking ground on 1 June 2026 with water-saving closed-loop cooling, the largest investment project in Michigan to date." },
  1029: { descEn: "A $16 billion US reshoring expansion.", detailEn: "In January 2025 GlobalFoundries announced $16 billion to expand mature and specialty manufacturing, advanced packaging and silicon photonics in Malta, New York and Vermont, addressing AI's need for power-efficient, high-bandwidth chips, with a new advanced-packaging and photonics centre in New York. The Malta fab has drawn over $16 billion since 2011 and ~2,500 staff — a major local grid customer." },
  1030: { descEn: "The first fab of the world's largest mega-fab cluster.", detailEn: "SK hynix is building a four-fab mega-cluster on a 4.15 million m² site in Yongin, Gyeonggi — billed as the world's largest mega-fab. The first fab broke ground in February 2025 with planned investment of ~21.6 trillion won, due to complete and produce in 2027; the cluster is a huge new power and water node for Korean semiconductors." },
  1143: { descEn: "Set to be the world's longest suspension bridge.", detailEn: "The Strait of Messina Bridge would link Sicily to mainland Italy with a 3,300 m main span — the world's longest suspension span — carrying road and rail. On 6 August 2025 Italy's CIPESS approved the final design, enabling the Webuild-led Eurolink contract (€10.6 billion supplement); works are planned from late 2025 toward 2032 completion, though the Court of Auditors declined to register the decision in October, leaving it not yet formally in force." },
  285: { descEn: "India's largest AI data-centre park.", detailEn: "Adani, via AdaniConneX with Google, is developing India's largest AI data-centre park at Visakhapatnam, Andhra Pradesh — $15 billion, a 1 GW first phase built in 2026-2030 and 5 GW long term, with renewable power." },
  365: { descEn: "An Indigenous-owned floating LNG project in Canada.", detailEn: "Developed by the Nisga'a Nation with Rockies LNG and Western LNG, Ksi Lisims won federal and provincial approval in September 2025 for two floating liquefaction units totalling 12 million tonnes/year, with 5 million tonnes of long-term offtake signed with TotalEnergies, Shell and SEFE; FID is targeted for 2026." },
  505: { descEn: "Amazon's AI data-centre phase-2 expansion in northwest Indiana.", detailEn: "In November 2025 Amazon announced an additional $15 billion for new campuses in northwest Indiana, adding 2.4 GW and up to 22 buildings from 2026 across LaPorte and other counties — the largest construction project in Indiana's history." },
  510: { descEn: "A Stargate Midwest site at Port Washington, Wisconsin.", detailEn: "The Lighthouse campus, developed by OpenAI, Oracle and Vantage at Port Washington north of Milwaukee, comprises four data centres totalling nearly 1 GW, breaking ground in December 2025 for 2028 completion and creating over 4,000 union construction jobs." },
  1135: { descEn: "West Africa's largest integrated mining rail-and-port project.", detailEn: "The Simandou project built a 600+ km multipurpose trans-Guinea railway linking the south-eastern iron-ore zone to a new barging and trans-shipment port on the Atlantic. It opened in early November 2025 with the first export — 9,850 tonnes shipped from Morebaya port on a Winning barge. At capacity the WCS and Rio Tinto/SimFer operations can export 120 million tonnes a year, making Guinea a major supplier of high-grade iron ore; the infrastructure is operated by the JV company CTG." },
  1404: { descEn: "A national railway linking Oman's main ports and cities.", detailEn: "Oman National Railway plans about 2,224 km and 46 stations linking Sohar, Muscat, Duqm and Salalah, at about $15 billion, led by ASYAD's Oman Rail with AIIB financing. Phases include Sohar-Muscat (242 km), Muscat-Duqm (486 km) and Duqm-Salalah (646 km)." },
  1755: { descEn: "A 6.5 GW offshore wind project off Rio Grande do Sul.", detailEn: "Ventos do Sul, ~21 km off Rio Grande do Sul and developed by Ocean Winds, is planned at up to 6.5 GW — one of the largest offshore wind projects in Brazil's pipeline — alongside the 700 MW Tramandaí project nearby. It is seeking preliminary permits from IBAMA, awaiting Brazil's first offshore-area auction (planned 2027)." },
  1869: { descEn: "A Red Sea green hydrogen/ammonia hub, nearly twice NEOM's size.", detailEn: "The first phase of the ACWA Power-EnBW Yanbu green-hydrogen hub on the Red Sea, with its own renewables, desalination and export jetty, has 4 GW of electrolysers producing 400,000 tonnes of green hydrogen and 2.2 million tonnes of green ammonia a year — about twice the NEOM project under construction. FEED by Técnicas Reunidas and Sinopec is due mid-2026, with FID in 2026 and start-up in 2030." },
  2057: { descEn: "A giant reclaimed-land airport north of Manila in Bulacan.", detailEn: "On the Bulacan coast ~35 km north of Manila, San Miguel Corporation (SMC) is developing this airport under a ~734 billion-peso concession with four runways. A Manila Bay sand-mining ban pushed phase 1 back a year; SMC commits to start the passenger terminal in January 2026, targeting opening in November 2028 with ~35 million passengers a year to relieve NAIA." },
  2063: { descEn: "The world's largest fully automated container port.", detailEn: "Singapore's largest-ever infrastructure project, Tuas Port is reclaimed in four phases for an eventual 65 million TEU a year — the world's largest single fully automated container terminal. In May 2025 it hit a 10-million-box milestone using 200 fast-charging automated guided vehicles, progressively consolidating city berths like Tanjong Pagar, with full completion in the 2040s." },
  2068: { descEn: "Deepwater gas fields in East Kalimantan feeding Bontang LNG.", detailEn: "In March 2026 Eni took a double FID on the deepwater Geng North-Gehem (North Hub) and Gendalo-Gandang (South Hub) gas clusters in Indonesia's Kutai Basin, at about $15 billion. Using the Jangkrik FPU and existing Bontang LNG facilities, the North Hub adds an FPSO (>1 Bcf/d, 90,000 b/d condensate), targeting 2028 start-up, a 2 Bcf/d peak in 2029 and the restart of an idle Bontang train." },
  3005: { descEn: "A 1.8 GW, 40-building data-centre campus in Buckeye, Arizona.", detailEn: "In August 2024 Tract acquired ~2,069 acres in Buckeye — one of the largest single data-centre land purchases in the US — planning up to 20 million sq ft and 40 facilities, with 1.8 GW delivered by the local utility over multi-phase construction lasting up to 15 years." },
  3037: { descEn: "A Pacific-coast LNG project in Sonora, advancing toward FID.", detailEn: "At Puerto Libertad in Sonora, Mexico, this 30-million-tonne/year project is pushing for a phase-1 FID (three 5-million-tonne trains), with gas from the Permian's Waha hub via the Saguaro Connector and Sierra Madre pipelines, arranging ~$15 billion of financing with MUFG, Santander and JPMorgan." },
  3207: { descEn: "A 3-million-tonne greenfield aluminium smelter in Odisha with captive power.", detailEn: "Vedanta Aluminium is building a greenfield integrated aluminium plant near Kamakhyanagar in Dhenkanal, Odisha on 1,447 acres, with 3 million tonnes/year of smelting and a 4,900 MW captive power station, at about 1.3 trillion rupees — set to be one of the world's largest aluminium smelters, approved at Odisha's 41st high-level clearance and expected to create 30,000 jobs." },
  1024: { descEn: "An HBM-focused fab for the AI era.", detailEn: "M15X is SK hynix's new 12-inch fab in Cheongju, with over 20 trillion won of investment focused on HBM and next-generation DRAM to meet AI-driven high-bandwidth memory demand, lifting HBM capacity by ~20-30%. The building was completed in November 2025 with tool move-in from December — a huge new industrial load on Cheongju's grid." },
  3253: { descEn: "An ~865 km Delhi-Varanasi high-speed railway.", detailEn: "The DVHSR is designed for 350 km/h over 865 km, including a 135 km Ayodhya/Lucknow spur and ~12 stations, at about 1.21 trillion rupees. NHSRCL has submitted the DPR to the Railway Ministry; the most advanced of the new HSR corridors, it would cut Delhi-Varanasi to ~4-4.5 hours." },
  3565: { descEn: "A road-rail sea crossing set to be China's longest sea bridge.", detailEn: "About 70 km long — longer than the Hong Kong-Zhuhai-Macao Bridge — this combined road-and-rail crossing (carrying cars and 350 km/h high-speed rail) east of the Hangzhou Bay Bridge would cost about 100 billion yuan. Included in the national 15th Five-Year Plan and Zhejiang's plan, it would put Shanghai-Ningbo high-speed rail within a half-hour." },
  1171: { descEn: "A large export LNG expansion on the Texas Gulf coast.", detailEn: "Sempra's phase-2 expansion of its Port Arthur, Texas LNG base adds two liquefaction trains and storage for ~13 million tonnes a year nameplate. It reached FID in September 2025, with Blackstone leading equity and ConocoPhillips as anchor buyer, targeting 2030-2031 start-up — an important addition to US LNG supply to Europe and Asia." },
  1222: { descEn: "Aramco exits; Petronas takes full ownership of the RAPID complex.", detailEn: "At the Pengerang complex in Johor, Malaysia, the RAPID integrated base pairs a 300,000 b/d refinery with large petrochemicals. In May 2026 Saudi Aramco announced its exit, transferring its stake to Petronas so PRefChem becomes a wholly-owned Petronas subsidiary; Aramco had invested ~$7 billion for 50% in 2017. The plant resumed operation after a 2025 gasoline-unit turnaround and brief RFCC shutdown." },
  1549: { descEn: "A cornerstone gas field for the Irkutsk region, full capacity in 2027.", detailEn: "Kovykta started up in late 2022 with the Kovykta-Chayanda section of the Power of Siberia pipeline; with ~1.8 trillion m³ of reserves and 27 bcm/year design output, it is the cornerstone of the Irkutsk gas zone. Power of Siberia reached its 38 bcm design capacity in 2025, and in September 2025 Russia and China agreed to raise supply to 44 bcm, with the pipeline at full capacity in 2027." },
  2809: { descEn: "Two new AP1000 units in Bulgaria.", detailEn: "At Kozloduy on the Danube in Bulgaria, two 1.1 GW Westinghouse AP1000 reactors are planned, advancing engineering contracts and financing in 2025 to replace retiring units and strengthen low-carbon baseload supply in southeastern Europe, targeting the mid-2030s." },
  2811: { descEn: "A series-build base for the Hualong One reactor; unit 2 online in 2026.", detailEn: "At Zhangzhou in Fujian, this base uses China's home-grown third-generation 'Hualong One' reactor, with six 1.2 GW units planned. Unit 1 started up in 2024 and unit 2 connected in November 2025 and entered commercial operation on 1 January 2026, with more units following — the flagship for series, scaled Hualong One construction." },
  1011: { descEn: "Toyota's first battery plant outside Japan, online in November 2025.", detailEn: "On an ~1,850-acre mega-site in Liberty/Randolph County, North Carolina, this nearly $13.9 billion plant is Toyota's 11th globally and its only battery plant outside Japan. Planned for 14 lines and ~30 GWh supplying HEV/PHEV/BEV batteries across ~7 million sq ft, it is a regional-scale power user creating up to 5,100 jobs; it began production on 12 November 2025, first making hybrid batteries." },
  1199: { descEn: "BASF's third-largest global site; core units online in late 2025.", detailEn: "On Donghai Island in Zhanjiang, Guangdong, this is BASF's largest overseas wholly-owned investment at about €10 billion, set to become its third-largest global site with 30+ lines and 100+ products. The core is a 1-million-tonne/year steam cracker with integrated downstream; the first core-unit products started in November 2025 with 100% green-power supply, serving autos, electronics, new energy and food packaging." },
  4212: { descEn: "China's largest private overseas investment; PMB refining phase 2 in Brunei.", detailEn: "Hengyi's PMB project on Pulau Muara Besar, Brunei has a ~$13.65 billion phase 2 adding 14 million tonnes/year of refining, 1.65 million tonnes of ethylene, 2 million tonnes of paraxylene and downstream PTA/PET, fully to Chinese standards. Phase 1 started up in 2019; phase 2 was confirmed in early 2026 with ~3-year construction, with CPECC-system engineering firms involved in design and EPC." },
  102: { descEn: "Inner Mongolia's first 10-GW-class desert wind-and-solar base.", detailEn: "This base plans 8 GW of solar and 4 GW of wind, with 4 GW of supporting coal power and 5 GWh of storage, at 98.8 billion yuan. A 2 GW pilot solar phase is connected, with the ±800 kV 'Ordos-Cangzhou' UHV line as export; full construction began in September 2025, targeting completion by end-2027." },
  2081: { descEn: "PMB refining phase 2, a flagship China-Brunei joint venture.", detailEn: "Hengyi Petrochemical's phase-2 refining-petrochemical project on Pulau Muara Besar (PMB), Brunei fully launched in January 2026 with a ~$13.6 billion package (Bank Islam Brunei financing and tax incentives). It adds a 1.65-million-tonne/year naphtha cracker and PE/PP units (Brunei's first polymer plant) and expands PTA/PET, lifting total refining capacity to 20 million tonnes/year (~400,000 b/d); completion is planned for end-2028 and start-up in 2029, adding over 2,000 jobs." },
  1220: { descEn: "A major Russia-to-China gas artery via Mongolia.", detailEn: "Advanced by Gazprom and CNPC, Power of Siberia 2 would carry West Siberian gas via the ~963 km Soyuz Vostok section through Mongolia to China, with 50 bcm/year design capacity over a term of up to 30 years. In September 2025 Russia and China signed a legally binding memorandum in Beijing — the project's biggest progress in years — though the sales contract and pricing remain unsettled, with the Mongolian section targeted for 2027-2028." },
  3554: { descEn: "A new 350 km/h line from Hunan to Guangzhou, starting 2026.", detailEn: "About 390 km at 350 km/h and ~95.1 billion yuan, this line runs from Yongzhou via Lianzhou and Qingyuan to north Guangzhou. It would cut Yongzhou-Guangzhou from 3h10 to 1.5 hours, strengthening links between southern Hunan and the Greater Bay Area; both Hunan and Guangdong have set 2026 construction starts." },
  309: { descEn: "India's first high-speed rail, using Japanese Shinkansen technology.", detailEn: "Using Japan's E5 Shinkansen technology, this 508 km, 320 km/h line with 12 stations is 88% financed by JICA soft loans. Civil works were 56% complete by early 2026, with the first Surat-Bilimora section likely to open in 2026." },
  322: { descEn: "A core rail-capacity project for Brisbane.", detailEn: "Cross River Rail is 10.2 km including a 5.9 km twin-track tunnel under the Brisbane River and CBD with four new underground stations, with costs rising from A$5.4 billion to over A$17 billion and opening pushed to 2029." },
  582: { descEn: "Europe's largest dedicated AI data centre, at Blyth, Northumberland.", detailEn: "Blackstone's QTS is investing about £10 billion at Blyth in Northumberland, England, building a 540,000+ m² hyperscale AI campus with 10 data halls on the former Britishvolt battery site; approved in 2025, it would become Europe's largest dedicated hyperscale AI data centre when built." },
  833: { descEn: "World Bank backing to revive the Grand Inga hydropower scheme.", detailEn: "At the Inga Falls on the Congo River in DR Congo, Inga III is planned at ~4.8 GW, with full Grand Inga development reaching 44 GW. In June 2025 the World Bank approved $250 million of first-phase credit for preparatory studies and the AFD signed technical support in 2026; total investment exceeds $10 billion, with no FID yet." },
  1141: { descEn: "A 57.5 km cross-Alps tunnel; main-tunnel boring began in 2025.", detailEn: "The Lyon-Turin base tunnel is the core of Europe's Mediterranean corridor, with a 57.5 km main tunnel that will rank among the world's longest rail tunnels. TBM Viviana was unveiled at Saint-Martin-la-Porte on 1 April 2025 and the first French-side machine began boring at La Praz in July; by late October ~45.3 km was excavated. Seven TBMs will ultimately bore 75% of the base tunnel, shifting France-Italy freight from road to rail, with Italian-side boring expected in 2027." },
  1142: { descEn: "The UK's largest road-tunnel project; approved and funded in 2025.", detailEn: "The Lower Thames Crossing is Britain's largest road-tunnel project — 23 km linking Kent's A2/M2 with Essex's A13/M25, centred on a 4.2 km twin-bore tunnel under the Thames (the UK's longest road tunnel) to relieve the Dartford Crossing. The Development Consent Order was approved on 25 March 2025; the government committed £590 million in June and a further £891 million in November for the public share, with private finance to follow and early works from March 2026." },
  1176: { descEn: "A new LNG export train for Papua New Guinea.", detailEn: "Led by TotalEnergies with ExxonMobil and Santos, Papua LNG would pipe gas ~320 km to new electric-drive trains at the liquefaction base outside Port Moresby, exporting about 5.6 million tonnes a year. Environmental permits and EPC contracts came together in late 2025, with FID advancing to early 2026." },
  2269: { descEn: "A trans-Saharan gas pipeline from Nigeria via Niger to Algeria (30 bcm/year).", detailEn: "The long-planned Trans-Saharan Gas Pipeline (TSGP) aims to start construction in 2026, carrying Nigerian gas via Niger to Algeria and on to Europe, with 30 bcm/year design capacity. The Algerian section crosses the Hassi R'Mel hub into the existing export network — a flagship cross-border project to boost Algeria's supply to Europe, partly overlapping the SoutH2 hydrogen corridor." },
  2806: { descEn: "Hungary's nuclear expansion (2×VVER-1200).", detailEn: "At Paks in Hungary, Russia's Rosatom is building two 1.2 GW VVER-1200 reactors, pouring first concrete in February 2025 to enter main construction. The new government is reviewing financing and costs, but the project is advancing and will sharply raise Hungary's nuclear share." },
  2820: { descEn: "Bangladesh's first nuclear plant; fuel loading in 2026.", detailEn: "At Rooppur in Pabna, Bangladesh, Russia's Rosatom is building two 1.2 GW VVER-1200 reactors — Bangladesh's first nuclear plant, at about $12.7 billion. The first unit completes fuel loading in April-May 2026 and will start generating that year, marking Bangladesh's entry into the nuclear age." },
  2832: { descEn: "The West's first grid-scale small modular reactor.", detailEn: "At Darlington in Ontario, OPG is building four GE Hitachi BWRX-300 small modular reactors (~1.2 GW total); the first unit formally began construction in 2025 — the first grid-scale SMR in the G7/West. At about C$20.9 billion, the first unit targets 2030, providing a template for global BWRX-300 deployment." },
  2954: { descEn: "Texas's first 765 kV lines, strengthening Permian supply.", detailEn: "In April 2025 the Texas PUC approved the ERCOT Permian reliability plan, building the state's first 765 kV lines with three import paths. Driven by data centres, hydrogen and electrification, ERCOT's 2030 summer peak is projected above 150 GW." },
  3007: { descEn: "Microsoft's ~C$19 billion AI and cloud build in Canada (2023-2027).", detailEn: "In December 2025 Microsoft announced a landmark Canadian investment of ~C$19 billion over 2023-2027, including over C$7.5 billion in the next two years for new digital and AI infrastructure, with new capacity from late 2026 deepening cloud regions such as Toronto." },
  3054: { descEn: "One of the world's largest potash mines (~8.5 Mt/year across two phases).", detailEn: "BHP's giant Jansen potash project in Saskatchewan, Canada (phase 1 ~$8.4 billion, phase 2 $4.9 billion) doubles capacity to about 8.5 million tonnes. Phase 1 was ~68% complete in early 2026, with costs rising on inflation and first production pushed to mid-2027." },
  4211: { descEn: "Power of Siberia support: one of the world's largest gas-processing plants.", detailEn: "The Amur Gas Processing Plant (AGPP) in Russia's Amur region is key to Gazprom's east-route supply to China, processing 42 bcm of gas a year and extracting helium. The CPECC system (including HQC) executed the EPC for package 2 — six trains of gas drying, purification, fractionation and compression — worth about $2.52 billion, built in five stages with start-ups through 2024-2025." },
  4231: { descEn: "The world's largest ethylene complex; CNCEC FEED+EPC ~€12 billion.", detailEn: "The Baltic Chemical Complex (BCC) at Ust-Luga, Russia, invested by RusGasDobycha, is the world's largest integrated ethylene project, producing 2.8 million tonnes of ethylene and 2.88 million tonnes of polyethylene a year. China National Chemical Engineering signed the FEED+EPC contract in 2019 worth about €12 billion, using world-leading process technology." },
  1193: { descEn: "Stabroek's fifth development; first oil in 2026.", detailEn: "Uaru is ExxonMobil's fifth development in Guyana's Stabroek block, ~200 km offshore in 1,750 m of water with over 800 million barrels of recoverable reserves. The Errea Wittu FPSO (250,000 b/d, 2 million barrels storage) completed mooring pre-installation in February 2026, with first oil expected within the year, continuing Guyana's rapid offshore ramp-up." },
  3589: { descEn: "A 100-billion-yuan-class coal-to-liquids plant using world-first 2nd-gen direct technology.", detailEn: "In the Chahaquan park of Barkol, Hami, Xinjiang, this project plans ~170 billion yuan total (~90 billion for stage 1), with a 15-million-tonne/year open-pit mine feeding 19 units including 3.2 million tonnes/year of direct and 800,000 tonnes/year of indirect coal liquefaction — China's first to use home-grown second-generation direct coal-liquefaction technology. Started in October 2024 and in civil works, it targets completion by end-2027." },
  1185: { descEn: "Stabroek's fourth and highest-capacity FPSO.", detailEn: "About 200 km offshore in 1,800 m of water in Guyana's Stabroek block, this is ExxonMobil's fourth development there. The ONE GUYANA FPSO produced first oil on 8 August 2025, about four months ahead of plan, at 250,000 b/d and 2 million barrels storage, pushing Guyana's total above 900,000 b/d and cementing its status as an emerging major producer." },
  1833: { descEn: "Phase 2 of the Middle East's largest unconventional gas field, online 2027.", detailEn: "As phase 2 of Aramco's $100-billion-class Jafurah project, a ~$12.4 billion contract was signed in June 2024 adding ~1,350 million cubic feet/day of processing. Phase 1 saw first gas in December 2025; phase 2 is due in 2027, driving the field toward 2 bcf/d of sales gas and ~630,000 b/d of high-value liquids by 2030, supplying low-cost feedstock for blue hydrogen and petrochemicals." },
  348: { descEn: "A $12 billion China-Saudi integrated refining-petrochemical JV in Liaoning.", detailEn: "A JV of Saudi Aramco (30%), Norinco (51%) and Panjin Xincheng (19%), this complex in Panjin, Liaoning began in 2023 at about $12 billion, building 300,000 b/d of refining and 1.65 million tonnes of ethylene; ~60% complete in 2025 with start-up expected in 2026." },
  1023: { descEn: "Japan's national 2nm breakthrough fab.", detailEn: "In the Bibi industrial park of Chitose, Hokkaido, Rapidus is Japan's national push for 2nm, co-developing GAA transistors with IBM. It installed Japan's first production-grade ASML EUV in late 2024, started a pilot line in April 2025 and announced working 2nm GAA transistors in July; the advanced EUV fab is a very-high-density grid load, targeting mass production in 2027." },
  1144: { descEn: "The first true US high-speed rail, along the I-15 corridor.", detailEn: "Brightline West is the first true US high-speed railway, ~350 km along the I-15 median linking Las Vegas and Rancho Cucamonga in Southern California, with all-electric trains over 300 km/h covering the route in about 2h10. Backed by a $3 billion federal grant and private activity bonds, it ran geotechnical drilling and surveys along I-15 through 2025; the Las Vegas station garage takes shape in early 2026, with heavy rail construction from April 2026 toward a late-2029 opening." },
  1158: { descEn: "A 1,500 km heavy-haul freight corridor from JNPT to Dadri.", detailEn: "Built by DFCCIL, the Western Dedicated Freight Corridor runs 1,506 km from Mumbai's JNPT to Dadri near Delhi — a double-track electrified heavy-haul line for containers and bulk that, with the eastern corridor, is reshaping Indian rail freight. After the JNPT-Vaitarna section was commissioned on 31 March 2026, DFCCIL declared the Western corridor fully open; ~96.4% of the two corridors' 2,843 km is now in service, sharply raising daily freight trains." },
  1175: { descEn: "A large WA gas-liquefaction expansion.", detailEn: "Woodside's Scarborough gas field is piped to a new Train 2 at the Pluto base in Karratha, ~5 million tonnes/year, with Train 1 modified for lean gas. By early 2026 it was over 96% complete, with 56,000-tonne modules delivered from Batam, Indonesia, sprinting to start-up — an important new WA LNG supply to Asia." },
  1754: { descEn: "A 5 GW giant offshore wind project off Rio de Janeiro.", detailEn: "Developed by OW Brasil (Ocean Winds, a 50/50 EDPR-ENGIE JV) in the South Atlantic off Rio de Janeiro, this 5 GW project with 371 13.5 MW turbines is one of Brazil's largest offshore wind projects under review. Ocean Winds has ~15 GW planned in Brazil (including Ventos do Sul 6.5 GW and Tramandaí 700 MW) and is seeking a preliminary licence from IBAMA, awaiting the offshore-area auction." },
  1900: { descEn: "A 45-billion-riyal Jeddah transit plan with a four-line light-rail network.", detailEn: "Saudi Arabia's cabinet approved a ~$12 billion (45 billion-riyal) Jeddah transport master plan with a 108 km light-rail network. The first Blue Line (~35 km) links King Abdulaziz International Airport to the Haramain high-speed station, and the Orange Line runs ~44.8 km along Medina and Old Mecca roads. Blue Line design tenders were issued in January 2026 (closing March), targeting operation before the 2034 World Cup, with Foster + Partners involved in design." },
  2071: { descEn: "Southwest offshore gas plus pipeline supplying the Ca Mau power complex.", detailEn: "The Block B (48/95 and 52/97) offshore gas field is piped ~400 km to the O Mon power complex in Ca Mau, Vietnam, with the value chain totalling nearly $12 billion. FID was taken on 28 March 2024 for ~490 million cubic feet/day; Petrovietnam has secured a $1 billion loan from Vietcombank. The central processing platform was completed in 2025, with first gas planned for Q3 2027." },
  2642: { descEn: "Microsoft's A$25 billion Australian cloud and AI supercomputing expansion.", detailEn: "In April 2026 Microsoft announced about A$25 billion to build new Azure AI supercomputing capacity in Australia and expand existing data centres by ~140%, concentrated around Western Sydney. The investment is ~1.9 times AWS's A$13.2 billion pledge, aimed at sovereign cloud and GPU-intensive AI workloads." },
  3116: { descEn: "A Gujarat green hydrogen/ammonia hub, about $12 billion.", detailEn: "At the Deendayal Port Authority in Kandla, Gujarat, Reliance, L&T, Greenko and Welspun New Energy are developing a ~$12 billion hub producing 1.4 million tonnes of green hydrogen and 7 million tonnes of green ammonia a year — a flagship cluster of India's National Green Hydrogen Mission, aimed at fertiliser and export." },
  3218: { descEn: "Planned 2.5 GW — potentially India's largest single data-centre park.", detailEn: "At Davos in January 2026, Lodha and Maharashtra signed to build a 2.5 GW data-centre park (about 1.3 trillion rupees) on ~350 acres of a 5,000-acre Palava site, expected to create over 16,000 jobs; Amazon has bought land and locked in 15-year power, and STT GDC has also acquired land." },
  3255: { descEn: "An ~1,738 km east-west freight corridor (planned).", detailEn: "The East-West Dedicated Freight Corridor (EWDFC) is planned for ~1,738 km from Palghar in Maharashtra to Dankuni in West Bengal; its DPR was sent to the Railway Board in July 2024 and remained under review as of November 2025, not yet sanctioned." },
  1114: { descEn: "A high-speed trunk line in the Chengdu-Chongqing Yangtze corridor.", detailEn: "The Chengda-Wan high-speed railway, part of the national Yangtze corridor, is designed for 350 km/h at about 85.1 billion yuan. It entered ballastless-track works in April 2025; by end-2025, 130 of 136 tunnels were through, bridges 86% and subgrade 96% complete. Targeting completion in September 2027, it would cut Chengdu-Dazhou from ~3 hours to just over one." },
  2951: { descEn: "An $11.8 billion PJM expansion to meet surging data-centre load.", detailEn: "Selected from 134 proposals, this PJM package includes a new 765 kV line and multiple 500 kV upgrades, mainly to serve Virginia data-centre load, with ~$4.8 billion in Dominion's territory — a sharp increase from 2024." },
  2910: { descEn: "The largest US offshore wind farm (2.6 GW, 176×14 MW turbines).", detailEn: "Off the southeast coast of Virginia, this 2.6 GW farm with 176 Siemens Gamesa 14 MW turbines will be the largest US offshore wind farm, owned by Dominion and Stonepeak at about $11.5 billion. The first commercial turbine sent power in March 2026 with the project ~75% complete." },
  3276: { descEn: "A new BPCL greenfield refinery in Nellore, Andhra Pradesh.", detailEn: "In October 2025 Andhra Pradesh allotted BPCL 6,000 acres near the Ramayyapatnam deep-water port, with ~960 billion rupees invested over FY26-FY30 for 9-12 million tonnes/year of refining plus petrochemicals, targeting January 2029 start-up. The state pledges up to 75% capex subsidy over 20 years — the first sub-project to land after the west-coast mega-refinery was split up." },
  3555: { descEn: "A new 350 km/h line filling a gap in the Qingdao-Yinchuan corridor.", detailEn: "239 km at 350 km/h and about 81.3 billion yuan, this line is part of the Qingdao-Yinchuan high-speed corridor, linking Shanxi toward Yulin in Shaanxi. Shanxi has listed it as a priority high-speed start for 2026." },
  195: { descEn: "One of Japan's largest infrastructure projects.", detailEn: "Japan's first long-distance HVDC subsea cable, ~800 km and 2 GW, links Hokkaido with the Sea-of-Japan side of Honshu to bring Hokkaido's abundant renewables to the Tokyo area. OCCTO evaluates and awards bids in March 2026, with an ~8-year build toward completion around 2033." },
  349: { descEn: "A world-class petrochemical complex at Jubail, Saudi Arabia.", detailEn: "SATORP, a JV of TotalEnergies and Saudi Aramco, took FID in December 2022 to build 1.65 million tonnes of ethylene and two 500,000-tonne polyethylene units at Jubail, using refinery off-gases as feedstock, with commercial operation expected in 2027." },
  504: { descEn: "The world's largest AI training supercluster, built for Anthropic in Indiana.", detailEn: "AWS's Project Rainier in New Carlisle, Indiana spans 1,200 acres, planned for 30 buildings and 2.2 GW of IT load running ~500,000 Trainium2 chips — the world's largest non-Nvidia AI training cluster. Construction began in September 2024 and phase 1 came online in October 2025, dedicated to Anthropic training its Claude models." },
  942: { descEn: "Germany's largest transmission project, sending northern wind south.", detailEn: "SuedLink runs ~700 km from Wilster in the north to Bergrheinfeld in Bavaria, comprising two parallel ±525 kV DC lines totalling 4 GW at about €10 billion, built by Prysmian and NKT. First trenching began in August 2024, with works across several states through 2025." },
  980: { descEn: "The largest US transmission project under construction.", detailEn: "Grain Belt Express crosses Kansas, Missouri, Illinois and Indiana as a ±600 kV/5 GW HVDC line, ~1,280 km long. It won all state permits in 2025 and awarded $1.7 billion of construction contracts, with construction in 2026 and a first section expected in service in 2029." },
  1022: { descEn: "Europe's first FinFET-capable foundry JV.", detailEn: "Controlled by TSMC with Bosch, Infineon and NXP in the Dresden 'Silicon Saxony' cluster, this over-€10 billion plant is the EU's first pure-play foundry with FinFET capability, planned for 40,000 12-inch wafers/month for automotive and industrial chips — a city-scale power and water user driving Saxon grid and ultra-pure-water expansion. The structure topped out in November 2025, with tools in late 2026 and production in 2027." },
  1162: { descEn: "A passenger-and-freight railway across the Malay Peninsula.", detailEn: "The East Coast Rail Link connects Kelantan, Terengganu and Pahang on the east coast with Selangor and Port Klang on the west, 665 km, built by MRL with China Communications Construction — a key Belt and Road project carrying passengers and freight. Civil works reached 91.7% by January 2026, ahead of schedule; phase 1 (Kota Bharu-Gombak) is set for testing in June 2026 and opening in January 2027, with phase 2 to Port Klang due in 2027." },
  1299: { descEn: "A new Brazilian oil frontier; SBM to build two FPSOs.", detailEn: "In April 2026 Petrobras's board took FID on SEAP I in the Sergipe-Alagoas basin, and on 29 May signed for two SBM Offshore FPSOs (BOT model) totalling 240,000 b/d and 22 million m³/day of gas processing. At over 60 billion reais and expected to recover over a billion barrels of oil equivalent, SEAP II plans oil in 2030 and gas exports in 2031." },
  1432: { descEn: "The Middle East's only fully integrated bauxite-to-aluminium base.", detailEn: "At Ras Al Khair on Saudi Arabia's east coast, the Ma'aden-Alcoa JV is the only aluminium base in the Middle East with its own alumina supply — an 1.8-million-tonne alumina refinery, a 740,000-tonne smelter (two potlines) and a 380,000-tonne rolling mill, fed by 4 million tonnes/year of bauxite from Az Zabirah / Al Baitha in the north." },
  1541: { descEn: "Set to be one of the world's largest base-polymer plants.", detailEn: "The Amur Gas Chemical Complex near Svobodny, adjacent to the Amur GPP for ethane feedstock, is a JV of SIBUR (60%) and Sinopec (40%) at about $11 billion, designed for 2.3 million tonnes of polyethylene and 400,000 tonnes of polypropylene a year. After European contractors Linde and Technip withdrew in 2022, SIBUR and Sinopec redesigned it and changed licensors; it was 87.9% complete by end-September 2025." },
  2650: { descEn: "A fully underground metro from Parramatta to Sydney CBD.", detailEn: "A ~24 km fully underground automated metro linking Parramatta and Sydney CBD, greatly boosting capacity between the two business centres. Tunnelling has advanced, and it is one of NSW's largest rail projects, targeting opening around 2030." },
  3048: { descEn: "A BC gas trunkline feeding LNG Canada, online in November 2024.", detailEn: "Coastal GasLink entered commercial service in November 2024, running 670 km from Dawson Creek over the Rockies to Kitimat, carrying Montney gas to the LNG Canada export terminal at 2.1 bcf/d, expandable to 5 bcf/d." },
});

/* ===== 批次4：全库投资额 TOP（约 85–110 亿美元）===== */
Object.assign(window.ENERGY_EN, {
  3217: { descEn: "A nationwide AI-ready compute network with Reliance and Nvidia (up to 2 GW).", detailEn: "Nvidia and Reliance Jio are building AI infrastructure for India hosted in AI-ready data centres, expanding to 2,000 MW long term. Reliance unveiled a ~$110 billion AI plan in February 2026 with nationwide sites beyond Jamnagar, bringing 120+ MW online in late 2026 on the Nvidia Blackwell platform." },
  3400: { descEn: "The first 10-GW-class export project of Inner Mongolia's largest desert base.", detailEn: "In the north-central Kubuqi Desert of Ordos, this base plans 12.2 GW of renewables (8 GW solar, 4 GW wind) with 4 GW of supporting coal power and 5 GWh of storage, exporting to north China via a ±800 kV line. Prioritising desertification control, full grid connection is targeted for end-2027." },
  4261: { descEn: "An east-west electrified railway across the Malay Peninsula, EPC by a Chinese firm.", detailEn: "Malaysia's East Coast Rail Link (ECRL), with EPC by China Communications Construction, runs ~665 km from Kota Bharu on the east coast to Port Klang/Gombak in the west at 160 km/h, with electric trainsets. At about RM50.3 billion (~$11 billion) it is a signature Belt and Road project; the Gombak tunnel broke through in early 2025, with commercial operation planned for January 2027." },
  4396: { descEn: "HQC's role in the Amur GPP, one of the world's largest gas-processing plants.", detailEn: "The Amur Gas Processing Plant near Svobodny in Russia's Amur region is one of the world's largest, processing 42 bcm of gas and 60 million m³ of helium a year across six trains as the supply hub for the Russia-China east-route pipeline. The first train started in June 2021 with all online through 2025; HQC (Huanqiu) handled design and EPC work, mastering large-scale gas-processing and helium-extraction technology." },
  140: { descEn: "A giant North Sea offshore wind farm under construction off Yorkshire.", detailEn: "About 120 km off the Yorkshire coast, this ~2.85 GW farm uses up to 231 14 MW turbines. After FID in December 2023, Ørsted sold a 50% stake to an Apollo fund in November 2025 to advance construction; the first export cable landed in April 2026, with full output expected in 2027 — set to be one of the world's largest single offshore wind farms." },
  1190: { descEn: "Suriname's first offshore oilfield development, with an FPSO under construction.", detailEn: "In Block 58 ~150 km off Suriname, GranMorgu develops the Sapakara and Krabdagu discoveries (over 750 million barrels recoverable) — Suriname's first offshore oil project. FID was taken in October 2024 and SBM won the 220,000 b/d FPSO in June 2025; the hull was about half built by end-2025, with first oil planned for 2028 to launch Suriname's oil era." },
  157: { descEn: "One of the world's largest planned onshore wind projects.", detailEn: "Over ~3,025 km² in western Sohag governorate, Egypt, this onshore wind project is developed by Masdar, Infinity Power and Hassan Allam, with a land-access deal signed in May 2024; once built it would cut 23.8 million tonnes of CO₂ a year, ~9% of Egypt's emissions." },
  279: { descEn: "Europe's largest planned AI data-centre campus.", detailEn: "On Portugal's Atlantic coast at Sines, this 1.2 GW campus saw SIN01 go live in April 2025, with Microsoft committing $10 billion and Nscale deploying 12,600+ Nvidia Blackwell Ultra GPUs, using zero-water-withdrawal ocean cooling with a target PUE of 1.1." },
  357: { descEn: "The ninth US LNG export terminal.", detailEn: "At Sabine Pass, Texas, Golden Pass LNG is developed by QatarEnergy (70%) and ExxonMobil (30%) with three trains for ~18 million tonnes a year, cooling down in late 2025 and first export in early 2026 to become the ninth operating US LNG export terminal." },
  363: { descEn: "A giant oilfield in Namibia's Orange Basin.", detailEn: "Discovered in 2022 with estimated reserves over 3 billion barrels, Venus is one of the most important recent deep-water discoveries globally, operated by TotalEnergies. An FPSO-based development targets FID in early 2026 for 150,000-180,000 b/d, with first oil in 2029-2030." },
  501: { descEn: "A multi-gigawatt AI training campus in New Albany, Ohio, nuclear-backed.", detailEn: "Meta is building the Prometheus campus in New Albany, Ohio with ~1.5 GW of IT load, powered mainly by nuclear and renewables — a core base for training Meta's next-generation models, with the first facilities due in early 2026 using dense liquid cooling." },
  517: { descEn: "QTS's largest-ever single campus, in Cedar Rapids, Iowa.", detailEn: "In August 2025 QTS announced $10 billion on 612 acres in the Big Cedar industrial park at Cedar Rapids, Iowa, planning seven buildings; three topped out in October, with first use expected in 2027 — next to a Google campus and the largest economic-development project in Cedar Rapids' history." },
  643: { descEn: "The largest undeveloped US copper mine; a 2025 Supreme Court ruling cleared a land appeal.", detailEn: "Near Superior, Arizona, this deposit lies 5,000-7,000 ft underground with potential reserves of ~40 billion lb of copper, enough for ~25% of US demand. A shaft-conversion milestone was reached in June 2025, the same month the Supreme Court declined a Native American appeal clearing the land transfer, with construction expected around the 2030s." },
  1136: { descEn: "Planned to be East Africa's largest deep-water port.", detailEn: "Bagamoyo Port restarted after over a decade stalled. On 6 December 2025 Tanzania's TPA signed an MoU with France's AGL (an MSC subsidiary) to design, build and operate a first three berths in ~36 months, with works from early January 2026. The ~$10 billion master plan envisions 28 berths and an SEZ for 20 million TEU a year — 25 times Dar es Salaam's port — reshaping East African trade." },
  1170: { descEn: "An LNG export expansion at an operating Texas terminal.", detailEn: "Cheniere's 7-train midscale expansion at Corpus Christi, Texas adds over 10 million tonnes a year, lifting the site above 25 million tonnes. The first trains produced LNG by end-2024 and the first cargo shipped in February 2025, with more trains reaching substantial completion through 2025-2026 — emblematic of the new US LNG export wave." },
  1198: { descEn: "The first wholly US-owned major petrochemical project in China, online July 2025.", detailEn: "At the Daya Bay petrochemical zone in Huizhou, Guangdong, this is the first major petrochemical project wholly owned by a US company in China, at about $10 billion. Phase 1 includes a 1.6-million-tonne flexible-feed cracker, two 1.2-million-tonne LLDPE lines, a world-largest single 500,000-tonne LDPE unit and two 950,000-tonne PP units; it produced on-spec ethylene on 15 July 2025, helping make Huizhou a world-class green petrochemical base." },
  1267: { descEn: "A major AI-computing hub at Rio's Olympic Park.", detailEn: "Elea is converting Rio de Janeiro's Olympic Park into an AI-computing hub planned for 1.5 GW in 2027 and 3.2 GW by 2032, running on 100% clean power with direct submarine-cable links. In August 2025 it signed MoUs with Oracle and the city; Elea's 1+ GW national pipeline needs over $10 billion of capital, backed by Goldman Sachs and others." },
  1386: { descEn: "HUMAIN, AMD and Cisco building AI infrastructure across Saudi Arabia and the US.", detailEn: "HUMAIN and AMD announced a combined $10 billion to deploy 500 MW of AMD computing within five years across data centres in Saudi Arabia and the US. In November 2025 they formed a JV with Cisco, with a first 100 MW using AMD Instinct MI450 GPUs and Cisco infrastructure, expected online in 2026." },
  1388: { descEn: "A gigawatt AI park by stc's center3 and HUMAIN.", detailEn: "stc's center3 and HUMAIN formed a JV to develop and operate AI data centres in Saudi Arabia, planned for 1 GW with a first 250 MW for large AI loads. center3 has invested ~$3 billion and plans another $10 billion by end-2030 for high-density hyperscale facilities in Riyadh, Jeddah and Dammam." },
  1420: { descEn: "A petrochemical expansion beside one of the world's largest integrated complexes.", detailEn: "KIPIC is building a ~$10 billion petrochemical complex beside the Al-Zour refinery (615,000 b/d) in Kuwait, with olefins and aromatics units for ~2.7 million tonnes of aromatics and polypropylene and 1.7 million tonnes of gasoline a year — making it one of the world's largest integrated refining-petrochemical bases, split into gasoline, petrochemical and marine EPC packages." },
  1421: { descEn: "A petrochemical cracker study alongside the Duqm refinery.", detailEn: "The OQ8 Duqm refinery reached full output in 2024 and raised nameplate capacity from 230,000 to 255,000 b/d. Beside it, a Duqm petrochemical complex is planned with a large mixed-feed cracker and several world-class derivative units for regional and Asian markets, part of OQ's $10 billion-plus strategic investment in Duqm." },
  1426: { descEn: "Two new LNG trains in the North Field South expansion.", detailEn: "NFS is the second phase of Qatar's North Field expansion, adding two trains totalling 16 MTPA which, with the 32 MTPA North Field East, lift Qatar's LNG capacity from 77 to 142 MTPA. In October 2024 McDermott won the subsea pipeline and cable EPCI contract." },
  1538: { descEn: "An 1,814 km gas export trunkline across four countries, now under construction.", detailEn: "The TAPI pipeline carries gas from Turkmenistan's Galkynysh field via Afghanistan and Pakistan to India, 1,814 km with 33 bcm/year design capacity. The ~214 km Turkmen section finished in 2024 and the Afghan Serhetabat-Herat section began in September 2024 (14 km built and 24 km graded by 2025, aiming to reach Herat by end-2026), while the Pakistani and Indian sections remain on hold." },
  1772: { descEn: "Elea's AI data-centre expansion to Recife and Belém.", detailEn: "Elea operates nine interconnected campuses in Brazil with over 1 GW under construction (needing $10 billion-plus of capital). After I Squared Capital took a controlling stake in April 2026, it accelerated national expansion into Recife and Belém with high-density AI infrastructure (location shown at Recife); specific capacity and timeline are to be announced." },
  1891: { descEn: "A 500 MW Nvidia GB300 AI factory in Saudi Arabia.", detailEn: "PIF's HUMAIN is partnering with Nvidia to build up to 500 MW and hundreds of thousands of top GPUs within five years. A first phase of 18,000 GB300 Grace Blackwell systems with InfiniBand activates multi-exaFLOP computing in early 2026, with the two committing up to $10 billion for the 500 MW deployment." },
  1903: { descEn: "A large new inland NEOM airport, aiming long-term to be the world's largest.", detailEn: "Located inland in NEOM near Tabuk and far larger than the existing NEOM Bay airport, this airport has AECOM as PMC consultant for master planning through operations, with Turkey's IC Ictas and Limak bidding for the terminal. Phase 1 targets ~25 million passengers a year, phase 2 up to 50 million and the long-term vision 100 million — among the world's largest — serving NEOM and Vision 2030 tourism." },
  2062: { descEn: "Changi Airport's largest-ever expansion: a reclaimed Terminal 5.", detailEn: "Built on ~1,080 hectares of reclaimed land east of Changi at about S$10 billion (~$13 billion), T5 is Changi's largest expansion. Groundbreaking was in May 2025, with initial capacity of 50 million passengers a year lifting the airport to 135 million total, featuring solar roofs and under-runway tunnels, with phase 1 due in the mid-2030s." },
  2270: { descEn: "A 3,300 km green-hydrogen corridor from Algeria to Italy, Austria and Germany.", detailEn: "Ministers of Algeria, Tunisia, Germany, Austria and Italy signed a joint declaration to build the 3,300 km SoutH2 corridor linking Algeria and Tunisia to industrial hubs in Italy, Austria and Germany, ~70% repurposing existing gas pipelines to cut costs, targeting 4 million tonnes of green hydrogen a year by 2030. Algeria has begun feasibility studies — its flagship green-hydrogen export route to Europe." },
  2350: { descEn: "A flagship Mauritania green-hydrogen project targeting 10 GW of electrolysers by 2030.", detailEn: "Developed by Chariot and TE H2 (a TotalEnergies-EREN JV), the Nour project plans 10 GW of electrolysis with an initial 3 GW of renewables for ~150,000 tonnes of green hydrogen a year, leveraging Mauritania's excellent wind and solar for export to Europe — the country's other mega green-hydrogen project alongside AMAN." },
  2461: { descEn: "A deep-water-port green-hydrogen export zone in the Northern Cape.", detailEn: "At Richtersveld in South Africa's Northern Cape, ~60 km north of Port Nolloth near the Namibian border, this deep-water-port scheme led by Sasol completed a pre-feasibility study confirming viability. It plans 10 GW of electrolysers and 240,000 hectares for renewables to export green hydrogen and ammonia to Europe, with a strategic environmental assessment under way from March 2024; no investment decision yet." },
  2564: { descEn: "A high-grade Gabon hematite mine; first shipment to China in late 2025.", detailEn: "Fortescue and the Gabon government jointly develop the high-grade Belinga hematite deposit, shipping the first ore to China in December 2025 and ramping toward 15-20 million tonnes in 2026. With a ~450-560 km rail corridor, deep-water port and hydro plants, the mining ministry estimates ~$10 billion of total infrastructure, targeting an integrated mine-rail-port by 2030." },
  2707: { descEn: "One of the world's largest planned offshore wind farms (4.1 GW off Scotland).", detailEn: "In the outer Firth of Forth off eastern Scotland, SSE's ~4.1 GW Berwick Bank is one of the world's largest planned offshore wind projects, able to power ~6 million homes. It advanced Scottish consent and grid connection in 2025 as a flagship of UK energy security, targeting the early 2030s." },
  2742: { descEn: "A European-gauge high-speed railway linking the Baltics with Poland.", detailEn: "Rail Baltica is a nearly 900 km European-standard-gauge high-speed railway through Estonia, Latvia and Lithuania into Poland and the EU network, with a ~€15.3 billion first phase. Large-scale construction proceeded across Poland and the Baltics in 2025 and the first platform of Tallinn's Ülemiste terminal opened, targeting phase-1 completion in 2030." },
  2747: { descEn: "A large coordinated North Sea oil-and-gas development.", detailEn: "In the central Norwegian North Sea, Aker BP leads an integrated development of the Hugin, Munin and Fulla fields (Yggdrasil/NOAKA) at about NOK 115 billion — one of Norway's largest recent offshore clusters. Platform and subsea works advanced in 2025, targeting start-up around 2027." },
  3001: { descEn: "Meta's 29th data centre, a 1 GW campus in El Paso, Texas.", detailEn: "Broken ground in October 2025 at an initial $1.5 billion expandable to 1 GW, this El Paso campus saw investment jump sixfold to over $10 billion in March 2026 with 12 buildings, expected online in 2028 with a peak workforce of 4,000, planned to rely mainly on gas power." },
  3006: { descEn: "A 500 MW, seven-building QTS campus in Van Wert, northwest Ohio.", detailEn: "On 29 May 2026 the city of Van Wert and QTS unveiled a ~$10 billion, 902-acre mega-site for up to seven buildings and 500 MW with zero-water-use closed-loop cooling; QTS fully funds the energy-infrastructure upgrades, with groundbreaking expected in Q4 and full build-out around 2032." },
  3293: { descEn: "A planned 300,000 b/d refining complex with Saudi Aramco at Gwadar.", detailEn: "Pakistan plans to bring in ~$10 billion from Saudi Arabia to build an integrated refining complex at Gwadar processing at least 300,000 b/d plus petrochemicals, on a Saudi 60% / Pakistan 40% basis, with land allocation advancing in early 2026 and start-up around 2030, potentially saving Pakistan ~$3 billion a year." },
  3427: { descEn: "The world's first Hualong One plus high-temperature-gas-reactor cogeneration project.", detailEn: "At the Xuwei New Area of Lianyungang, Jiangsu, CNNC Su Energy plans four Hualong One units plus two high-temperature gas-cooled reactors; phase 1 builds two Hualong One and one HTGR, mainly for industrial heat with some power, approved by the State Council in August 2024 and started in January 2026." },
  3446: { descEn: "China's home-designed next-generation fusion engineering test reactor.", detailEn: "Led by ASIPP and designed with international collaboration, this reactor builds on Hefei's EAST and Kuafu platforms. Its overall integrated engineering design is complete, targeting construction before 2035 for physics experiments and a commercial fusion demonstration plant around 2050." },
  3507: { descEn: "YMTC Wuhan phase 3, including China's first fully domestic NAND line.", detailEn: "YMTC's third Wuhan fab has entered tool install and commissioning, due online by end-2026 reaching 50,000 wafers/month in 2027, alongside the first pilot line built entirely from domestic equipment. With all three new fabs at capacity, total output rises from ~200,000 to 500,000 wafers/month, aiming for 15% of the global NAND market." },
  3582: { descEn: "A 100-billion-yuan China-Saudi refining-petrochemical complex in Fujian.", detailEn: "On the Gulei Peninsula in Zhangzhou, Fujian, this JV of Fujian Petrochemical (50%), Sinopec (25%) and Saudi Aramco (25%) at 71.1 billion yuan builds 16 million tonnes of refining, 1.5 million tonnes of ethylene and 2 million tonnes of aromatics across 30+ units. Started in November 2024, it entered substantive operation in November 2025 and targets full production by 2030 — a flagship of China-Saudi energy cooperation." },
  4085: { descEn: "A world-class copper mine, MMG's flagship overseas asset.", detailEn: "At ~4,000 m in Peru's Apurímac region, Las Bambas is one of the world's largest copper mines, with ~410,000 tonnes of copper-in-concentrate in 2025, a multi-year high. The Chalcobamba pit started up and was approved for development in 2025 (~$130 million phase 1), supporting 380,000-400,000 tonnes a year with Ferrobamba; MMG keeps investing in tailings and mine infrastructure." },
  4097: { descEn: "State Grid's wholly-owned ±800 kV link carrying Amazon hydro to Rio.", detailEn: "The Belo Monte phase-2 UHVDC is State Grid's first wholly-owned overseas UHVDC, running 2,539 km from the Xingu converter in Pará to a Rio de Janeiro converter at 4 GW. After milestone documents were signed by China and Brazil in April 2024, the line is fully in service, operated by State Grid Brazil Holding." },
  3592: { descEn: "A 4,269 km gas artery from Sichuan-Chongqing to East China.", detailEn: "Running 4,269 km through eight provinces from Sichuan-Chongqing to Fujian, this 10 MPa pipeline carries 14 bcm/year, approved and built in western and eastern segments. The western section (started September 2023) is over 70% done; the 2,698 km eastern section saw its first part commissioned in August 2025, with full completion expected in 2027, lifting the Sichuan-East gas system to 26 bcm/year." },
  321: { descEn: "Australia's largest rail expansion in nearly 40 years.", detailEn: "A 9 km twin-track tunnel under Melbourne's CBD with five new metro stations opened on 30 November 2025, with full operation by February 2026, adding over 1,000 weekly services and doubling Melbourne's underground rail network." },
  584: { descEn: "AWS's largest single-region investment in Europe, in the Frankfurt region.", detailEn: "AWS announced a cumulative €8.8 billion in its Frankfurt cloud region by 2026, building a 7+ hectare campus at Schöneck and a 10.6-hectare campus at Maintal, supporting over 15,200 jobs — its largest single-region investment in Europe to date." },
  1148: { descEn: "Toronto's Line 5 (Eglinton Crosstown), opening February 2026.", detailEn: "The 19 km, 25-station Eglinton Crosstown LRT (Line 5) runs east-west along Toronto's Eglinton Avenue with over 10 km underground. Built by Ontario's Metrolinx and the Crosslinx consortium (including Aecon), it was substantially handed over on 5 December 2025 after years of delay and opened by the TTC on 8 February 2026, connecting Kennedy and Mount Dennis stations." },
  3018: { descEn: "A $9.5 billion new international terminal at JFK, first phase mid-2026.", detailEn: "Built on the former T1/T2/T3 site, the New Terminal One is the core of the Port Authority's $19 billion JFK overhaul. The first phase, with arrivals/departures halls and 14 gates, opens in mid-2026, reaching 23 gates and over 2.6 million sq ft by 2030 to become JFK's largest terminal." },
  3024: { descEn: "The Purple Line extension to West LA, first section opening for the World Cup era.", detailEn: "Extending west from Koreatown to the West LA VA Medical Center with seven new stations. Section 1 (~4 miles, 3 stations) opens on 8 May 2026; section 2 reaches Century City by late 2026 and section 3 the VA by 2027, racing toward the 2028 Olympics." },
  3556: { descEn: "A new second Shanghai-Hangzhou high-speed corridor, early works begun.", detailEn: "About 197 km at 350 km/h and ~67.1 billion yuan, this line runs from Shanghai via Jinshan to Hangzhou West, relieving the existing Shanghai-Hangzhou line and serving Yangtze Delta integration. Approved by the NDRC, it has entered early construction." },
  3588: { descEn: "A 67.3-billion-yuan mega coal-to-olefins base, Baofeng's third.", detailEn: "In the Jiangjunmiao mining area of eastern Junggar, Xinjiang, this ~67.3 billion-yuan project plans 4×2.8-million-tonne methanol, 4×1-million-tonne methanol-to-olefins, olefin separation and 1.95 million tonnes each of PP and PE plus EVA and UHMWPE units. It is Baofeng's third coal-to-olefins base after Ningdong and Inner Mongolia, lifting company olefin capacity toward 9.7 million tonnes/year, with start-up in 2027-2028." },
  3557: { descEn: "A new 350 km/h line forming a Central Plains-Jianghuai corridor.", detailEn: "389 km at 350 km/h and ~66.6 billion yuan, this line links Nanyang and Xinyang in Henan with Hefei (toward Jinzhai) in Anhui. It has passed NDRC project-proposal review and is expected to start after feasibility approval in the first half of 2026." },
  3569: { descEn: "A major hub-airport expansion with two new runways and a 730,000 m² T2, due 2029.", detailEn: "Designed for 95 million passengers and 1 million tonnes of cargo by 2030, this expansion adds East-2 and West-3 runways, a 730,000 m² T2 terminal, a ground transport centre and parking at ~66.5 billion yuan, with a solar-plus-storage low-carbon energy system. The East-2 runway passed acceptance by end-2025 and the T2 main structure was 67.6% complete." },
  606: { descEn: "ByteDance/TikTok's first Latin American data centre, wind-powered.", detailEn: "In December 2025 ByteDance's TikTok announced a 300 MW wind-powered data centre with Omnia and Casa dos Ventos at the Pecém port industrial complex in Ceará, Brazil (an initial $9.3 billion), starting construction in April 2026 and operating in 2027 — Latin America's largest single-customer data centre." },
  1140: { descEn: "The world's longest underground rail tunnel; exploratory tunnel holed through in 2025.", detailEn: "The Brenner Base Tunnel crosses the Alps linking Innsbruck (Austria) and Fortezza (Italy); with the Inn Valley tunnel it totals 64 km, set to be the world's longest underground rail tunnel. In May 2025 Webuild completed mechanised boring on the Italian Mules 2-3 lot, with a TBM reaching the border after 14+ km, and on 18 September the 56 km exploratory tunnel was holed through. Shifting road freight to rail, it would cut Fortezza-Innsbruck to under 25 minutes, targeting 2032." },
  3509: { descEn: "A 40 GWh battery base in Fuzhou, CATL's 15th domestic site.", detailEn: "Signed in January 2025 with phase 1 started in April, this 40 GWh, 65-billion-yuan base in Fuzhou's Taiwanese Investment Zone builds a full chain from materials to recycling, due online in mid-2027 with annual output value exceeding 100 billion yuan at capacity." },
  350: { descEn: "A large mixed-feed cracker and aromatics complex at Yanbu.", detailEn: "In April 2025 Saudi Aramco, Sinopec and Yasref signed a framework to build a 1.8-million-tonne mixed-feed cracker and 1.5-million-tonne aromatics complex beside the Yanbu refinery to maximise conversion of refinery feed into chemicals, currently in engineering study." },
  515: { descEn: "Two new Google campuses in South Carolina ($9 billion).", detailEn: "In October 2025 Google announced $9 billion (through 2027) in South Carolina, expanding its Berkeley County campus and building new campuses at Ridgeville and St. George in Dorchester County for cloud and AI — its largest single-state expansion in the US Southeast." },
  516: { descEn: "A $9 billion Google expansion in Virginia.", detailEn: "In August 2025 Google announced an additional $9 billion in Virginia (through end-2026), building a Meadowville campus in Chesterfield County and a near-million-sq-ft campus in Botetourt County, and expanding facilities in Loudoun and Prince William counties." },
  1131: { descEn: "Egypt's first high-speed line connecting the Red Sea and the Mediterranean.", detailEn: "Egypt and Siemens are building a 2,000+ km high-speed network; the first ~660 km Green Line with 21 stations runs from Ain Sokhna on the Red Sea via the New Administrative Capital, Alexandria and El Alamein to Marsa Matrouh — the first rail link between the two seas at 250 km/h, dubbed the 'Suez Canal on rails'. The first line was 67% done by September 2025, with a test run launched in November, serving ~90% of the population and opening in December 2026." },
  1300: { descEn: "A Campos Basin pre-salt gas field, Brazil's first offshore-processed gas into the grid.", detailEn: "Comprising the Pao de Acucar, Gavea and Seat pre-salt discoveries in ~2,900 m of water with over a billion barrels of oil equivalent, this development uses a MODEC FPSO (modules lifted at Seatrium's Angra yard in March 2026) with a 204 km line to the Cabiunas terminal at Macaé — Brazil's first offshore-processed gas into the grid. Drilling starts in March 2026 for 2028 start-up, supplying ~15% of national gas demand." },
  2569: { descEn: "Integrating gas sources to feed the Punta Europa LNG plant.", detailEn: "Equatorial Guinea's gas mega-hub centres on the 3.7-MTPA Punta Europa LNG plant and a 1.1-million-tonne methanol plant, integrating regional gas to extend output. In 2026 it aims to finalise PSCs for blocks B/4 and EG-27 with ConocoPhillips (unlocking ~$9 billion), with Chevron's Aseng gas supplying via a $690 million deal and a Gulf-of-Guinea pipeline planned to bring Nigerian gas." },
  2607: { descEn: "Australia's most advanced offshore wind project, 2.2 GW off Gippsland.", detailEn: "Off Gippsland in Victoria, this is Australia's fastest-moving offshore wind project at up to 2.2 GW, able to power ~1.2 million homes. Holding a feasibility licence and advancing environmental and grid-connection design as a Gippsland front-runner, it targets supplying the grid in the early 2030s." },
  2626: { descEn: "Queensland's flagship pumped hydro: 2 GW, up to 48 GWh.", detailEn: "At Borumba reservoir near Imbil, Queensland, this 2 GW pumped-hydro scheme stores up to ~48 GWh for ~24 hours of discharge — the flagship long-duration storage of Queensland's energy transition. It won federal environmental approval in 2025 for early works, with QIC taking over commercial development in June, and is in site preparation." },
  2999: { descEn: "Tesla's sixth gigafactory near Monterrey; FID confirmed May 2026.", detailEn: "Tesla's Giga Mexico at Santa Catarina near Monterrey, Nuevo León is about $9 billion. Repeatedly delayed by tariff and EV-policy uncertainty, it formally confirmed FID in May 2026, with early and road-access works advancing and some suppliers already locating nearby." },
  3003: { descEn: "A planned 2 GW AI campus in the Permian Basin, West Texas.", detailEn: "On the 568-acre Longfellow Ranch site at Fort Stockton, Texas, AI firm Poolside plans a 2 GW campus in eight 250 MW phases. Originally partnered with CoreWeave (October 2025), the two ended their deal in April 2026 and Poolside is in talks with cloud providers including Google for new partners." },
  3143: { descEn: "A planned new nuclear cluster in Punjab, Pakistan (two large units).", detailEn: "At Muzaffargarh in Punjab, Pakistan, PAEC plans two ~1,100 MW units (M-1, M-2) as a new nuclear cluster after Chashma. The regulator has completed siting studies, with ~3,300 MW planned in Punjab medium-term at an estimated ~$13 billion." },
  3282: { descEn: "Reliance polyester-chain expansion: the world's largest single 3-million-tonne PTA.", detailEn: "In 2025 Reliance announced ~750 billion rupees of petrochemical expansion, building the world's largest single-train 3-million-tonne/year PTA and a 1-million-tonne PET at Dahej (both targeting 2026), plus phased 1.5-million-tonne PVC expansions at Dahej and Jamnagar, matched to US ethane feedstock arriving in the late 2020s." },
  4232: { descEn: "One of the world's largest single-train methanol plants; CNCEC EPC ~€8.4 billion.", detailEn: "A gas-to-methanol complex at Ust-Luga on Russia's Baltic produces 5,400 tonnes/day (~1.8 million tonnes/year) from a single train — among the world's largest. CNCEC's Seventh Construction Company signed the EPC contract with Baltic Methanol worth about €8.4 billion (~65 billion yuan), with a 48-month schedule." },
  3498: { descEn: "A 100,000-wafer/month 12-inch foundry in Lingang, Shanghai.", detailEn: "In the Lingang free-trade zone of Shanghai, this foundry plans 100,000 wafers/month at ~$8.87 billion across three stages — one of China's largest single fabs. A phase-1 revision was published in February 2025, with capacity ramping from 2025 to full output by end-2027, focused on mature and specialty processes." },
  622: { descEn: "Pakistan's first world-class copper-gold mine, first output ~2028.", detailEn: "In Balochistan, Reko Diq is one of the world's great copper-gold deposits. An updated feasibility and ~$5.57 billion phase-1 capital were approved in April 2025 with early works begun; the ADB committed $410 million and IFC $700 million, and phase 1 will produce ~200,000 tonnes of copper a year." },
  824: { descEn: "Canada's most expensive dam; all units online in August 2025.", detailEn: "On the Peace River in British Columbia, Site C began in 2015 and connected its sixth and final unit in August 2025, with 1,100 MW and ~5,100 GWh a year. At over C$16 billion it is the costliest dam in Canadian history, adding ~15% to BC's power supply." },
  1214: { descEn: "A new refining-petrochemical complex in northwest India.", detailEn: "At Pachpadra in Barmer, Rajasthan, this HPCL-Rajasthan JV pairs a 9-million-tonne/year refinery with 2.4 million tonnes of petrochemicals. Crude is in storage and the 180,000 b/d CDU plans to start up by late January 2026, with petrochemicals about a quarter later, strengthening northwest India's fuel and chemical self-sufficiency." },
  247: { descEn: "TSMC's first volume fab in Japan.", detailEn: "At Kikuyo in Kumamoto, this fab focuses on 22/28nm and 12/16nm at 55,000 wafers/month, reaching volume production in late 2024 for automotive and image sensors; with phase 2 launched, total investment will exceed $20 billion." },
  4254: { descEn: "Segment 4 of the Lagos-Kano railway, completing the central corridor.", detailEn: "The Ibadan-Kaduna section is the fourth segment of Nigeria's ~1,315 km Lagos-Kano standard-gauge railway, contracted to CRCC's CCECC — a ~616 km double-track main line plus an ~81 km single-track spur (via Osun-Ado-Ekiti) at up to 150 km/h, ~48-month build. Once through it joins the existing Lagos-Ibadan and Abuja-Kaduna sections into a central corridor, fully to Chinese standards — key to modernising Nigeria's railways." },
  547: { descEn: "The Greater Bay Area hub of China's 'east-data-west-compute' plan.", detailEn: "Shaoguan has attracted 22 AI-compute projects totalling 62.1 billion yuan, with 67,400 racks and 50,600 PFLOPS built and ten 400G all-optical links to the Bay Area cutting latency to Guangzhou/Shenzhen to 1.3/1.66 ms, targeting 500,000 racks by 2025." },
  1550: { descEn: "A giant Chukotka copper-gold mine, one of the world's largest undeveloped.", detailEn: "In the Bilibino district of Chukotka in Russia's Far East, Baimskaya processes 70 million tonnes of ore a year, averaging ~300,000 tonnes of copper a year in its first decade. With a 428 km all-weather road and a port exporting via the Northern Sea Route using automation and IoT, VEB and others pledged over 1.1 trillion roubles, of which 260+ billion is deployed." },
  2058: { descEn: "The Philippines' first subway, Japan-financed.", detailEn: "At about 488.5 billion pesos with Japanese financing, the Metro Manila Subway runs 33 km from Valenzuela to Ninoy Aquino International Airport. Land clearing reached ~90.76% by end-2025 (from 51% at year-start); originally due 2029, it has slipped to 2032 at the latest, with funding concentrated in the first half of 2026." },
  2643: { descEn: "AWS's A$13.2 billion Australian data-centre expansion.", detailEn: "AWS pledged about A$13.2 billion over 2023-2027 to expand cloud data-centre infrastructure in Sydney and Melbourne, with large renewable PPAs, supporting Australian business and government cloud and generative-AI demand — one of the country's largest cloud-infrastructure investments." },
  2651: { descEn: "A heavy-rail link from Melbourne Airport to the city, ~A$7 billion federal.", detailEn: "This heavy-rail link between Melbourne Airport and the CBD has ~A$7 billion of federal funding (total ~A$13 billion). The phase-1 West Footscray-Albion rail upgrade has begun for 2030 completion, with track realignment around the airport station from 2026 — a major Victorian transport project." },
});

/* ===== 批次5：全库投资额 TOP（约 65–85 亿美元）===== */
Object.assign(window.ENERGY_EN, {
  2655: { descEn: "Sydney Harbour's second road tunnel.", detailEn: "The ~6.5 km Western Harbour Tunnel relieves the existing Harbour Bridge and tunnel, linking the Western Distributor with North Sydney at about A$13 billion. Immersed-tube and bored construction is advancing, with opening planned for 2028 — a key piece of the Greater Sydney road network." },
  3016: { descEn: "The first line of Sheinbaum's passenger-rail plan, 226 km to Querétaro.", detailEn: "About 226 km from Mexico City to Querétaro, started in April 2025 with a 2.5-year schedule. Needing six tunnels and 14 viaducts, its cost rose to ~$8.5 billion; the Querétaro station will later extend toward Nuevo Laredo and Nogales, forming the backbone of a national passenger-rail network." },
  3038: { descEn: "A CPChem-QatarEnergy ethane cracker complex in Orange, Texas, in commissioning.", detailEn: "Owned 51% by CPChem and 49% by QatarEnergy in Orange, Texas, this complex has a 2.08-million-tonne/year ethane cracker and two 1-million-tonne HDPE units. The $8.5 billion project enters commissioning in 2026 and full production in 2027, with ~25% lower greenhouse gases than comparable plants." },
  3401: { descEn: "An 11 GW wind-and-solar base in Gansu's Badain Jaran Desert; supporting works started 2025.", detailEn: "Planned for at least 11 GW of renewables (4.3 GW wind, 6.7 GW solar, 0.2 GW CSP) with 4 GW of peaking coal power and 1.4 GW/5.6 GWh of storage, exporting via the 'Gansu-to-Shanghai' corridor. On 27 February 2025 four 1 GW supporting coal units broke ground together, with renewables advancing in parallel." },
  3564: { descEn: "The Hefei-Wuhan section of the Shanghai-Chongqing-Chengdu Yangtze HSR.", detailEn: "About 360 km at 350 km/h from Hefei via Lu'an, Jinzhai, Macheng and Hong'an to Wuhan — a key section of the Yangtze high-speed corridor. Started in late 2023 with the Hubei portion progressing well, it will join the operating Wuhan-Yichang line, putting Wuhan-Hefei within about an hour." },
  2962: { descEn: "A ~$8.2 billion CFE grid build: 275 new lines, 6,735 km, 524 substations.", detailEn: "CFE's 2025-2030 reinforcement plan, ~$8.2 billion (164 billion pesos), builds 275 new lines totalling 6,735 km and 524 substations, with 66 priority projects scheduled for 2025-2026 across many states to support nearshoring power demand." },
  3020: { descEn: "An $8.2 billion-plus O'Hare terminal overhaul, with a new Concourse D and Global Terminal.", detailEn: "ORDNext replaces Terminal 2 with a Global Terminal, adds a 24-gate Satellite Concourse E and underground tunnels. The initial $1.3 billion Concourse D began in August 2025, with vertical construction from spring 2026 and completion in 2028; the Global Terminal's sequencing was renegotiated in late 2025." },
  143: { descEn: "The Netherlands' largest offshore wind project, with green-hydrogen production.", detailEn: "This project pairs 2 GW of offshore wind (IJmuiden Ver Beta), 50 MW of floating offshore solar and 1 GW of onshore electrolysers, with green hydrogen distributed via Rotterdam's industrial pipeline network. Approved in June 2024 and restructured into two phases in August 2025, it has a 250 MW PPA with Google." },
  240: { descEn: "CATL's largest battery gigafactory in Europe.", detailEn: "At Debrecen, Hungary, this ~€7.3 billion plant plans 100 GWh a year to supply Volkswagen, BMW and Stellantis. Phase 1's structure has topped out with tools being installed, expected online in early 2026 and employing ~9,000." },
  319: { descEn: "A metro line linking Riyadh's giga-projects.", detailEn: "About 65 km (47 km underground) with 19 stations, this line links the Qiddiya entertainment city, King Salman Park and Diriyah Gate. Bidding closed in January 2026, targeting a contract signing and construction start in 2026." },
  1139: { descEn: "The world's longest immersed-tube tunnel; first element sunk in 2025.", detailEn: "The Fehmarn Belt tunnel links Lolland in Denmark with Fehmarn in Germany, 18 km — set to be the world's longest combined road-and-rail immersed tunnel, with twin electrified rail tracks and a four-lane motorway. In May 2025 Femern A/S sank and joined the first standard element to the Danish portal; built from 79 elements, it will cut the Rødby-Puttgarden train crossing to 7 minutes, targeting 2029 and slashing the Hamburg-Copenhagen journey." },
  1159: { descEn: "India's largest deep-water port, built on an artificial island.", detailEn: "Near Dahanu in Palghar, Maharashtra, Vadhavan is India's planned all-weather deep-water mega-port, a JNPT-Maharashtra Maritime Board PPP built on an artificial island — India's first offshore mega-port, designed for ~23 million TEU a year to enter the global top ten. PM Modi laid the foundation in August 2024, with construction and reclamation under way from 2025 toward operational readiness by December 2029." },
  1186: { descEn: "Equinor's largest overseas oilfield, the first foreign-led pre-salt project.", detailEn: "In the Santos Basin pre-salt off Brazil in over 2,000 m of water, Bacalhau is Equinor's largest overseas oilfield and Brazil's first pre-salt project developed entirely by an international operator. Its 370 m FPSO is designed for 220,000 b/d and produced first oil on 15 October 2025; phase-1 recoverable reserves exceed a billion barrels." },
  1301: { descEn: "Shell's 2025-FID Santos Basin pre-salt gas-condensate project.", detailEn: "In March 2025 Shell Brazil took FID on the Gato do Mato pre-salt project in the Santos Basin, covering the BM-S-54 concession and the Sul de Gato do Mato production-sharing area in 1,750-2,050 m of water. A new MODEC FPSO will produce up to 120,000 b/d from ~370 million barrels of recoverable resources, targeting 2029." },
  1385: { descEn: "A flagship AI compute centre near Riyadh training Grok.", detailEn: "Announced at the November 2025 US-Saudi investment forum, this is built by Musk's xAI with Saudi sovereign-AI firm HUMAIN and Nvidia near Riyadh, at over 500 MW. A first phase of ~18,000 Nvidia GB300 GPUs serves as the training base for xAI's next-generation Grok models, with xAI the first customer." },
  1406: { descEn: "A 350 km/h line linking Abu Dhabi and Dubai in 30 minutes.", detailEn: "In early 2025 the UAE's Etihad Rail announced a 150 km high-speed railway linking Abu Dhabi and Dubai at 350 km/h for a 30-minute trip, at about $8 billion, targeting 2030. The Abu Dhabi section went to NPC, Trojan, Turkey's Kalyon and China State Construction; the Dubai section to India's L&T, China Harbour and Wade Adams." },
  1548: { descEn: "New gas supply to China via the Sakhalin-Khabarovsk system.", detailEn: "The Far East route is a new spur supplying China via the Sakhalin-Khabarovsk-Vladivostok pipeline system on Russia's Pacific coast. In September 2025 Gazprom and CNPC agreed to raise supply from 10 to 12 bcm/year, with exports starting in 2027 at an initial 2 bcm rising to 12 bcm; China said construction was advancing in late 2025." },
  1551: { descEn: "Russia's largest undeveloped copper mine; phase 1 ramping up.", detailEn: "In Zabaikalye, Udokan started phase 1 in 2023, targeting ~135,000 tonnes of copper a year at capacity, with 160,000 tonnes of copper equivalent exported by September 2025. The phase-2 international feasibility study is done, planned to start in 2028, lifting ore throughput to 24-28 million tonnes a year and copper capacity toward 450,000 tonnes." },
  1680: { descEn: "Europe's largest battery investment; 100 GWh, online early 2026.", detailEn: "On a 221-hectare site in southern Debrecen, Hungary, this ~€7.3 billion, 100 GWh plant is the EU's largest battery investment and Hungary's largest greenfield FDI, supplying Mercedes, BMW, Stellantis and Volkswagen. Phase-1 40 GWh is fully booked by customers; module assembly began in 2024 with cell mass production planned for Q1 2026." },
  1870: { descEn: "The main renewable supply for NEOM's off-grid smart microgrid.", detailEn: "Built by NEOM's energy-and-water unit ENOWA to power the new city, this plans 2+ solar farms totalling 6.5 GW and 2+ wind farms totalling 1.6 GW, coming online from 2026 into the world's first HVDC smart microgrid — distinct from the NGHC green-hydrogen power, serving city loads like Oxagon." },
  1901: { descEn: "Phase 1 (Lines B and C) of Mecca's four-line metro.", detailEn: "The Royal Commission for Makkah plans a four-line (A-D), 89-station metro in three phases over 2032-2045. Phase 1 focuses on Lines B and C — over 62 km and 31 stations (21 underground), including a 2.4 km tunnel beneath the Masar project and integration with the existing Mashaaer pilgrim line. Phase 1 is ~$8 billion and the full network up to $16.5 billion; preliminary design tenders were issued in 2025, closing 5 August." },
  2277: { descEn: "Eni's $8 billion A&E Structures gas project, 0.75 bcf/d by 2026.", detailEn: "Developed by Italy's Eni with Libya's NOC, the $8 billion A&E Structures gas project targets 750 million cubic feet/day by 2026 to meet Libyan domestic demand and stabilise supply to Europe — a flagship of Libya's oil-and-gas recovery, aligned with NOC's 45 new and upgrade projects and a 2-million-barrel-a-day output goal." },
  2608: { descEn: "The Hunter region's first offshore wind project with a feasibility licence.", detailEn: "In the declared Hunter offshore wind zone off Newcastle, NSW, this ~2 GW project won a feasibility licence in February 2025. The developer has applied to extend its development period; as the Hunter's pioneer offshore project it aligns with local coal-plant retirements and industrial decarbonisation." },
  2746: { descEn: "The Barents Sea's largest oilfield, opening a new Arctic oil province.", detailEn: "In the Norwegian Barents Sea, Equinor (46.3%) leads the Johan Castberg development of the Skrugard, Havis and Drivis fields via an FPSO peaking at 220,000 b/d. First oil came in August 2025 — the largest producing field in the Barents Sea, opening a new Arctic oil era and reinforcing Norway as a long-term European energy exporter." },
  2807: { descEn: "Romania completing two CANDU heavy-water reactors.", detailEn: "At Cernavoda in Romania, units 3 and 4 (each ~700 MW), begun in the 1980s, are being completed, advancing in 2025 toward around 2031 — significantly raising Romania's nuclear share and cementing its regional power-export role." },
  2814: { descEn: "Phase 1 of the Lianjiang Hualong One plant in Guangdong.", detailEn: "At Lianjiang in Zhanjiang, Guangdong, this uses the home-grown third-generation Hualong One, with two 1.2 GW units in phase 1 — an important clean baseload source for western Guangdong, recently approved and under construction to support the province's low-carbon transition." },
  2815: { descEn: "China's home-grown large Gen-III reactor 'Guohe One' demonstration.", detailEn: "At Shidao Bay in Rongcheng, Shandong, this demonstrates China's indigenous large advanced PWR 'Guohe One' (CAP1400) at 1.5 GW per unit. The first unit started up in late 2024 with more under construction, moving CAP1400 into scaled deployment, listed among 2026 large-investment-supported projects." },
  2823: { descEn: "Korea completing two indigenous APR1400 reactors.", detailEn: "At Uljin in North Gyeongsang, KHNP is building two 1.4 GW APR1400 indigenous Gen-III reactors, restarted and advancing through 2024-2025 — emblematic of Korea's nuclear revival, with the same APR1400 exported to the UAE and Czechia." },
  3525: { descEn: "A 56 GW integrated solar super-factory in Taiyuan — the world's largest single PV base.", detailEn: "JinkoSolar's 56 GW vertically integrated base in Shanxi, at about 56 billion yuan, builds 56 GW each of ingots/wafers/cells/modules in four phases. Phases 1-2 started in 2024 and 3-4 in 2025, creating the world's largest, highest-efficiency TOPCon integrated digital super-factory, employing ~30,000 at capacity." },
  1019: { descEn: "A Weichai-BYD blade-battery base, online March 2025.", detailEn: "The Weichai-FinDreams (Yantai) new-energy park in Fushan, Yantai spans ~1,700 mu with ~56 billion yuan planned — a key new-energy pivot for Weichai, China's largest diesel-engine maker. Phase 1 builds 20 GWh of cells and 20 GWh of blade-battery PACK lines; the first blade battery rolled off on 28 March 2025 — a huge new Yantai industrial power load." },
  2004: { descEn: "A $7.8 billion TSMC-affiliated VIS-NXP 12-inch fab in Singapore.", detailEn: "VisionPower (VSMC), a JV of VIS (a TSMC affiliate) and NXP, announced ~$7.8 billion in June 2024 for a 300mm fab in Singapore, starting in late 2024 with production in 2027 reaching 55,000 wafers/month by 2029 across 130-40nm — process technology licensed from TSMC, targeting auto, industrial and consumer markets and creating ~1,500 jobs." },
  1530: { descEn: "Kazakhstan's largest petrochemical project, ending all-import polyethylene.", detailEn: "KazMunayGas, with Russia's SIBUR and Sinopec, is building a 1.25-million-tonne/year polyethylene plant at the Atyrau industrial petrochemical park, fed by Tengiz gas. First pile in late 2024 and formal start in March 2025, with Sinopec Engineering as EPC; at ~$7.7 billion, it is due in 2028 and onstream in 2029, ending Kazakhstan's 100% polyethylene imports." },
  351: { descEn: "The Middle East's first clean-power-driven LNG export terminal.", detailEn: "At Ruwais Industrial City in Abu Dhabi, two liquefaction trains total 9.6 million tonnes/year, doubling ADNOC LNG capacity to 15 million tonnes. FID was taken in June 2024 with a $5.5 billion EPC contract; the first train is due in 2028." },
  2000: { descEn: "The world's largest 200mm silicon-carbide power-chip fab, phase 3.", detailEn: "Phase 1 (€2 billion) started in August 2024; phase 2 (up to €5 billion) and phase 3 bring the total to ~€7 billion built in stages to the late 2020s, making it Infineon's largest 200mm front-end base in Kulim, Malaysia. SiC capacity is underpinned by ~€5 billion of design wins and €1 billion of prepayments from auto and industrial customers." },
  2204: { descEn: "A fully privately-funded million-tonne green-ammonia flagship.", detailEn: "Signed by Egypt and France, the Ras Shukheir green-hydrogen and derivatives complex on the Red Sea has €7 billion of fully private investment in three phases, producing 1 million tonnes of green ammonia a year at capacity, mainly as marine fuel for Suez Canal traffic. It includes a 368 km² wind-solar base, desalination, a 7 km transmission corridor and a dedicated Red Sea jetty; phase 1 (EDF Renewables and Zero Waste, €2 billion, 300,000 t/year) targets 2029." },
  2988: { descEn: "A 500,000-vehicle/year Hyundai megaplant with an LG battery JV.", detailEn: "The Hyundai Motor Group Metaplant America (HMGMA) at Ellabell in Bryan County, Georgia is $7.6 billion and over 16 million sq ft; the first IONIQ 5 rolled off in October 2024, IONIQ 9 entered production, and the first Kia model arrives in 2026, with a $4.3 billion HL-GA battery JV. Hyundai is adding $21 billion of US investment over 2025-2028." },
  3240: { descEn: "Chennai Metro phase 2: three corridors, ~119 km, 128 stations.", detailEn: "Phase 2 comprises the Madhavaram-SIPCOT, Lighthouse-Poonamallee and Madhavaram-Sholinganallur corridors, with 30 billion rupees in FY2025-26 from the centre, planning partial opening in 2026 and full operation by 2028-29, lifting Chennai's metro network to 173 km." },
  1111: { descEn: "A northwest high-speed line completing the Beijing-Lanzhou corridor.", detailEn: "The Baoyin high-speed railway runs 519 km from Baotou to Yinchuan via Bayannur, Ordos, Wuhai and Shizuishan at 250 km/h, ~54.6 billion yuan. The Baotou-Huinong section opened on 23 December 2025, completing the line (Baotou-Yinchuan in 2h38). With it the 'Beijing-Lanzhou' corridor is fully through, bringing Bayannur and Wuhai into the high-speed era." },
  786: { descEn: "A Danish-German multi-terminal HVDC offshore wind hub.", detailEn: "Turning Denmark's Bornholm island into an offshore wind hub with 3 GW nearby (~2 GW for Germany, 1.2 GW for Denmark) to power three million homes. Germany and Denmark signed a bilateral deal in January 2026 and won a €645 million EU grant, targeting operation in 2032 — the world's first cost-shared cross-border offshore wind project." },
  1150: { descEn: "An inter-oceanic isthmus railway; Line K phase 1 opened November 2025.", detailEn: "Mexico's Interoceanic Corridor railway crosses the Tehuantepec Isthmus linking the Pacific port of Salina Cruz with the Atlantic port of Coatzacoalcos — a land alternative to the Panama Canal. The Z Line fully opened in late 2023; the 459 km K Line toward the Guatemala border was over 87% complete by early 2026 with phase 1 opening in November 2025. In spring 2025 Hyundai ran a first international vehicle-transport test across it in ~72 hours, ~5 days faster than the Panama Canal." },
  1752: { descEn: "A 3 GW offshore wind flagship off Ceará.", detailEn: "Neoenergia (Iberdrola group) plans the Jangadas offshore wind farm off Ceará — 3 GW, 200 15 MW turbines — having applied to IBAMA in December 2019, now in early environmental review. With Rio's Maravilha and Rio Grande do Sul's Águas Claras it forms a 9 GW Brazilian offshore portfolio, awaiting 2026 guidelines and first permits." },
  1753: { descEn: "A 3 GW offshore wind project off Rio Grande do Sul.", detailEn: "The Águas Claras offshore wind farm off Rio Grande do Sul, developed by Neoenergia, plans 3 GW with 200 15 MW turbines, applied to IBAMA in December 2019 and in early environmental licensing. The southern waters' strong winds make it a priority Brazilian offshore area, awaiting the first offshore auction and IBAMA's first permits in 2026." },
  2985: { descEn: "The most advanced 300mm silicon-wafer fab in the US; first wafers in 2025.", detailEn: "GlobalWafers' Sherman, Texas 300mm wafer fab produced first wafers in Q1 2025 — the most advanced high-volume 300mm wafer facility in the US. Phase 1 reached an initial 300,000 wafers/year in December 2025, with phase 2 starting in January 2026, at a planned ~$7.5 billion total." },
  3039: { descEn: "The world's first net-zero-emissions ethylene complex, in Alberta (delayed).", detailEn: "Dow's Path2Zero would be the world's first scope-1-and-2 net-zero ethylene cracker and derivatives complex, with carbon capture and blue-hydrogen power. Approved in November 2023, paused in April 2025 on tariffs and demand, and in January 2026 phase 1 slipped to 2029 and phase 2 to 2030, with cost up to ~C$10.3 billion." },
  1122: { descEn: "China's first airport with five commercial runways.", detailEn: "Guangzhou Baiyun Airport's ~53.8 billion-yuan phase-3 expansion opened its T3 terminal and fifth runway on 30 October 2025 after five years, making it China's first airport with five commercial runways and three terminals. It can handle 120 million passengers and 3.8 million tonnes of cargo near-term (ultimate 140 million); from January 2026 all 30 international airlines moved to T3, strengthening the Greater Bay Area hub." },
  1431: { descEn: "Phase 3 of Saudi Arabia's northern phosphate city; started early 2025.", detailEn: "At the Wa'ad Al Shamal mining city in Turaif, northern Saudi Arabia — one of the Middle East's largest mining projects — phase 3 is ~28 billion riyals (~$7.5 billion), launched by Prince Faisal in February 2025, lifting Saudi phosphate capacity to ~9 million tonnes a year. ~$922 million of construction contracts went to Chinese and Turkish contractors in January 2025." },
  1218: { descEn: "Indonesia's largest refinery upgrade.", detailEn: "At Balikpapan in East Kalimantan, Pertamina's refinery master plan (RDMP) raises capacity from 260,000 to 360,000 b/d and adds residue catalytic cracking to improve fuel quality. Inaugurated by President Prabowo in January 2026, it will help Indonesia stop diesel imports within 2026 and sharply cut gasoline imports." },
  3202: { descEn: "AM/NS India expanding Hazira crude steel from 9 to 15 million tonnes.", detailEn: "ArcelorMittal-Nippon Steel's AM/NS India is investing ~600 billion rupees to raise crude-steel capacity at Hazira, Gujarat from 9 to 15 million tonnes, adding a blast furnace, sinter, coke, converters and a hot-strip mill. Ground was broken in January 2025 with completion in H2 2026, eyeing 24 million tonnes by 2030." },
  183: { descEn: "The world's first UHV four-terminal flexible HVDC project.", detailEn: "This 2,681 km line spans Tibet, Yunnan, Guangxi and Guangdong at 10 GW rated capacity, with an integrated hydro-wind-solar base of over 150 billion yuan. Launched in September 2025 with the Guangdong section starting in January 2026, it targets full operation in 2029, delivering over 43 TWh of clean power a year." },
  502: { descEn: "The first site of the world's most powerful AI super-factory, in Wisconsin.", detailEn: "Microsoft is investing over $7.3 billion in the Fairwater 1 campus at Mount Pleasant, Wisconsin — 15 buildings, nearly 9 million sq ft, 3.3 GW at full power. A 400 MW phase 1 comes online in early 2026, joined with Atlanta's Fairwater 2 via dedicated fibre to form the world's first 'AI super-factory' for joint training." },
  2469: { descEn: "A R127 billion Transnet rail-and-port overhaul.", detailEn: "South Africa's state logistics giant Transnet announced R127 billion (~$7.3 billion) over five years to overhaul ageing rail and ports. Its three priority corridors are Richards Bay coal, Saldanha iron ore and Durban containers; an RFI to bring in private capital was issued in March 2025, with the Richards Bay dry-bulk terminal to expand 45% (18.5 to 26.9 million tonnes), focused on chrome and magnetite." },
  3279: { descEn: "IOCL's largest-ever single-site petrochemical complex at Paradip, Odisha.", detailEn: "In April 2025 IOCL signed an MoU with Odisha for a ~610.8 billion-rupee integrated PX and PTA complex with phenol, polypropylene and other downstream at Paradip, fed by its existing 15-million-tonne/year refinery — IOCL's largest single-site investment, expected to save over 300 billion rupees of forex a year." },
  3558: { descEn: "A new 350 km/h line across Anhui, Henan and Hubei.", detailEn: "318.4 km at 350 km/h and ~52.1 billion yuan from Fuyang West via Henan and Hubei to Huangzhou — a new north-south passenger corridor in central China. It has NDRC feasibility approval, with provinces along the route set to start in 2026." },
  1110: { descEn: "A key Yangtze-corridor high-speed section, opened December 2025.", detailEn: "The Wuhan-Yichang high-speed railway runs 313 km from Hankou via Tianmen, Jingshan, Jingmen and Dangyang to Yichang North at 350 km/h, ~52.3 billion yuan, opening on 26 December 2025 (Wuhan-Yichang in 69 minutes). A key section of the national Yangtze corridor, it links the Wuhan hub west toward the building Yichang sections, helping bring Shanghai-Chengdu within 6 hours." },
  2516: { descEn: "A second floating LNG vessel in the Rovuma Basin.", detailEn: "For the Coral North floating LNG project in Area 4 of Mozambique's Rovuma Basin, Eni took a $7.2 billion FID in October 2025 with partners CNPC, KOGAS, Mozambique's ENH and Abu Dhabi's XRG, producing 3.6 million tonnes of LNG a year from 2028. Technip Energies won key contracts; with the operating Coral South it lifts Mozambique's LNG above 7 million tonnes a year." },
  2649: { descEn: "An automated metro to the new Western Sydney Airport, opening 2026.", detailEn: "This ~23 km automated metro links St Marys with Western Sydney International Airport and the new Aerotropolis at about A$11 billion with several new stations. It is due to open in late 2026 alongside the new airport — one of NSW's largest rail projects, driving the Western Sydney aerotropolis." },
  1123: { descEn: "The world's largest offshore artificial-island airport.", detailEn: "Dalian Jinzhou Bay International Airport is China's first offshore artificial-island airport, ~50.9 billion yuan, built to 4F standard with four planned runways and a 900,000 m² terminal. Reclamation accelerated in 2025, forming 19.15 km² of land and ~95% of total works by mid-year; main completion is expected in 2028, set to be a Northeast Asian hub and the world's largest offshore airport." },
  105: { descEn: "Three 10-GW-class wind-and-solar bases in Xinjiang.", detailEn: "Northern Hami's Gobi and the Junggar Basin host multiple GW-scale wind and solar projects; in H1 2024 the Hami, Junggar and southern-Tarim 10-GW-class bases completed their 14th Five-Year tasks early, with Xinjiang adding 35.57 GW of renewables in 2024, the most of any province." },
  129: { descEn: "Shantou's drive to be a national offshore-wind industry base.", detailEn: "Built around an 'International Wind Power Innovation Port' strategy with a full offshore-wind supply chain, Shantou has attracted leaders like Mingyang and Goldwind, with several offshore projects approved and under construction, planning ~10 GW across nearshore and deep-sea waters." },
  263: { descEn: "North Africa's largest green-ammonia plant.", detailEn: "At Tarfaya in southwest Morocco, OCP uses local wind and solar to electrolyse green hydrogen for ammonia — 200,000 tonnes in 2026 rising to 1 million in 2027 — winning EU renewable-fuel pre-certification in June 2025 to open the European green-ammonia market." },
  514: { descEn: "A new Google campus in Cedar Rapids, Iowa.", detailEn: "In June 2025 Google committed $7 billion to expand its Iowa data centres, including a new campus in the Big Cedar industrial park at Cedar Rapids (first building due 2026, five phases) and an expansion at Council Bluffs, lifting Google's total Iowa investment above $13.8 billion." },
  1127: { descEn: "A freight railway land bridge linking the Red Sea to the capital.", detailEn: "The Saudi Landbridge builds over 1,500 km of railway, centred on the ~900 km Riyadh-Jeddah trunk plus a 146 km extension to King Abdullah Port on the Red Sea, giving direct freight access between the Red Sea and the capital. Built by the SAR-CRCC 'Saudi-China Landbridge' consortium with Al-Ayuni as local partner, it began in 2025 with phased tendering, targeting the 2030s — a backbone of the Vision 2030 logistics strategy." },
  1756: { descEn: "Ceará offshore wind directly supplying Pecém green hydrogen.", detailEn: "France's Qair plans the 1.2 GW Dragão do Mar offshore wind farm on the Ceará shelf, supplying a 2.2 GW electrolyser at Pecém port for ~296,000 tonnes of green hydrogen a year. At nearly $7 billion, it is a model of integrated offshore wind and green hydrogen, in IBAMA's offshore permit pipeline and the Pecém green-hydrogen hub, awaiting the offshore auction." },
  1872: { descEn: "~7 GW of long-duration pumped hydro across NEOM phases 2-4.", detailEn: "NEOM plans four pumped-hydro plants; besides phase-1 Nestor, the Al-Qimmah, Nima and Beach Mountain stations are planned at ~3,000/1,000/3,000 MW, totalling ~7 GW, providing intraday peaking and long-duration storage for the off-grid renewable system, phased in after Nestor for 2029-2031." },
  1964: { descEn: "A large Thai green hydrogen and ammonia value chain.", detailEn: "Thailand's PTT and EGAT signed an MoU with Saudi ACWA Power to build a green hydrogen-and-ammonia value chain at ~$7 billion, targeting 225,000 tonnes of green hydrogen converted to ~1.2 million tonnes of green ammonia a year for power co-firing, exports to Japan and Korea and marine fuel. PTTGC-BIG cooperation and a Map Ta Phut hub are advancing in parallel — a flagship of Thailand's energy transition." },
  2001: { descEn: "A ~$7 billion advanced-packaging base in Penang; first phase in 2026.", detailEn: "Announced in 2021 at ~$7 billion (RM30 billion), Intel's Penang plant was paused then restarted under CEO Lip-Bu Tan, with another RM860 million added in December 2025 for assembly and test. With the building nearly done, advanced-packaging first-phase operation is set for 2026, reinforcing Malaysia's ~13% share of global assembly and test." },
  2253: { descEn: "OCP's green-ammonia plant at Tarfaya, reaching 3 million tonnes by 2032.", detailEn: "At the core of OCP's $13 billion green investment, ~$7 billion builds a green-ammonia plant at Tarfaya via the green-hydrogen route: 200,000 tonnes/year first output in 2026, 1 million in 2027 and 3 million by 2032 to decarbonise its own fertiliser supply chain. OCP earned $5 billion of H1 2025 revenue, issued a $1.75 billion bond in April and won SACE and AFD green loans." },
  2266: { descEn: "An eastern Algerian phosphate-to-fertiliser complex, ~$7 billion.", detailEn: "Sonatrach with China's CITIC develops an integrated phosphate project: the Tebessa facility (~$7 billion) processes Bled El Hadba ore into ~5.4 million tonnes of fertiliser a year, with a downstream plant near Souk Ahras (~$2 billion). Saipem won the FEED in June 2025; ~$1.5 billion more goes to mining the Bled El Hadba and Djebel El Onk deposits (~4.7 billion tonnes of reserves)." },
  3022: { descEn: "The Q line extended north to 125th Street, adding three East Harlem stations.", detailEn: "New stations at 106th, 116th and 125th Streets connect to Metro-North. Full FTA funding of $3.4 billion was secured in November 2023, with a ~$7 billion budget partly backed by congestion pricing; Skanska signed a ~$1 billion contract in June 2026, with boring expected in 2027 and opening in 2032." },
  3040: { descEn: "A planned world-largest low-carbon hydrogen-ammonia plant at Baytown, with CCS.", detailEn: "ExxonMobil plans the world's largest low-carbon hydrogen and ammonia facility at Baytown, Texas — up to 1 billion cubic feet/day of blue hydrogen and over 1 million tonnes of blue ammonia a year, capturing up to 7 million tonnes of CO₂ (~98% of production CO₂). ADNOC plans a 35% stake, with FID expected in 2025 and start-up in 2028-2029." },
  3219: { descEn: "AWS's $7 billion 14-year Hyderabad data-centre expansion.", detailEn: "AWS announced $7 billion over 14 years to expand its Asia Pacific (Hyderabad) cloud infrastructure, on top of an $8.3 billion Mumbai-region top-up the same year, targeting 2-3 GW of data-centre capacity in India for AI and cloud demand." },
  3266: { descEn: "A ~$7 billion double-tracking upgrade of the 1,687 km Karachi-Peshawar ML-1.", detailEn: "ML-1 is Pakistan's main railway, ~1,687 km from Karachi's Kiamari to Peshawar; phase 1 (~929 km, $3.32 billion) and phase 2 (~796 km, $3.36 billion) are planned with a China-led financing consortium including the ADB and AIIB. In December 2025 Pakistan Railways reached an agreement with the ADB on the project." },
  3438: { descEn: "The largest China-Russia nuclear project; Tianwan phase 4, unit 7 cold-tested in 2025.", detailEn: "At the Tianwan base in Lianyungang, Jiangsu, developed by Jiangsu Nuclear Power, phase-4 units 7 and 8 use Russia's AES-2006 (VVER-1200) at 1.265 GW each. Construction was witnessed by the Chinese and Russian presidents via video in May 2021, with unit 7 completing cold tests in 2025." },
  3570: { descEn: "A hub-airport phase-3 expansion: a 610,000 m² T3 and third runway.", detailEn: "This expansion adds a 3,600 m third runway and taxiway system south of the second runway, plus a 610,000 m² T3 terminal west of T1/T2, 174 stands and a ground transport centre, at ~50 billion yuan. It would lift the airport to 65 million passengers and 900,000 tonnes of cargo a year; Nanjing has made it the city's top project for 2026, aiming to start by end-2026." },
  4516: { descEn: "Datang's 1 GW solar MoU with Zambia's ZESCO.", detailEn: "In October 2024, witnessed by Zambia's science minister and ZESCO's chairman, Datang Overseas Investment signed a 1 GW solar MoU and an energy-technology-innovation-centre MoU with ZESCO, building on an earlier 220 MW cooperation. The 1 GW solar would greatly boost Zambia's clean-energy supply, with an accompanying innovation centre; it is in early planning." },
  1194: { descEn: "Stabroek's seventh development; FID in September 2025.", detailEn: "Hammerhead is ExxonMobil's seventh approved development in Guyana's Stabroek block, taking FID in September 2025 at about $6.8 billion, with the SBM-built FPSO Jaguar producing an initial 150,000 b/d. With block reserves near 11 billion barrels of oil equivalent, it targets 2029 start-up — an important part of Guyana's mid-term growth." },
  2061: { descEn: "A railway giving landlocked Laos sea access via Vietnam's Vung Ang port.", detailEn: "Linking Vientiane in Laos with Vung Ang port in Ha Tinh, Vietnam, this gives landlocked Laos its first direct rail route to the sea, at about $6.6 billion as a PPP by Laos's PTL and Vietnam's Deo Ca Group. In December 2025 it was announced the Laos section starts in 2026 and the Vietnam section in 2027, targeting completion by 2030." },
  3533: { descEn: "A 46.8-billion-yuan hyperscale AI-compute centre in Pinghu, part of a national 10,000-GPU cluster.", detailEn: "In Xindai, Pinghu, Jiaxing, Zhejiang, this 46.8-billion-yuan centre adds 344 mu and over 560,000 m² of floor area for four high-grade AI-compute halls over a four-year build, becoming an important part of the national integrated compute network's 10,000-GPU cluster project." },
  251: { descEn: "The world's first large-scale green-hydrogen DRI plus electric-arc steel plant.", detailEn: "At Boden in northern Sweden, this plant uses a 690 MW electrolyser to make wind-powered green hydrogen to reduce iron ore instead of coke. Electrolyser modules were installed by end-2025 (~60% overall), with 2.5 million tonnes of green steel after hot commissioning in 2026 — the most important green-metallurgy demonstration globally." },
  630: { descEn: "A top-ten global copper mine, shut since 2023, awaiting a 2026 restart decision.", detailEn: "In Coclé, Panama, Cobre Panamá produced ~400,000 tonnes of copper a year (~1% of global) until it was shut in November 2023 amid nationwide protests. An environmental-social audit finished in late 2025, with the president promising a decision on its fate by June 2026; a restart would add major copper supply globally." },
});

/* ===== 批次6：全库投资额 TOP（约 56–65 亿美元）===== */
Object.assign(window.ENERGY_EN, {
  1146: { descEn: "North America's largest driverless light-rail network; phase 2 opened November 2025.", detailEn: "The REM is a ~67 km fully automated driverless light-rail system for Greater Montreal, built and operated by CDPQ Infra. It launched on 14 November 2025, with the 33 km/14-station Deux-Montagnes branch through the Mount Royal tunnel opening on the 17th; four western stations follow in May 2026 and the Trudeau Airport spur in 2027." },
  1221: { descEn: "The fourth Central Asia-to-China gas line.", detailEn: "Line D runs ~966 km from Turkmenistan's Galkynysh field via Uzbekistan, Tajikistan and Kyrgyzstan into Xinjiang at 30 bcm/year, greatly raising total Central Asia-China pipeline capacity. Long delayed over transit and pricing, Galkynysh phase-4 development and Line D construction advanced in early 2026 — key to diversifying China's overland energy imports." },
  1764: { descEn: "Four green-powered data centres at the Pecém green digital hub in Ceará.", detailEn: "In November 2025 Ceará's export-processing zone approved Exportdata's four data centres (partnered with Casa dos Ventos executives) at R$349 billion, phased to 2032, forming the Pecém port green digital hub alongside the ByteDance project, powered 100% by new Casa dos Ventos wind farms and creating ~95,000 jobs." },
  2024: { descEn: "Oracle's $6.5 billion Malaysia public cloud region.", detailEn: "Oracle is investing over $6.5 billion in a Malaysian public cloud region — its 12th in Asia-Pacific — with 150+ cloud services and an OCI supercluster of 130,000 Blackwell GPUs, likely in Johor (a 15-year lease on Yondr's 98 MW first phase), phased from 2025 to capture Southeast Asian sovereign-cloud and AI demand." },
  2255: { descEn: "Africa's first battery gigafactory; Gotion's 20 GWh first phase at Kenitra.", detailEn: "Led by China's Gotion High-Tech at ~$5.6-6.8 billion, Africa's first battery gigafactory at Kenitra, Morocco broke ground in May 2025 for a 20 GWh first phase (expandable to 100 GWh) making cells, cathode and anode materials, ~85% for the EU, drawing a full chain of Chinese suppliers." },
  3323: { descEn: "The region's largest iron-ore deposit (~2.2 billion tonnes).", detailEn: "Hajigak in Bamyan province, central Afghanistan is the region's largest iron-ore deposit at ~2.2 billion tonnes, a world-class find. After an Indian consortium won then withdrew in 2011, the Taliban signed seven mining contracts worth ~$6.5 billion with Chinese, Iranian, Turkish and UK firms in August 2023, including a 30-year Herat iron deal giving the government a 13% share." },
  787: { descEn: "The finale of Iberdrola's East Anglia offshore wind cluster.", detailEn: "In the southern North Sea off England, ScottishPower Renewables' wholly-owned 960 MW East Anglia THREE began substation works in Q4 2025, with foundations in 2027 and operation in 2028 to power ~950,000 homes." },
  3017: { descEn: "A six-lane cable-stayed bridge across the Detroit River, among North America's longest.", detailEn: "With an 853 m main span and six lanes plus a walkway, the Canada-funded Gordie Howe International Bridge linking Windsor and Detroit cost about C$6.4 billion. The main structure was largely done by end-2025, with opening pushed to early 2026 on testing and border handover — set to be one of the busiest US-Canada freight crossings." },
  3559: { descEn: "A new 350 km/h line opening a high-speed corridor through the Wuling Mountains.", detailEn: "About 222 km at 350 km/h and ~45.4 billion yuan, this line links Qianjiang in Chongqing with Jishou in western Hunan, joining the Chongqing-Hunan and Zhangjiajie-Jishou-Huaihua high-speed lines; pre-review and industry review were completed in January 2026." },
  1463: { descEn: "The world's tallest dam; rising to 1,110 m in 2025.", detailEn: "On the Vakhsh River, Rogun's 335 m clay-core rockfill dam is the world's tallest, with 3,780 MW that would double Tajikistan's generation and power ~10 million people. By August 2025 the dam neared 1,110 m elevation (up ~100 m and 13 million m³ in a year); built by Italy's Webuild, with two units already running, Tajikistan aims for energy independence by 2027." },
  3572: { descEn: "Chongqing's second airport, a greenfield 4F hub, targeting 2030.", detailEn: "Sited at Zhengxing in Bishan, this 4F greenfield airport covers ~37 km² with 3-4 runways of 3,200-3,800 m, planned long-term for 70 million passengers and 3.5 million tonnes of cargo. Phase 1 (T1, two runways and a transport hub) is ~45 billion yuan; it is a key reserve project, to start early in the 15th Five-Year period and aim for 2030." },
  784: { descEn: "Poland's largest offshore wind project; FID January 2025.", detailEn: "In the Baltic 40 km off Poland, Baltica 2 is a 50/50 Orsted-PGE JV of 1.5 GW with 107 turbines and four offshore substations. After FID in January 2025, monopile installation starts in May 2026 for full operation by end-2027, powering 2.5 million Polish homes." },
  1212: { descEn: "The world's largest single polyolefins base.", detailEn: "At Ruwais Industrial City, Abu Dhabi, ADNOC-OMV's Borouge adds ~1.4 million tonnes/year of polyethylene/polypropylene with a world-largest ~1.8-million-tonne mixed-feed cracker. The first XLPE unit started up in April 2026 with the rest onstream through 2026, making Ruwais the world's largest single polyolefins complex." },
  2023: { descEn: "AWS's second Southeast Asia cloud region, live August 2024.", detailEn: "AWS launched its Asia Pacific (Malaysia) cloud region with three availability zones on 21 August 2024, planning $6.2 billion of cumulative investment by 2038, mainly in Selangor. It is expected to add ~$12.1 billion to Malaysian GDP and support 3,500+ jobs a year, strengthening local data residency and low latency." },
  2528: { descEn: "A world-class new refinery in Angola.", detailEn: "Sonangol's $6.2 billion Lobito refinery, 200,000 b/d, is in talks for a ~$4.8 billion Chinese loan to finish, targeting 2027 to sharply raise Angola's fuel self-sufficiency and cut imports." },
  3434: { descEn: "Zhejiang's fourth nuclear base; Jinqimen phase-1 island works fully started August 2025.", detailEn: "At Xiangshan in Ningbo, Zhejiang, CNNP-controlled Jinqimen plans six MW-class PWRs; phase-1 units 1-2 use Hualong One at 1.2 GW each with a 60-year design life, approved by the State Council in December 2023 with nuclear-island works in full swing from August 2025." },
  3563: { descEn: "A 350 km/h coastal-corridor line from Wenzhou to Fuzhou; started September 2025.", detailEn: "About 287.7 km at 350 km/h and ~44 billion yuan from Wenzhou via Rui'an, Cangnan, Fuding and Ningde to Fuzhou — part of the national coastal corridor. It started on 29 September 2025 for 2030 completion, putting Wenzhou-Fuzhou within about an hour." },
  879: { descEn: "Xinjiang's largest green hydrogen-ammonia-methanol investment to date.", detailEn: "Led by Energy China at 44.5 billion yuan in Kashgar, Xinjiang, this plans a GW-scale off-grid integrated green-power-to-hydrogen-ammonia-methanol park; environmental review began in September 2025, with approvals by end-2025 and core construction in Q1 2026." },
  3254: { descEn: "The Eastern Dedicated Freight Corridor's core section is fully in service.", detailEn: "The EDFC core from Ludhiana in Punjab to Sonnagar in Bihar (1,337 km) was fully commissioned in November 2025; the full ~1,856 km to Dankuni in West Bengal is under construction at ~510 billion rupees, running ~385 freight trains a day." },
  3407: { descEn: "Qingdao's first large 3 GW offshore wind project.", detailEn: "In national-managed waters of Qingdao's southeast EEZ, this project plans 214 14 MW turbines (~2,996 MW) with offshore and onshore converter stations. The offshore part was approved in November 2024, with environmental review in September 2025 and the 3.1-billion-yuan onshore export works approved on 31 December 2025." },
  3430: { descEn: "China's first nuclear project with private (Geely) capital; phase-2 unit 3 started November 2025.", detailEn: "At Xiaguan in Cangnan, Wenzhou, Zhejiang, CGN-controlled Cangnan plans six Hualong One units; phase 2 builds units 3-4 at 1.2 GW each, approved by the State Council in August 2024 and among Zhejiang's Q1 construction starts." },
  3435: { descEn: "The starting point for series deployment of the Guohe One (CAP1400); siting EIA approved December 2025.", detailEn: "At Dongmajiapo in Laiyang, Yantai, Shandong, SPIC plans six Guohe One units at ~128.3 billion yuan; fully built, over 9.2 GW would make it one of China's largest nuclear bases, with two units in phase 1." },
  3436: { descEn: "SPIC's Lianjiang nuclear phase 2; two Guohe One units, preparatory work fully launched in 2025.", detailEn: "At Cheban in Lianjiang, Zhanjiang, Guangdong, SPIC's base plans two CAP1000 plus four Guohe One units; phase 2 builds Guohe One units 3-4 at ~1.53 GW each over a 60-month schedule, with phase 1 already started." },
  163: { descEn: "Africa's largest single-country renewable-development agreement.", detailEn: "In June 2024 Infinity Power (an Egypt Infinity-UAE Masdar JV) signed an MoU with Cameroon's West Region to phase in up to 4 GW of solar, wind, hydro and biomass by 2035 — a pillar of its 10 GW African expansion." },
  242: { descEn: "CATL's largest full-chain battery base in Southeast Asia.", detailEn: "At nearly $6 billion, this covers nickel mining in North Maluku, cathode materials and battery and vehicle production in Karawang; phase 1 is 6.9 GWh rising to 15 GWh at capacity, expected online by end-2026." },
  264: { descEn: "Australia's largest aluminium smelter goes green.", detailEn: "At Gladstone, Queensland, this 500,000-tonne/year smelter saw Rio Tinto sign Australia's largest renewable PPA (2.8 GW wind, solar and storage) in 2024; with federal and state subsidies, green aluminium could be produced from 2028." },
  273: { descEn: "Inner Mongolia's 'east-data-west-compute' hub, top-ranked for green computing.", detailEn: "Horinger New Area has landed 39 data-centre projects with 50,600 PFLOPS in use (94% AI compute) and 84.57% green power by May 2025, using wind, solar and a cold climate to serve Beijing-Tianjin-Hebei compute demand." },
  518: { descEn: "A CoreWeave Mid-Atlantic AI supercomputing campus in Lancaster, Pennsylvania.", detailEn: "In July 2025 CoreWeave announced converting two former printing plants in Lancaster, Pennsylvania into AI data centres with an initial 100 MW (expandable to 300 MW), developed by Chirisa and Machine Investment Group and leased exclusively by CoreWeave." },
  581: { descEn: "The UK's largest AI supercomputer, the first Stargate UK node.", detailEn: "Nscale is building the UK's largest AI supercomputing campus at Loughton, England, with Microsoft signing a $6 billion GPU-capacity lease; a first phase deploys 23,040 Nvidia GB300 GPUs and OpenAI places a Stargate UK node here, expandable to 90 MW and due online in Q1 2027." },
  631: { descEn: "One of the world's largest copper-gold mines, restarting in phases after a 2025 accident.", detailEn: "In West Papua, Indonesia, Grasberg — one of the world's largest single copper-gold mines — went underground in 2019. After a September 2025 mudflow accident it declared force majeure, restarting main production zones in Q2 2026, aiming to recover ~85% of capacity in H2 and full capacity by 2027-2028." },
  877: { descEn: "A 6 GW green-hydrogen project in WA, with Australian government funding.", detailEn: "On the WA coast in the Murchison region, Copenhagen Infrastructure Partners plans 6 GW of wind and solar for ~1.3 million tonnes of green ammonia export a year, winning A$814 million from the Hydrogen Headstart program in 2025 and fast-track status, targeting FID in 2027 and phase-1 operation in 2029." },
  1181: { descEn: "Argentina's first large-scale LNG export.", detailEn: "Southern Energy — Pan American Energy, YPF, Pampa, Harbour and Golar — deploys two floating liquefaction vessels at Punta Colorada (San Matías Gulf), Río Negro: Hilli Episeyo (2.45 MTPA) and the converting MkII (3.5 MTPA), fed by Vaca Muerta gas. The second vessel's FID came in 2025 with an 8-year deal with Germany's SEFE, targeting exports from late 2027." },
  1196: { descEn: "An expansion of the supergiant Caspian Kashagan field, with gas plants.", detailEn: "Kashagan in the northern Caspian produces ~450,000 b/d; the NCOC consortium is building two gas plants (~2.5 bcm/year of sales gas with LPG) and pursuing further expansion to reach 500,000 b/d in 2026 and 700,000 b/d by 2031. In October 2025 Kazakhstan and ExxonMobil discussed further growth — key to Central Asian output and gas use." },
  1213: { descEn: "The Middle East's largest ethane cracker.", detailEn: "At Ras Laffan Industrial City, Qatar, the QatarEnergy-Chevron Phillips Chemical JV builds a 2.08-million-tonne/year ethane cracker (the Middle East's largest) and two HDPE units totalling 1.68 million tonnes. Started in 2022 with $4.4 billion financing in 2023, it targets late 2026, lifting Qatar's petrochemical capacity to ~14 million tonnes/year." },
  1529: { descEn: "Compressors to sustain the Karachaganak condensate plateau.", detailEn: "KPO's expansion adds a fifth gas-reinjection compressor (2020-2025, fuel gas introduced July 2024) and a sixth (phase 1B, 2022-2028); by raising reinjection capacity to manage rising gas-oil ratios, it sustains liquids output at Kazakhstan's second-largest oil-and-gas field." },
  1540: { descEn: "Vostok Oil's Arctic export terminal, shipping via the Northern Sea Route.", detailEn: "Sever Bay is the Arctic crude export terminal of the Vostok Oil project, on the Kara Sea at the Yenisei mouth, with oil shipped by icebreaking tankers via the Northern Sea Route. Two cargo berths and a fleet berth are near completion, with throughput planned to reach 50 million tonnes a year by 2027." },
  1552: { descEn: "The world's largest undeveloped gold mine, Polyus's flagship.", detailEn: "In Irkutsk region, Sukhoi Log is called the world's largest undeveloped gold deposit. A trial at the Verninskaya plant produced first gold in 2024; the processing plant began construction in 2025 ($650-800 million capex that year), with ~$6 billion total. Phase 1 reaches 10 million tonnes/year of ore in 2028, with 30 million planned." },
  1716: { descEn: "A deepwater module 2 in the Sergipe-Alagoas basin, a new northeast producing area.", detailEn: "SEAP II (P-87) develops the ultra-deepwater Budião and other fields in the Sergipe-Alagoas basin ~80 km off Aracaju, producing 120,000 b/d and processing 12 million m³/day of gas. FID came in April 2026 with an SBM BOT contract in May (SEAP I+II over R$60 billion combined); oil from 2030 and gas from 2031 would lift northeast gas supply from 16% to 31%." },
  1898: { descEn: "The Saudi backbone of the GCC railway, linking the Kuwaiti and UAE borders.", detailEn: "As the core of the 2,117 km GCC rail network, the Saudi section runs ~672 km from Al-Khafji near Kuwait in the Eastern Province south to Al-Batha on the UAE border. SAR issued design-consultancy tenders in May 2025 (closing 30 June); the network targets 2030, with the Saudi section starting in 2026 to enable Gulf-wide rail interconnection." },
  1917: { descEn: "Saudi Arabia's fourth integrated phosphate-fertiliser project.", detailEn: "In January 2026 Ma'aden won an energy-ministry gas-feedstock allocation to begin engineering on its fourth phosphate project, adding ~2.5 million tonnes/year of phosphate and specialty fertilisers and ~1.1 million tonnes of ammonia, lifting group phosphate-fertiliser capacity toward 12 million tonnes/year — a net addition beyond Phosphate 3, on the northern phosphate belt." },
  2563: { descEn: "A cross-border iron-ore mine with a 510 km haul railway and the Kribi deep-water port.", detailEn: "Straddling the Cameroon-Congo border, Mbalam-Nabeba plans 35 million tonnes/year of iron ore, needing a ~510 km railway to the Kribi deep-water port. Formerly Sundance's Cam Iron, it passed to local firm Cameroon Mining after a licence dispute, forming a multi-billion-dollar integrated mine-rail-port development." },
  2656: { descEn: "Transport infrastructure for the Brisbane 2032 Olympics.", detailEn: "A cluster of transport works for the Brisbane 2032 Olympics — rail, bus rapid transit (Brisbane Metro expansion), venue links and airport upgrades — boosting Southeast Queensland's transit capacity and connectivity, with planning and construction advancing from 2025." },
  2716: { descEn: "A 1.5 GW offshore wind farm off Lincolnshire.", detailEn: "Off the Lincolnshire coast in eastern England, this ~1.5 GW offshore wind farm (developed by Corio Generation and others) can power ~1.6 million homes, advancing DCO consent and grid connection in 2025 as an important North Sea expansion." },
  2802: { descEn: "The UK's first small modular reactors, sited at Wylfa, Anglesey.", detailEn: "Great British Energy-Nuclear selected Rolls-Royce SMR as preferred partner and in November 2025 chose Wylfa on Anglesey, Wales as the UK's first SMR site, planning several 470 MW-class units for factory-built, series nuclear, targeting the 2030s." },
  2812: { descEn: "Haiyang CAP1000 phase 3, approved in 2025.", detailEn: "At Haiyang in Yantai, Shandong, using the localised Gen-III CAP1000, phase-3 units of 1.25 GW each were approved by the State Council in April 2025. The Haiyang base also pioneers nuclear district heating ('Warm Nuclear No.1'), a benchmark for nuclear power and zero-carbon heat in northern China." },
  2813: { descEn: "Sanmen Gen-III nuclear phase 3, approved in 2025.", detailEn: "At Sanmen in Taizhou, Zhejiang — one of the world's first AP1000 sites — phase-3 units were approved by the State Council in April 2025. Built on passive Gen-III safety technology, the continuing expansion serves Yangtze Delta clean power." },
  2817: { descEn: "China's demonstration sodium-cooled fast reactor with a closed fuel cycle.", detailEn: "At Xiapu in Fujian, the CFR-600 is China's demonstration sodium-cooled fast reactor, two 600 MW units. Fast reactors greatly improve uranium use and transmute long-lived waste — key to Gen-IV nuclear and a closed fuel cycle; the first unit is near start-up and the second under construction, targeting around 2026." },
  2821: { descEn: "India's largest nuclear base completing two more VVER units.", detailEn: "At Kudankulam in Tamil Nadu, India's largest nuclear base, Russia's Rosatom is helping complete units 5 and 6 (1 GW VVER-1000 each), with main works advancing in 2025 toward around 2027 to support southern India's power and clean-energy goals." },
  2830: { descEn: "A world-leading commercial fusion effort; Google to buy ARC power.", detailEn: "At Devens, Massachusetts, Commonwealth Fusion Systems is building the SPARC tokamak (demonstrating net fusion gain), largely done by end-2026 with first plasma in 2027, and plans a ~400 MW ARC commercial fusion plant in Virginia. Google has agreed to buy 200 MW from ARC, becoming the first fusion firm to apply to join the PJM grid in 2026 — a global commercial-fusion frontrunner." },
  3036: { descEn: "A midscale LNG export terminal at the Port of Brownsville, EPC with Kiewit.", detailEn: "Glenfarne's Texas LNG at the Port of Brownsville has 4 million tonnes/year total in two phases. FERC re-approved it early in August 2025, and in March 2026 it signed a full-facility EPC with Kiewit, aiming for completion by end-2029." },
  3294: { descEn: "Five Pakistani refineries upgrading to Euro-V, ~$6 billion total.", detailEn: "Pakistan's 2023 brownfield refining policy is pushing PARCO, Attock, NRL, Cnergyico and PRL to upgrade for Euro-V fuels, drawing at least $6 billion, with capacity potentially rising from ~21-23 million tonnes/year toward ~33 million by 2035; PARCO plans to bring in ~$1.3 billion from the UAE for a hydrocracker." },
  3571: { descEn: "A Silk Road hub expansion: a new T4 and twin runways; North Terminal opened April 2025.", detailEn: "This rebuild lifts terminal space to 500,000 m² and upgrades the airfield to 4F with three runways and 198 stands, designed for 35 million passengers and 550,000 tonnes of cargo at ~42.84 billion yuan. T4 and the two northern runways opened on 17 April 2025, with the airport renamed Urumqi Tianshan International." },
  4206: { descEn: "Tsingshan-led integrated nickel-stainless super-park at Morowali, Indonesia.", detailEn: "At Morowali in Central Sulawesi, this 2,000+ hectare park is a JV of Shanghai Decent (66.25%) and Indonesia's Bintang Delapan (33.75%), producing 4.2 million tonnes of nickel-iron, 4 million tonnes of stainless steel, 7 million tonnes of carbon steel and 90,000 tonnes of HPAL nickel a year, with coke power, ferrochrome, a 140-million-tonne port and 2,000+ MW of captive power (~4,300 MW total) — the world's first full mining-to-stainless chain park." },
  3560: { descEn: "A new 350 km/h line, part of the Baotou(Yinchuan)-Haikou corridor.", detailEn: "About 276 km at 350 km/h and ~42 billion yuan, this line links Baotou and Ordos in Inner Mongolia with Yulin in Shaanxi as part of the Bao(Yin)-Hai corridor; the pre-feasibility study is done, aiming to start in 2026." },
  3561: { descEn: "China's southernmost cross-strait high-speed link, using rail plus ferry across the Qiongzhou Strait.", detailEn: "With ~132 km of onshore mainline at 350 km/h and a ~23 km ferry crossing of the Qiongzhou Strait, at ~41.94 billion yuan, this is part of the Bao(Yin)-Hai corridor. The NDRC approved the ferry crossing and related lines on 31 December 2025, aiming for completion within the 15th Five-Year period." },
  3585: { descEn: "An 11-million-tonne refining phase 2 at Zhenhai, lifting the base above 50 million tonnes.", detailEn: "At Zhenhai in Ningbo, Zhejiang, this 41.6-billion-yuan phase 2 covers 18 chemicals-focused units (11-million-tonne CDU, FCC, propane dehydrogenation, polypropylene). The core 11-million-tonne refining unit started up in January 2025, lifting Zhenhai's refining to 40-million-tonne class and the Ningbo petrochemical base above 50 million tonnes." },
  244: { descEn: "One of the largest new US battery campuses.", detailEn: "At Glendale, Kentucky, this twin-plant BlueOval SK campus totals 86 GWh, mainly for the Ford F-150 Lightning; first cells rolled off in August 2025 with ~5,000 jobs, backed by a US DOE loan." },
  255: { descEn: "Korea's largest US steel investment.", detailEn: "In Louisiana, this plant will make 2.7 million tonnes/year of low-carbon automotive sheet with 70% lower emissions than a blast furnace, with POSCO holding 20%; construction starts in Q1 2026 for 2029 production, mainly for the US-Mexico auto market." },
  874: { descEn: "South Africa's largest green hydrogen-ammonia export project.", detailEn: "At the Coega industrial zone in Eastern Cape, a JV of UK's Hive Energy and South Africa's BuiltAfrica plans $5.8 billion for 3.5 GW of wind and solar and 1 million tonnes/year of green ammonia for Europe, with $20 million of SA-H2 fund development finance, FID targeted for H2 2026 and operation from 2029." },
  2054: { descEn: "An east-west metro trunk line across Bangkok; western section under construction.", detailEn: "35.9 km (27 km underground, 22 stations; 8.9 km elevated, 7 stations) in eastern (22.5 km) and western (13.4 km) sections at ~200 billion baht. BEM holds a 140-billion-baht, 30-year PPP for the western section; the eastern civil works finished in June 2023 and the western started in July 2024, targeting the east by May 2028 and the west by 2030." },
  2460: { descEn: "South Africa's first large-scale green-ammonia export project, with Topsoe technology.", detailEn: "Hive Hydrogen is developing a 1-million-tonne/year green-ammonia plant at the Coega SEZ powered by 1,499 MW of wind and 1,430 MW of solar (3.5 GW total). Denmark's Topsoe won a ~$1 billion technology contract and the SA-H2 fund injected $20 million; full output is designed for 2029, expandable to 4 million tonnes." },
  1223: { descEn: "A petrochemical expansion at the Bina refinery in central India.", detailEn: "At Bina in Madhya Pradesh, BPCL is raising refining from 7.8 to 11 million tonnes/year and adding a petrochemical complex with a 1.2-million-tonne dual-feed cracker plus PE, PP and aromatics. A ~318-billion-rupee syndicated loan closed financing in January 2025; ~11% complete by March 2025, it targets 2028 — central to BPCL's shift from fuels to chemicals." },
  1810: { descEn: "A green-iron project in Bahia's Chapada Diamantina.", detailEn: "Brazil Iron and state miner CBPM develop a green-iron project in Bahia's Chapada Diamantina (Piatã, Abaíra, Jussiape) at ~$5.7 billion, using direct reduction to make ultra-low-carbon hot-briquetted iron (HBI), with three open-pit mines, a 120 km rail spur, a pellet plant and a coastal HBI plant at Porto Sul. With ~1.7 billion tonnes of resources, it starts in late 2026 for 2030 production." },
  2989: { descEn: "Twin battery plants at Kokomo; plant 1 online, plant 2 in 2027, 67 GWh combined.", detailEn: "The Stellantis-Samsung SDI StarPlus JV is investing over $5.7 billion in two lithium plants at Kokomo, Indiana; plant 1 started up in December 2024 (33 GWh) and plant 2 is due in early 2027 (initially 34 GWh), totalling 67 GWh, with a ~$7.54 billion DOE loan." },
  4298: { descEn: "State Grid holds ~21% of HK Electric Investments, in Hong Kong's grid.", detailEn: "State Grid subscribed ~21% (~$5.7 billion) as the largest cornerstone investor when HK Electric Investments listed in 2014. HK Electric is the sole power supplier to Hong Kong Island and Lamma Island, a vertically integrated utility from generation to supply — a key Hong Kong grid asset giving State Grid stable returns and an overseas-grid platform." },
  1128: { descEn: "Dubai Metro's third line, opening 2029.", detailEn: "The 30 km Blue Line (15.5 km underground, 14.5 km elevated) links several hubs; the design-build contract went to MAPA-Limak-CRRC in late 2024, with CRRC supplying 28 driverless trains. Works began in June 2025 with tunnelling, ~12% complete by December, targeting 9 September 2029 (the metro's 20th anniversary)." },
  1147: { descEn: "The world's first floating-bridge light rail; cross-lake link opens March 2026.", detailEn: "Seattle's Sound Transit Line 2 (East Link), ~23 km, links downtown Seattle with Redmond via 10 stations including Bellevue and Mercer Island. On 28 March 2026 the cross-Lake-Washington segment opens, running ~7 miles on the world's first floating-bridge electrified light rail along I-90, with Judkins Park and Mercer Island stations — connecting Seattle and Bellevue in ~20 minutes after 18 years of planning." },
});

/* ===== 批次7：全库投资额 TOP（约 50–60 亿美元）===== */
Object.assign(window.ENERGY_EN, {
  4222: { descEn: "Aramco-Sinopec Yanbu petrochemical expansion: 1.8 Mt ethylene + 1.5 Mt aromatics.", detailEn: "In April 2025 Saudi Aramco, Sinopec and YASREF signed a framework to build a 1.8-million-tonne/year mixed-feed steam cracker and 1.5-million-tonne/year aromatics complex at Yanbu Industrial City, creating a world-class petrochemical cluster. The Yanbu refinery processes 430,000 b/d of Saudi heavy crude, with Aramco holding 62.5% and Sinopec 37.5%." },
  4501: { descEn: "CATL's Karawang battery plant and full nickel-to-recycling chain in Indonesia, ~$6 billion.", detailEn: "CATL and Indonesian partners are building a battery plant in Karawang, West Java plus a full chain from nickel mining through materials, cells and recycling, with eventual investment near $6 billion. Phase 1 is 6.9 GWh built to lighthouse-factory standard; at capacity it would produce 142,000 tonnes of nickel and 30,000 tonnes of cathode a year and recycle ~20,000 tonnes of batteries, with Brunp's DRT process giving Indonesia its first recycling system (>95% metal recovery), later extending to storage." },
  2092: { descEn: "The Philippines' largest undeveloped copper-gold mine.", detailEn: "In southern Mindanao ~40 km from General Santos, Tampakan is one of the world's largest undeveloped copper-gold deposits, planned for ~375,000 tonnes of copper and 360,000 ounces of gold a year over a 17-year life. First production slipped from 2026 to 2028; it is seeking a strategic partner with advanced technology, with Chinalco set to take a ~$2 billion stake in parent Indophil." },
  1187: { descEn: "China's largest offshore gas field; phase 2 fully online June 2025.", detailEn: "In the Qiongdongnan Basin of the South China Sea ~150 km off Hainan in ~1,500 m of water, Deep Sea No.1 is China's first deep-water high-pressure gas field. Phase 2 added 12 subsea wells with a new manifold platform and subsea production system, fully online on 25 June 2025, lifting capacity above 4.5 bcm a year to become China's largest offshore gas field, supplying the Greater Bay Area and Hainan." },
  1805: { descEn: "South America's largest auto investment; Leapmotor production at Goiana.", detailEn: "Stellantis announced ~30-32 billion reais of South American investment over 2025-2030 (~30 billion in Brazil), its largest ever. From 2026 it SKD-assembles China's Leapmotor B10 and C10 EVs at Goiana, Pernambuco, launches its first electrified model at Betim the same year and adds six Bio-Hybrid ethanol models, deepening localisation." },
  2987: { descEn: "BlueOval City battery plant, run by SK On, in production 2028.", detailEn: "Ford's BlueOval City near Stanton, Tennessee is ~$5.6 billion overall (vehicles, supplier park and battery plant). In December 2025 Ford and SK On signed a deal: Ford buys two Kentucky battery plants and SK On runs the 45 GWh Tennessee plant, with mass production in 2028." },
  1117: { descEn: "A coastal high-speed artery across Hangzhou Bay.", detailEn: "The Tong-Su-Jia-Yong high-speed railway, part of the national coastal corridor, runs ~309.8 km at 350 km/h, with a Hangzhou Bay sea-crossing rail bridge as its key structure. In 2025 the bridge entered over-water construction, with the 200 m main tower of the north navigation bridge advancing; due by end-2027, it directly links Nantong-Suzhou-Jiaxing-Ningbo, reshaping Yangtze Delta travel." },
  103: { descEn: "China's first UHVDC corridor powered mainly by a desert wind-solar base.", detailEn: "Supporting the Longdong-Shandong ±800 kV UHVDC line, this builds ~16 GW of wind and solar in the Qingyang area of Gansu — the first UHV corridor in China powered mainly by a desert mega-base — with construction from 2024 and source-grid coordinated start-up." },
  131: { descEn: "China's earliest 10-GW-class wind base.", detailEn: "Jiuquan (Guazhou, Yumen) in Gansu is China's earliest large-scale wind base, with over 10 GW of wind plus growing solar and CSP, exporting via several UHV lines as a hub of west-to-east clean power." },
  142: { descEn: "Germany's largest offshore wind cluster under construction in the North Sea.", detailEn: "Comprising Nordlicht I (980 MW) and II (630 MW) ~85 km north of Borkum, Vattenfall took FID on phase I in March 2025 and confirmed FID for the whole cluster after full permits in January 2026, with both phases fully online in 2028 — Vattenfall's largest single German investment." },
  245: { descEn: "LG Energy Solution's largest wholly-owned US battery base.", detailEn: "At Queen Creek, Arizona, two plants make 27 GWh of cylindrical cells and 16 GWh of LFP storage cells; the cylindrical plant was completed in late 2025 and the LFP plant comes online in 2026." },
  270: { descEn: "One of the world's densest concentrations of hyperscale data centres.", detailEn: "Gui'an New Area hosts 27 large data centres from Huawei, Tencent, Apple and the three telecoms operators, with over 160 EFLOPS of compute (>98% AI), where Huawei Cloud is building the world's largest AI-compute centre — a core 'east-data-west-compute' site." },
  544: { descEn: "A core node of the Yangtze Delta Wuhu 'east-data-west-compute' hub.", detailEn: "Huawei Cloud's East China (Wuhu) data centre spans three districts over ~6,000 mu, planned for 3 million servers and opened in June 2024, with liquid cooling giving a ~1.1 annual PUE and 10-millisecond dedicated links across six East China provinces and Shanghai." },
  593: { descEn: "Microsoft and G42 add 200 MW via Khazna in the UAE, with a GB300 export licence.", detailEn: "In November 2025 Microsoft and G42 announced 200 MW of new UAE capacity via Khazna, winning a US export licence to deploy Nvidia GB300 equivalent to 60,000 A100s, online by end-2026 — central to Microsoft's $7.9 billion 2026-2029 UAE plan." },
  599: { descEn: "AWS's Asia Pacific (Thailand) cloud region, live January 2025.", detailEn: "AWS launched its Asia Pacific (Thailand) region with three availability zones covering Bangkok on 8 January 2025, pledging over $5 billion of investment over 2025-2037, expected to add $10 billion to Thai GDP and support 11,000 jobs a year." },
  640: { descEn: "BHP and Lundin merged two giant Argentine copper deposits in 2025.", detailEn: "In San Juan, Argentina, the world-class Filo del Sol and Josemaria copper deposits hold over 31.7 million tonnes of combined copper. BHP and Lundin merged them 50/50 in January 2025 and issued a pre-feasibility study in February, planning ~395,000 tonnes of copper-in-concentrate a year over the first 25 years, targeting a start around 2030 — one of Argentina's largest-ever mining investments." },
  1026: { descEn: "Europe's largest self-funded semiconductor investment.", detailEn: "Infineon is self-funding €5 billion in a Smart Power Fab in Dresden — its largest single investment — making power and analog/mixed-signal 12-inch wafers for EVs, renewables and data-centre power. Started in 2023, the cleanroom shell topped out in April 2025 and it won ~€1 billion of final EU Chips Act subsidy in May, targeting 2026 production." },
  1553: { descEn: "The world's largest palladium producer's nickel-palladium capacity and SO2 cleanup.", detailEn: "Nornickel's nickel-palladium-copper smelting base in Taymyr, Siberia committed $5.5 billion of environmental investment in 2020 ($3.6 billion for sulphur-dioxide capture), targeting a 90% SO2 cut by 2025. Its 2025 budget is ~210 billion roubles, with nickel capacity 204,000-211,000 tonnes and palladium 2.62-2.73 million ounces." },
  2706: { descEn: "Ireland's largest offshore wind farm, off Dublin.", detailEn: "Off Ireland's east coast near Dublin, the ~1.3 GW Dublin Array is Ireland's largest offshore wind project, a JV of EDF and Fred Olsen. As the core of Ireland's first ORESS offshore auction, it advanced planning consent and grid connection in 2025, targeting 2030." },
  3004: { descEn: "A 300 MW HPC campus at Barber Lake, West Texas.", detailEn: "On a 587-acre site near Colorado City, Texas, Cipher signed a $5.5 billion, 15-year, 300 MW turnkey compute lease with AWS supplying from July 2026, plus a 10-year full lease with Fluidstack (with a $333 million Google debt backstop)." },
  3023: { descEn: "A 14-mile light rail linking Brooklyn and Queens along existing freight lines.", detailEn: "Using the LIRR Bay Ridge and CSX Fremont branches, the ~14-mile Interborough Express links Bay Ridge in Brooklyn with Jackson Heights in Queens, estimated at ~$5.5 billion (half secured). In July 2025 Jacobs and HDR took the ~$166 million design contract." },
  3239: { descEn: "Delhi Metro phase 4 extensions, ~112 km.", detailEn: "Phase 4 covers the Inderlok-Indraprastha, Lajpat Nagar-Saket and Rithala-Narela-Kundli corridors among others, ~450 billion rupees network-wide. Priority sections target March 2026 and all works 2028, with the Janakpuri West-Krishna Park section already opened in January 2025." },
  320: { descEn: "Africa's longest high-speed railway under construction.", detailEn: "Extending from Kenitra to Casablanca and south to Marrakech, 430 km at 320 km/h, this is the large extension of Africa's first high-speed line, Al-Boraq. Started in April 2025 with 18 Alstom high-speed trains ordered, it targets 2029." },
  1201: { descEn: "A 1.5-million-tonne ethylene expansion at Zhenhai, completed 2025.", detailEn: "At Zhenhai in Ningbo, Zhejiang, this ~38.08 billion-yuan Sinopec chain-strengthening project adds 1.5 million tonnes/year of ethylene and 18 process units (POE, LDPE/EVA, adiponitrile and other new materials). Due in 2025, it gives Zhenhai 38 million tonnes of refining and 3.7 million tonnes/year of ethylene, feeding Yangtze Delta EV, solar and high-end-equipment chains." },
  3256: { descEn: "A deep-water container transhipment port at Galathea Bay, Great Nicobar.", detailEn: "Part of the Great Nicobar integrated development, the ICTP at Galathea Bay was designated India's 13th major port in September 2024, built in four phases — phase 1 (~2028) at ~4 million TEU rising to 16 million by 2058 — at ~440 billion rupees, with the DPR complete." },
  243: { descEn: "VW PowerCo's largest North American battery plant.", detailEn: "At St. Thomas, Ontario, PowerCo is investing up to €4.8 billion for 90 GWh a year at capacity; main construction reached October 2025, with production expected in 2027 — Canada's largest new-energy manufacturing project." },
  2311: { descEn: "Senegal's first offshore oilfield, 100,000 b/d.", detailEn: "Sangomar is Senegal's first offshore oilfield, led by Australia's Woodside at $5.2 billion, with first export in July 2024 at 100,000 b/d. 2025 output is expected at 34.5 million barrels, above initial estimates — a pillar of Senegal's oil sovereignty." },
  596: { descEn: "Korea's largest AI data centre, a 15-year SK-AWS partnership.", detailEn: "SK Group and AWS signed a 15-year deal to build Korea's largest AI data centre at the Ulsan national industrial park, ~7 trillion won, with a 41 MW first phase by 2027 expanding to 103 MW by 2029 and 1 GW long term, deploying 60,000+ GPUs, with groundbreaking in August 2025." },
  1210: { descEn: "A leading coal-to-liquids upgrade demonstration, advancing in 2025.", detailEn: "In the Shengyuan industrial park of Ejin Horo Banner, Ordos, Inner Mongolia, next to the world's first million-tonne direct coal-liquefaction unit, China Energy is building a ~36.5 billion-yuan, 3-million-tonne/year coal-to-liquids project (2.2 million tonnes direct, 800,000 indirect plus gasification, 18 units) making military/vehicle diesel, jet fuel, naphtha and asphalt — a 2025 priority for Ordos, supporting energy security and clean coal conversion." },
  1536: { descEn: "An expansion of the world's second-largest gas field, supporting exports to China.", detailEn: "Turkmengaz and CNPC signed for Galkynysh phase 4, with CNPC building a 10-bcm/year sales-gas facility at ~$5.1 billion for domestic use and exports to China. The field plans seven phases totalling ~200 bcm/year — the world's second-largest — with ~90% of Turkmen gas exported to China via the Central Asia-China pipeline." },
  3123: { descEn: "A 4,500 MW mega gravity dam on the Indus in Gilgit-Baltistan.", detailEn: "A concrete gravity dam across the Indus between Kohistan in KP and Diamer in Gilgit-Baltistan, developed by WAPDA with two underground powerhouses of six units each totalling 4,500 MW, at ~1.4 trillion rupees, targeting 2028." },
  3567: { descEn: "A sea bridge from Xiamen Xiang'an toward Kinmen; main line by end-2026.", detailEn: "The 17.34 km main line (14.2 km over water), eight lanes at 100 km/h, plus a 2.275 km Xiang'an spur, at ~36 billion yuan. By early 2026 over 13 billion yuan (~36%) was invested and works were 37% done, with the island-ring tunnel right bore through, aiming to open the offshore main bridge by end-2026 and the full line by December 2027." },
  1989: { descEn: "A 1,400 MW pumped-hydro station in Laguna, among Asia's largest.", detailEn: "The Pakil pumped-hydro station in Laguna, developed by Prime Infra's Ahunan Power, is 1,400 MW with 14,000 MWh of daily storage at ~$5.03 billion (296 billion pesos). A notice to proceed launched access-road and upper-reservoir works, with First Gen set to buy 40% in 2026, targeting 2030 — one of Asia's largest pumped-hydro plants." },
  124: { descEn: "China's earliest 10-GW-class solar park.", detailEn: "Built on the Longyangxia hydro-solar complementary scheme for steady output and famed for its 'solar sheep' grazing land restoration, this continually expanding park is a key part of China's second batch of desert mega-bases." },
  145: { descEn: "New York's largest offshore wind project under construction.", detailEn: "Off New York at 810 MW, wholly owned by Equinor, Empire Wind closed $3 billion of financing in late 2024. Halted then resumed by federal order in 2025 and with its lease suspended again at year-end, Equinor filed a legal challenge in early 2026; it remains under construction, aiming to power over 500,000 homes." },
  275: { descEn: "A flagship net-zero AI data centre in NEOM.", detailEn: "DataVolt and NEOM signed a $5 billion deal in February 2025 to develop a 1.5 GW AI data centre in the Red Sea Oxagon industrial zone, 100% renewable-powered with LG advanced cooling for net-zero emissions, with a 300 MW first phase expected in 2028." },
  783: { descEn: "Poland's first offshore wind farm, due online 2026.", detailEn: "On ~130 km² of Polish Baltic near-shore waters, this JV of Poland's ORLEN and Canada's Northland Power uses 76 Vestas 15 MW turbines; turbine and substation installation began in 2025 for full operation in 2026, powering 1.5 million Polish homes." },
  820: { descEn: "Africa's largest hydro plant, formally inaugurated September 2025.", detailEn: "On the Blue Nile in Ethiopia, the Grand Ethiopian Renaissance Dam totals 5.15 GW; started in 2011 and inaugurated in September 2025 after ~14 years, it is Africa's largest hydro plant, doubling Ethiopia's generation and enabling power exports, though Nile water-rights disputes with downstream Egypt and Sudan persist." },
  831: { descEn: "India's largest planned hydro plant.", detailEn: "In the Lower Dibang Valley of Arunachal Pradesh, this 2,880 MW project is India's largest single planned hydro plant; a diversion-tunnel breakthrough in 2025 marked a key milestone, with a 108-month schedule and 2032 completion to become India's largest hydro plant." },
  1013: { descEn: "A Hyundai-SK On battery plant, in production H2 2025.", detailEn: "At Cartersville in Bartow County, Georgia, Hyundai Motor Group and SK On (50/50, ~$5 billion) plan 35 GWh, enough for 300,000 Hyundai/Kia/Genesis EVs a year, beside the Hyundai Metaplant, adding ~3,500 jobs — a record-scale Georgia industrial power user, with cell mass production from H2 2025." },
  1177: { descEn: "A Train 7 expansion at Bonny Island LNG.", detailEn: "Nigeria LNG's Train 7 at Bonny Island lifts total capacity from 22 to 30 million tonnes/year, with EPC by Saipem, Chiyoda and Daewoo emphasising local content. It reached 80% in June 2025 and over 92% by 2026, entering system completion and pre-commissioning, with start-up expected in 2027." },
  1197: { descEn: "Uganda's first oil, with the East African Crude Oil Pipeline.", detailEn: "The Kingfisher field southeast of Lake Albert, operated by CNOOC at 40,000 b/d peak, sends crude via the 1,443 km East African Crude Oil Pipeline (EACOP) to Tanga port in Tanzania for export. By December 2025 EACOP was ~79% done, the Kingfisher central plant over 90% and all 19 initial wells drilled, targeting Uganda's first oil in H2 2026 — a landmark of the emerging East African oil corridor." },
  1387: { descEn: "An AWS-HUMAIN AI zone in Saudi Arabia.", detailEn: "AWS and HUMAIN announced over $5 billion for a Saudi AI zone, with AWS deploying up to 150,000 AI accelerators. Twin 100 MW campuses in Riyadh and Dammam broke ground in 2025, combining Nvidia GB300 and AWS Trainium chips, with first operation expected in Q2 2026." },
  1396: { descEn: "A scalable 22 MW campus at KIZAD, Abu Dhabi.", detailEn: "In January 2025 Gulf Data Hub signed with KKR to jointly invest over $5 billion expanding in the UAE and GCC. GDH has a 22 MW facility under construction at KIZAD in Abu Dhabi (four more planned there) and a fully pre-leased fifth Dubai facility due in Q1 2026, with ~90 MW under construction overall." },
  1405: { descEn: "Doha Metro phase 2: a new Blue Line plus Green and Gold extensions, to four lines and 300 km.", detailEn: "Phase 2 adds ~70 stations, centred on a semi-orbital Blue (City) Line linking Hamad Airport T2 with West Bay and other districts, plus extensions of the 2019-opened Green and Gold lines (the Green extension has ~10 km of tunnel and 10 km surface). The network reaches four lines and ~300 km, targeting around 2026." },
  1517: { descEn: "A railway from Central Asia through Afghanistan to the Indian Ocean.", detailEn: "Running ~573 km from the Uzbek border at Termez via Mazar-i-Sharif and Kabul to the Pakistani border, designed for 20 million tonnes/year. On 17 July 2025 the three countries' transport ministers signed a framework in Kabul; estimated at ~$5 billion (some figures $7 billion), it would cut Uzbekistan-Pakistan freight from 35 days to 3-5." },
  1521: { descEn: "A new southwest radial Moscow metro line, opening in sections.", detailEn: "The Troitskaya Line (Line 16) is a new Moscow metro radial built in sections toward Troitsk in New Moscow. The Tyutchevskaya-Novomoskovskaya section opened on 28 December 2024 and Novatorskaya-ZIL on 13 September 2025, with Sosenki, Vatutinki and Troitsk stations planned for 2029, serving the fast-growing southwest." },
  1535: { descEn: "A large gas-chemical complex making polymers via methanol-to-olefins.", detailEn: "MTO Central Asia is building a methanol-to-olefins complex in Karakul district, Bukhara region, converting domestic gas via methanol to ethylene and propylene and polymerising ~1.1 million tonnes/year of HDPE, LDPE, EVA, PET and polypropylene. It drew ~$5 billion of investment and technology from the US, Germany, Denmark, Austria, Italy and China, targeting full operation by end-2025." },
  1673: { descEn: "BYD's first European passenger-car plant, trial production early 2026.", detailEn: "At Szeged, Hungary, BYD's first self-built European passenger-car plant plans 200,000 vehicles a year, starting with the Dolphin Surf. A strategic pivot to local European production avoiding EU tariffs, the first lines arrived in December 2025, with trial production from late January 2026 and mass production in Q2 2026." },
  1718: { descEn: "A high-quality pre-salt discovery in the Santos Aram block.", detailEn: "The Aram block, won in the sixth production-sharing round in 2020, lies 248 km off Santos in 1,952 m of water. In May 2025 a discovery of clean, high-quality pre-salt crude was announced, with appraisal including two more wells; the ANP extended the exploration phase to June 2029, making it a key prospect for Petrobras's 2026-2030 plan and a likely base for a next-generation pre-salt FPSO." },
  1840: { descEn: "Upgrading the Yanbu Samref refinery into a crude-to-chemicals base.", detailEn: "On 8 December 2025 Aramco, ExxonMobil and Samref signed a venture framework to study upgrading the 400,000 b/d Samref refinery at Yanbu into an integrated petrochemical complex making high-value chemicals and low-emission distillates, advancing Aramco's liquids-to-chemicals strategy (4 million b/d by 2030). FEED has begun, with FID subject to market and approvals, targeting around 2030." },
  1885: { descEn: "An AI-ready data centre at First Tech Park, East Riyadh.", detailEn: "DataVolt agreed a lease with MODON for a 55,000 m² plot at First Tech Park in East Riyadh to build an advanced AI-processing, liquid-cooled data centre for hyperscale and cloud customers, part of DataVolt's $5 billion Saudi pipeline, targeting operation around 2027." },
  1969: { descEn: "A 2 GW floating offshore wind project in the Philippines.", detailEn: "Off North Ilocos in the Philippines, this floating offshore wind project — a JV of PetroGreen Energy and Denmark's Copenhagen Energy (BuhaWind Energy) — is 2 GW, targeting full operation before 2030. It won a pre-development environmental certificate in June 2025 and grid approval in August, one of 16 green-lit Philippine offshore wind farms, kick-starting the country's deep-water floating wind." },
  1971: { descEn: "Singapore's first round-the-clock large-scale green-power import.", detailEn: "Sembcorp and Sarawak Energy won conditional Singapore EMA approval on 17 October 2025 to import ~1 GW of mostly-hydro green power from Sarawak via a ~700 km subsea cable, with a priority supply deal signed with Prysmian and a landing point from Tondong to Changi. Power flows from 2031 and scales by 2035, serving Singapore's 6 GW low-carbon import target." },
  2005: { descEn: "A 22/28nm advanced fab in Singapore, mass production 2026.", detailEn: "UMC announced ~$5 billion in 2022 for a new 300mm fab (Fab12i P3) beside its existing Fab12i in Singapore; an opening ceremony was held in April 2025, with phase-1 30,000 wafers/month of 22/28nm and mass production deferred to 2026, lifting UMC's Singapore capacity above a million wafers a year and adding ~700 engineering jobs." },
  2052: { descEn: "A super transhipment hub port planned at Can Gio, Ho Chi Minh City.", detailEn: "Covering ~571 hectares with a ~7.5 km main quay, this port is ~128.9 trillion dong (~$5 billion), a JV of Vietnam's VIMC (36%), Saigon Port (15%) and MSC's TiL (49%), able to berth 250,000-tonne (24,000 TEU) ships, designed for 4.8 million TEU in 2030 rising to 16.9 million by 2047. It won the PM's investment-policy approval in January 2025 with a 10-year equity lock-in." },
  2275: { descEn: "Southern Tunisian solar sent to Italy's Lazio via a 2,000 MW cable.", detailEn: "TuNur, a UK-French-Maltese-Tunisian JV, builds large solar in Kebili in southern Tunisia and an HVDC line to a substation in Lazio, Italy, transmitting 2,000 MW to power ~2 million European homes — a flagship for exporting Saharan solar to Europe." },
  2300: { descEn: "Dangote's planned largest deep-water port in Africa.", detailEn: "In mid-2025 Dangote applied to build a 10,000+ hectare seaport-industrial complex at Olokola on the Ondo-Ogun border, ~100 km from the Lekki refinery, to handle future LNG exports and heavy-equipment imports — which the group says would become Africa's largest and deepest seaport." },
  2558: { descEn: "Eni's Marine XII gas liquefaction and power supply in Congo.", detailEn: "Eni Congo develops the Marine XII gas; phase 2 adds three production platforms, a Scarabeo 5 processing-compression unit and the Nguya FLNG, lifting Congo LNG to 3 million tonnes/year. Phase 2 started early in December 2025, supplying Congo's power plant (70% of national generation) and upgrading the Pointe-Noire-Brazzaville high-voltage line." },
  2604: { descEn: "A 3 GW electrolyser green-ammonia project at Gove, with 4.75 GW solar-storage.", detailEn: "On the Gove Peninsula in the Northern Territory, this plans 3 GW of electrolysers for ~958,500 tonnes of green ammonia a year, with 4.75 GW of solar and 1.6 GWh of daily battery storage. It signed an engineering deal with ABB in 2025 to accelerate FID, mainly for ammonia export to Asia — one of northern Australia's largest green-hydrogen plans." },
  2660: { descEn: "PNG's next LNG expansion after Papua LNG.", detailEn: "At the P'nyang field in PNG's Western Province, led by ExxonMobil, this would add a liquefaction train to the PNG LNG plant; originally parallel with Papua LNG, it was sequenced after it by the PNG government, advancing commercial talks and the development concept in 2025." },
  2704: { descEn: "A 2 GW mega offshore wind farm in the Dutch North Sea.", detailEn: "At the IJmuiden Ver Alpha site ~60 km off the Netherlands, this 2 GW farm was awarded in June 2024 with FID advancing in late 2025, with green-hydrogen coupling and Delta Rhine corridor export — one of the flagships of the Dutch energy transition." },
  2741: { descEn: "AWS's €7.8 billion independent European Sovereign Cloud in Germany.", detailEn: "AWS is investing ~€7.8 billion to build the 'European Sovereign Cloud' in Brandenburg, Germany, with data and operations entirely in the EU run by EU staff to meet government and regulated-industry data-sovereignty needs; the first region is being built from 2025 toward operation around 2027." },
  2745: { descEn: "A high-speed and freight corridor linking Genoa port with Milan.", detailEn: "Italy's 'Terzo Valico dei Giovi' high-speed line links the port of Genoa with the Milan/Turin plain, with the ~27 km Giovi tunnel — a passenger-and-freight corridor connecting the Mediterranean at Genoa with Europe's Rhine-Alpine corridor, at ~€6.8 billion. Tunnelling advanced in 2025, targeting 2027." },
  2912: { descEn: "A planned world-largest green-hydrogen hub in South Texas making 1 million tonnes of green ammonia for export.", detailEn: "GHI plans Hydrogen City in South Texas, ultimately 60 GW producing over 2.5 billion kg of green hydrogen a year with salt-cavern storage. Phase 1's 280,000 tonnes/year of green hydrogen is piped to Corpus Christi and Brownsville to make 1 million tonnes/year of green ammonia for export, partnered with Japan's INPEX, targeting 2026 construction and 2029 commercial operation." },
  2929: { descEn: "Amazon-funded deployment of up to 12 Xe-100 reactors at Hanford, Washington.", detailEn: "On the DOE Hanford reservation next to Energy Northwest's Columbia plant, this builds reactors in ~320 MW segments — funded by Amazon, with X-energy supplying the reactors and Energy Northwest operating. In October 2025 phase 1 was expanded from 4 to 12 units, targeting the mid-2030s." },
  2939: { descEn: "SaskPower selects Estevan for Saskatchewan's first BWRX-300 SMR.", detailEn: "SaskPower chose the GE-Hitachi BWRX-300, securing two ~320-acre sites by reservoirs near Estevan (up to two units each). A final site is expected in 2026 and FID in 2029, with the first ~315 MWe unit targeted for 2034." },
  2953: { descEn: "New 500 kV lines for 7,500 MW of new data-centre load.", detailEn: "NextEra's MARL and Gore-Doubs-Goose Creek upgrades are part of PJM's B3800 series, approved in late 2023. Dominion is building 500 kV lines along existing corridors in Virginia to serve up to 7,500 MW of new Virginia and Maryland data-centre load." },
  3000: { descEn: "A Stargate data centre and AI-server factory in Lordstown, Ohio.", detailEn: "One of Stargate's five new sites, SoftBank has broken ground using a rapidly replicable advanced design; a SoftBank-Foxconn JV doubles it as an AI-server and data-centre-equipment factory, reaching 1.5 GW within 18 months together with the Milam County site." },
  3011: { descEn: "AWS's Mexico (Central) cloud region, in Querétaro.", detailEn: "AWS launched its Mexico (Central) region with local availability zones in January 2025, planning over $5 billion of investment over 15 years. Querétaro concentrates ~65% of Mexico's data-centre capacity under construction, with AWS, Azure and Google Cloud all present." },
});

/* ===== 批次8：全库投资额 TOP（约 42–50 亿美元）===== */
Object.assign(window.ENERGY_EN, {
  3015: { descEn: "A freight expansion of the 1,525 km Yucatán passenger loop, possibly extending to Belize/Guatemala.", detailEn: "On the existing 1,525 km Maya Train passenger loop, freight is being added with four hubs and in-station tracks at Palenque, Poxila, Progreso and Cancún. Freight was ~47.5% done by May 2026, with start-up expected by end-2026; the president has also proposed a ~300 km extension toward Belize and Guatemala." },
  3115: { descEn: "A million-tonne green-ammonia plant in Kota, Rajasthan, ~$5 billion.", detailEn: "Avaada and the Rajasthan government are building a ~$5 billion, million-tonne/year renewable-ammonia plant in Kota. Avaada also won 50 MW/year of electrolyser capacity under the NGHM and 240 MW in SECI's eighth tranche — a leading Indian green hydrogen-ammonia developer." },
  3134: { descEn: "India's first nuclear plant built by the NPCIL-NTPC joint venture.", detailEn: "At Napla in Banswara, Rajasthan, four indigenous 700 MW PHWRs (2.8 GW total) are being built at ~420 billion rupees by ASHVINI, a JV of NPCIL (51%) and NTPC (49%). PM Modi laid the foundation in September 2025 with excavation approved and first concrete in March 2026." },
  3216: { descEn: "OpenAI's first large AI-compute anchor in India via Stargate, with Tata deploying AMD GPUs.", detailEn: "At the February 2026 India AI Impact Summit in New Delhi, OpenAI became the first customer of TCS's HyperVault data centre, a 100 MW first phase expandable to 1 GW. TCS, with a $1 billion TPG injection, plans sites in Navi Mumbai, Hyderabad and Chennai, with $6-7 billion of platform investment over 5-7 years deploying AMD accelerators." },
  3286: { descEn: "Reliance and bp developing three deep-water gas fields in the KG-D6 block.", detailEn: "Reliance (66.67%) and bp (33.33%) have invested ~$5 billion in the R-Cluster, Satellite cluster and MJ deep-water fields off India's east coast in the KG-D6 block, peaking at ~30 million m³/day. The MJ high-pressure/high-temperature gas-condensate field has an onshore terminal at Gadimoga, with added investment approved in 2024-25." },
  3601: { descEn: "China's largest ultra-deep condensate gas field; output topped 10 bcm in 2025.", detailEn: "On the northern Tarim Basin at the Wensu-Baicheng border in Xinjiang, this is a trillion-cubic-metre-class ultra-deep gas region after Kela-Keshen, with ultra-deep, ultra-high-pressure/temperature, low-porosity, low-permeability characteristics. The 15th Five-Year period launches a 10-bcm capacity build with 85 new wells and processing and export facilities; output topped 10 bcm in December 2025, with processing capacity rising from 5 to 12 bcm/year." },
  4207: { descEn: "A Tsingshan-led integrated nickel park at Weda Bay, using laterite ore vertically.", detailEn: "On Halmahera in North Maluku, Indonesia, this JV of Tsingshan (40% via Perlus), Huayou Cobalt (30%) and Zhenshi (30%) is the world's first vertical laterite-ore-to-nickel-intermediates-to-stainless-and-battery-materials park. Weda Bay Nickel (Tsingshan 57%/Eramet) has ~3 million tonnes/year of RKEF nickel-iron and ~3,400 MW of captive power; phase 1 started in 2020." },
  4394: { descEn: "HQC's installation works for ADNOC's Ruwais LNG, its first overseas tie-up with JGC.", detailEn: "After ADNOC's June 2024 FID, a Technip Energies-JGC-NMDC Energy consortium won the EPC for two 4.8-million-tonne/year trains (9.6 million total) at Ruwais. In early 2025 the Huanqiu (HQC) system signed the installation contract, handling feed-gas compression, cryogenic liquefaction, utilities and flare systems — its first overseas tie-up with JGC, targeting 2028 to make the UAE a major LNG exporter." },
  755: { descEn: "The world's largest approved solar-plus-storage project.", detailEn: "On ~9,500 acres of retired farmland in Fresno County, California, Intersect Power's project won AB 205 fast-track approval in June 2025, with 1,150 MW of solar and 1,150 MW/4,600 MWh of storage — a world-record storage size — able to power 850,000 homes for four hours." },
  1034: { descEn: "A fully electrified fossil-free steel plant in northern Sweden, with twin arc furnaces.", detailEn: "SSAB is building a fully electrified integrated mill in the Svarton zone of Luleå with two scrap-charging arc furnaces, secondary metallurgy and direct strip rolling to replace its blast furnaces, making 2.5 million tonnes/year of fossil-free special steel. At ~€4.5 billion, it cuts 2.8 million tonnes of CO₂ a year (90%); ground was broken in September 2025 with permits confirmed in November, targeting 2029." },
  1240: { descEn: "Brazil's first long-distance flexible HVDC, carrying northeast wind-solar south.", detailEn: "Defined by EPE and ONS as a fast corridor, this runs ~2,500 km from Angicos in Rio Grande do Norte to Itaporanga 2 in Paraná using VSC HVDC — Brazil's first long-distance VSC project. At 26.5 billion reais (~17.1 billion for the DC system), it relieves the bottleneck on 60+ GW of northeast wind and solar." },
  3594: { descEn: "A 10-million-tonne-class LNG terminal in Yantai, PipeChina's first.", detailEn: "At Longkou port in Yantai, Shandong, this 20-million-tonne/year, 35-billion-yuan terminal builds six 220,000 m³ tanks and a 266,000 m³ berth in phase 1 (5 million tonnes/year) — PipeChina's first 10-million-tonne-class LNG terminal, the core of Yantai's drive to be northern China's largest LNG hub, extending into the 15th Five-Year period." },
  1454: { descEn: "Central Asia's largest wind farm, a $4.85 billion PPA.", detailEn: "ACWA Power signed a $4.85 billion PPA with Uzbekistan's grid to build 5 GW of wind in Gungrad, Karakalpakstan in five phases for ~18.5 TWh a year — set to be Central Asia's largest onshore wind farm, transferred to the government after a 25-year concession, in development in 2025." },
  184: { descEn: "The world's first cross-region UHVDC with flexible HVDC at both ends.", detailEn: "From Minqin in Wuwei, Gansu to Shangyu in Shaoxing, Zhejiang through six provinces, with a 2,370 km DC line; tower assembly on the first lot began in January 2026, targeting July 2027, helping integrate over 21.2 TWh of northwest renewables a year." },
  781: { descEn: "RWE's 1.4 GW flagship on Dogger Bank in the North Sea.", detailEn: "On Dogger Bank 195 km off northeast England, RWE's wholly-owned Sofia uses 100 Siemens Gamesa 14 MW turbines on 252 m towers; by end-2025 all foundations and over half the turbines were done, with completion and commissioning in 2026 to power 1.2 million homes." },
  1231: { descEn: "A 2.4 GW electrolyser green-ammonia project at Pecém, online 2030.", detailEn: "On 60 hectares at Pecém port in Ceará, this has up to 2.4 GW of electrolysers producing 960 tonnes of hydrogen a day for 2.2 million tonnes of green ammonia a year. The plant is ~12 billion reais with ~13 billion reais of supporting generation; TotalEnergies is a partner, aiming to export to European refineries." },
  1304: { descEn: "A pre-salt gas-processing and lubricants hub at Itaboraí, the reborn Comperj.", detailEn: "On the former Comperj site, fed pre-salt gas via the Rota 3 line, the first gas-processing module started in 2024 and a second reached commercial operation in May 2025 (21 million m³/day). A ~13 billion-reais phase 2 builds South America's first Group II lube base oils (12,000 b/d) plus diesel and jet fuel and a 19,000 b/d HVO/SAF facility, with full output in 2028." },
  1683: { descEn: "Indonesia's integrated upstream: nickel smelting, cathode materials and battery recycling.", detailEn: "As the upstream and materials end of CATL's full-chain Indonesia battery project, this is at the FHT park in East Halmahera, North Maluku, planned for 142,000 tonnes of nickel and 30,000 tonnes of cathode a year and 20,000 tonnes of battery recycling (>95% recovery), forming a closed mining-materials-manufacturing-recycling loop with the Karawang plant toward Indonesia's 2060 carbon neutrality." },
  2310: { descEn: "A Senegal-Mauritania cross-border offshore LNG project; first export in 2025.", detailEn: "The Greater Tortue Ahmeyim (GTA) project on the Senegal-Mauritania maritime border, led by bp and Kosmos, has a ~2.5-million-tonne/year phase 1. It made its first LNG export in 2025 with strong output, with further phases to expand it — a flagship West African gas project." },
  2351: { descEn: "A deepwater floating LNG project shared by Mauritania and Senegal, online 2025.", detailEn: "Led by bp with Kosmos Energy across the Mauritania-Senegal maritime border, GTA saw first gas to the FPSO in late 2024, first LNG in February 2025 and first export in April, reaching ~2.3 MTPA (2.7 nameplate) at full capacity in December 2025. Phase 2 would add 2.5-3 MTPA via a gravity-based subsea structure for over 5 MTPA total." },
  2718: { descEn: "Poland's first large offshore wind farm in the Baltic, 1.2 GW.", detailEn: "In the Polish Baltic, this JV of Poland's ORLEN and Canada's Northland Power is 1.2 GW with 76 15 MW turbines — Poland's first completed large offshore wind farm, at ~€4.5 billion. Offshore works advanced in 2025, targeting 2026 to launch Poland's offshore wind era." },
  3010: { descEn: "Mexico's largest hyperscale campus, six buildings and 900 MW at Querétaro.", detailEn: "CloudHQ is investing ~$4.8 billion at Galeras in Querétaro for six data centres on 52 hectares, up to 900 MW of critical IT load (a 200 MW first phase secured), due in 2027 — billed as Mexico's largest hyperscale hub." },
  3142: { descEn: "Pakistan's largest single nuclear unit, China's Hualong One.", detailEn: "At Chashma in Mianwali, Punjab, Pakistan, this uses China's Gen-III Hualong One (HPR1000) at 1,200 MW — Pakistan's largest single nuclear unit. China and Pakistan signed a $4.8 billion deal, with first concrete on 30 December 2024; it is the third Hualong One in Pakistan, helping move its nuclear capacity toward 8,800 MW." },
  1208: { descEn: "A Zhundong 2025 priority: an 800,000-tonne coal-to-olefins plant.", detailEn: "In the Wucaiwan Huoshaoshan park of Zhundong, Xinjiang, Shandong Energy's Yankuang Xinjiang Energy & Chemical is building a 33.8-billion-yuan project with 800,000 tonnes/year of coal-to-olefins, a 23-million-tonne/year open-pit mine phase 1 and a rail spur, using home-grown 3,000-t/d OMB gasification and MTO. Started on 23 February 2025 over ~2.5 years, it would yield ~4.7 billion yuan a year in profit and tax — a landmark of Xinjiang's coal-chemical scaling." },
  1513: { descEn: "A landmark cross-border railway linking China and Central Asia.", detailEn: "A groundbreaking was held in Kyrgyzstan on 27 December 2024 with formal works from July 2025. About 486 km (311 km in Kyrgyzstan, 69 km in Uzbekistan) at 120 km/h with 50 bridges and 29 tunnels (three over 12 km), built over six years toward around 2030 — China's shortest overland route to Central Asia." },
  3568: { descEn: "A greenfield 4F hub airport able to handle the world's largest airliners, opening end-2026.", detailEn: "Designed for 45 million passengers, 750,000 tonnes of cargo and 380,000 movements a year, with a 3,800 m 4F North-1 runway and a 118,000 m² metal-roof terminal at ~33.5 billion yuan; substantially complete by end-2025, calibration flights in March 2026 and opening by end-2026." },
  1623: { descEn: "CPECC's $4.6 billion turnkey EPC megadeal in Central Asia.", detailEn: "CNPC subsidiary CPECC signed a $4.614 billion (~31.6 billion yuan) turnkey EPC for Galkynysh phase-4 sales-gas capacity in Turkmenistan, adding 10 bcm/year for owner Turkmengaz. Tied directly to Central Asia-China lines A/B/C and supporting Line D, it lifts overall capacity from 40 to 65 bcm/year — strategic for China's Central Asian gas supply." },
  109: { descEn: "The largest hydro plant on the upper Jinsha River.", detailEn: "On the upper Jinsha at the Sichuan-Tibet border, Yebatan has a 217 m dam and 2.24 GW; started in 2017, it pushed toward first-unit start-up in 2025, completing the upper Jinsha cascade." },
  283: { descEn: "Australia's (and the Southern Hemisphere's) largest data-centre project.", detailEn: "NextDC and OpenAI unveiled the S7 campus at Eastern Creek in Western Sydney in December 2025, targeting 650 MW Tier IV at ~$4.6 billion, helping make Australia the world's second-largest AI-infrastructure destination." },
  943: { descEn: "The world's first commercial ±525 kV XLPE HVDC cable project.", detailEn: "SuedOstLink runs 540 km from Wolmirstedt to the Isar substation near Munich — the world's first large commercial 525 kV XLPE HVDC project. Prysmian won a ~€4.6 billion contract, with cable installation from 2024 and operation expected in 2027/28." },
  1285: { descEn: "An Amazon grain railway from Sinop to Miritituba.", detailEn: "Linking Sinop in Mato Grosso with the Miritituba terminal in Pará, ~933 km, Ferrogrão relieves soy haulage on the BR-163 highway, with 65 bridges and claimed savings of 8 billion reais a year. The transport ministry approved updated technical studies, sent to the Federal Court of Accounts." },
  1807: { descEn: "The world's largest single-line pulp mill, at Inocência.", detailEn: "Chile's Arauco's first Brazilian pulp venture, at Inocência in Mato Grosso do Sul, is the world's largest single-phase bleached-pulp mill at $4.6 billion and 3.5 million tonnes a year, with 400 MW of captive power (~220 MW exportable). Started in 2025, it targets late 2027." },
  1821: { descEn: "A State Grid-controlled CPFL five-year distribution expansion.", detailEn: "State Grid-controlled CPFL is investing ~24.7 billion reais in distribution in its 2025-2029 capex plan, covering 7.8 million customers in São Paulo and Rio Grande do Sul to expand, modernise and strengthen the network — one of the largest Chinese grid investments in Brazil." },
  3504: { descEn: "A 33-billion-yuan 12-inch IC line in Yizhuang, Beijing, 50,000 wafers/month.", detailEn: "GigaDevice's Yandong Micro, with BOE and Yizhuang state capital, raised capital for BD United Integrated at 33 billion yuan and 50,000 wafers/month. Tool move-in starts in Q4 2025 with mass production by end-2026 and full output by 2030, focused on power devices, display drivers and power-management chips." },
  241: { descEn: "A CATL-Stellantis 50/50 LFP plant in Zaragoza.", detailEn: "Beside the Stellantis vehicle plant in Zaragoza, Spain, this €4.1 billion plant makes 50 GWh/year of LFP batteries; started in November 2025 and targeting end-2026 production, with over €300 million of EU support." },
  386: { descEn: "One of Indonesia's largest nickel HPAL projects.", detailEn: "At Pomalaa in Sulawesi, this JV of PT Vale, Huayou Cobalt and Ford (~$4.5 billion) processes 28 million tonnes/year of limonite via high-pressure acid leaching to MHP, yielding 120,000 tonnes of nickel and 15,000 tonnes of cobalt a year, targeting Q3 2026." },
  1155: { descEn: "Mumbai's first fully underground metro, north-south.", detailEn: "The Aqua Line is Mumbai's first fully underground metro, 33.5 km with 27 stations from Cuffe Parade in the south to Aarey JVLR in the north, connecting the international airport and business districts. Opened in three stages — BKC-Aarey in October 2024, BKC-Acharya Atre Chowk in May 2025 and the final ~11 km to Cuffe Parade in October 2025 — it greatly eases east-west and north-south traffic." },
  1215: { descEn: "One of India's largest refinery expansions.", detailEn: "At Panipat in Haryana, IOC is raising refining from 15 to 25 million tonnes/year with downstream polypropylene and butadiene rubber. By 2025 it was ~84% complete, starting up in phases over FY2025-26 — central to IOC's strategy to triple petrochemical capacity by 2030." },
  1596: { descEn: "A 2,172 MW hydro plant on the Kwanza, Angola's largest power project.", detailEn: "EPC by China Energy's Gezhouba, on the middle Kwanza near Dondo in Cuanza Norte, Angola, with a 103 m concrete dam and four 530 MW units (plus an ecological station) totalling 2,172 MW. Excavation began in August 2023, with the first unit's pit done by March 2025 (243,000 m³ excavated) — a strategic project for Angola." },
  1808: { descEn: "A large new pulp mill at Bataguassu, Mato Grosso do Sul.", detailEn: "Singapore's RGE group's Bracell announced ~$4.5 billion for a new pulp mill at Bataguassu in Mato Grosso do Sul, ~2.8 million tonnes a year. Relocated from Água Clara for logistics and strategy, it is in feasibility and early stages — another pulp hub for the state." },
  1899: { descEn: "A second Saudi-Bahrain road-and-rail causeway, parallel to the King Fahd Causeway.", detailEn: "Linking the Dammam rail station with the King Hamad rail station at Ramli, Bahrain, ~25 km with road and twin GCC-rail tracks to relieve the King Fahd Causeway, at ~$4-5 billion on a 25-30-year PPP concession. The Dammam station becomes Saudi Arabia's main rail hub; feasibility is done, targeting 2026 construction and 2028 operation." },
  2064: { descEn: "A Central Java refinery upgrade for cleaner fuels.", detailEn: "Pertamina's RU IV Cilacap RDMP would raise capacity from 350,000 to 400,000 b/d, lifting gasoline 59→138 and diesel 82→137 thousand b/d. In 2026 Pertamina reaffirmed it and kept seeking a JV partner (having courted Saudi Aramco), part of the ~$6.2 billion three-refinery RDMP plan (Dumai/Plaju/Cilacap by 2027)." },
  2213: { descEn: "A passenger-and-freight high-speed line linking the Red Sea and Mediterranean.", detailEn: "Egypt signed a $4.5 billion contract with a Siemens-led consortium for the 660 km Green Line connecting the Red Sea and Mediterranean in as little as 3 hours. Part of Egypt's 2,000+ km three-line electrified network, track-laying began in 2025 toward 2026 completion, linking Upper Egypt, the Delta and new cities." },
  2515: { descEn: "Southern Africa's largest hydro plant in half a century.", detailEn: "A 1,500 MW run-of-river plant on the Zambezi in Mozambique, ~$4.5 billion, developed by France's EDF and TotalEnergies with EDM and HCB; the World Bank has pledged debt, equity and risk guarantees plus $1.4 billion of transmission support. A February 2026 technical workshop in Maputo advanced credit enhancement, targeting 2031." },
  2525: { descEn: "Angola's largest single power source.", detailEn: "The Caculo Cabaça hydro plant on the middle Kwanza in Cuanza Norte, Angola, 2,172 MW, will become Angola's largest single power source (above the downstream 2,070 MW Laúca). Built by China's Gezhouba (CGGC), its spillway tunnel was holed through in June 2025, clearing the way for unit installation and impoundment, targeting 2026 and ~8.57 TWh a year." },
  2744: { descEn: "A Y-shaped high-speed line linking Bilbao, San Sebastián and Vitoria.", detailEn: "The 'Basque Y' high-speed railway in northern Spain links Bilbao, San Sebastián and Vitoria and ties into the Spanish HSR network and France — a key segment of the Iberia-Europe Atlantic corridor. Multiple lots advanced in 2025, targeting around 2028." },
  2992: { descEn: "A low-carbon recycled-aluminium rolling mill at Bay Minette, online H2 2026.", detailEn: "Novelis is building a low-carbon recycled-aluminium rolling mill at Bay Minette, Alabama, recycling ~15 billion cans a year for packaging and automotive sheet. Originally for mid-2025, it now targets H2 2026 commissioning — one of North America's first new integrated aluminium rolling mills in decades." },
  3043: { descEn: "A blue-hydrogen and blue-ammonia complex at Darrow, Louisiana, revived via Yara.", detailEn: "Air Products plans a $4.5 billion blue-hydrogen complex at Darrow, Louisiana producing over 750 million cubic feet/day of blue hydrogen and capturing ~95% of CO₂. Paused in 2025, it regained momentum after deep talks with Yara on a 25-year blue-hydrogen offtake and the sale of ammonia-making assets, with start-up pushed to 2028." },
  3462: { descEn: "A Qinghai desert mega-base sending power to the Greater Bay Area; generation started November 2025.", detailEn: "Qinghai's Hainan clean-energy export base plans 19.44 GW (86.4% renewable: 9.6 GW solar, 6 GW wind, 2.64 GW coal and 1.2 GW/4h storage), sending power to Guangdong via one ±800 kV, 8 GW UHVDC line at ~36 TWh a year — the largest approved renewable desert-base in China." },
  3503: { descEn: "China's first volume 8-inch automotive silicon-carbide line, online 2025.", detailEn: "Sanan Optoelectronics and STMicroelectronics' ~$3.2 billion JV (Sanan-ST) in Chongqing built an 8-inch automotive SiC fab, reaching first line in February 2025 with volume production in Q4 toward ~10,000 wafers/week, plus a 7-billion-yuan Chongqing Sanan 8-inch substrate line already started." },
  871: { descEn: "Namibia's flagship green-hydrogen project, Africa's largest.", detailEn: "In the Tsau Khaeb National Park of southern Namibia, Hyphen (with ENERTRAG) and the government plan ~$9.4 billion total, with a 2 GW wind-solar phase 1 for ~800,000 tonnes of green ammonia a year. The AfDB provided $10 million for FEED in 2024, with FID targeted for 2026 and green ammonia for Europe and East Asia." },
  1012: { descEn: "A Honda-LG pouch-battery plant, in production 2025.", detailEn: "At Jeffersonville in Fayette County, Ohio (~40 miles southwest of Columbus), the Honda-LG Energy Solution JV is ~$4.4 billion for ~40 GWh of pouch cells for Honda's North American EV plants. Over 2 million sq ft, it is a core local grid load creating ~2,200 jobs, topping out and ramping production in 2025." },
  1056: { descEn: "BYD's first European passenger-car gigafactory.", detailEn: "At Szeged, Hungary, up to ~€4 billion, this is BYD's first European passenger-car plant. The first lines arrived in December 2025, with trial production from late January 2026 and mass production in Q2 2026, starting with the Dolphin Surf — initially 150,000 vehicles a year rising to 200,000, with ~960 staff, to localise production and avoid EU tariffs." },
  1681: { descEn: "A 50/50 CATL-Stellantis LFP plant, 50 GWh planned.", detailEn: "CATL and Stellantis (50/50) are building a large LFP plant at Figueruelas in Zaragoza, Spain, next to the Stellantis vehicle plant, at up to €4.1 billion and 50 GWh/year using renewable power, with over €300 million of EU support; ground was broken in late November 2025, targeting end-2026." },
  3027: { descEn: "A new double-deck companion bridge and 8-mile corridor on I-71/I-75 at Cincinnati.", detailEn: "A new double-deck companion bridge carries interstate traffic on I-71/I-75 between Ohio and Kentucky over ~8 miles, with the existing bridge handling local traffic. At ~$4.4 billion split between the states (with ~$1.6 billion federal), works began on 8 May 2026, with the companion bridge open in 2031 and full completion in 2033." },
  3270: { descEn: "Dhaka Metro Line 1 (Airport and Purple lines), JICA-financed, with an underground section.", detailEn: "MRT-1 is ~539.8 billion taka with ~394.5 billion of JICA aid, comprising the Airport and Purple lines — Dhaka's first underground metro. The depot was over 95% built by April-May 2025, targeting 2028." },
  3277: { descEn: "CPCL building a new 9-million-tonne greenfield refinery at Nagapattinam, Tamil Nadu.", detailEn: "CPCL is demolishing its old small refinery and building a new 9-million-tonne/year greenfield refinery at Nagapattinam via a JV at ~364 billion rupees, making LPG, BS-VI fuels and jet fuel with polypropylene; it has environmental clearance, owned 50/50 by IOCL and CPCL." },
  3566: { descEn: "Part of the Shanghai-Zhoushan-Ningbo sea crossing, linking Beilun and Zhoushan; fully started August 2025.", detailEn: "Built to six-lane expressway standard across the Huibie Yang waters at ~31.3 billion yuan, this is a key part of Zhejiang's Shanghai-Zhoushan-Ningbo and Yiwu-Ningbo-Zhoushan corridors. Fully started on 29 August 2025, it will strengthen Ningbo-Zhoushan port collection and distribution." },
  181: { descEn: "The world's highest-altitude UHVDC project.", detailEn: "From two converter stations in Chamdo (Tibet) and Garze (Sichuan) to Huangshi in Hubei, ~1,900 km, using the world's first high-altitude split-site cascade technology with a sending altitude of 3,720 m and line up to 4,800 m. It entered service on 18 December 2025, delivering ~40 TWh of clean power a year." },
  1149: { descEn: "The Americas' first metro built and run end-to-end by a Chinese firm; over 75% done.", detailEn: "Bogotá Metro Line 1 is Colombia's capital's first metro, 24 km elevated with 16 stations, invested, built and operated by a JV of China Harbour (CHEC) and Xi'an Rail Transit — the first metro in the Americas a Chinese firm handles from construction to operation, ~$4.3 billion. Viaduct and station works continued in 2025, passing 75% completion, with Qingdao-made driverless trains arriving by sea, targeting 2028 and over a million daily riders." },
  912: { descEn: "A line carrying southern Xinjiang clean power to Sichuan-Chongqing, 40+ TWh a year.", detailEn: "From Ruoqiang in Xinjiang via Qinghai to Mianyang in Sichuan, ~1,996 km; a cooperation deal among Xinjiang, Sichuan and Chongqing was signed in January 2026, with ~10% private capital sought in February, aiming for approval and start in 2026 and completion in 2028." },
  4218: { descEn: "The Middle East's largest refinery (615,000 b/d); SEG's first Kuwait turnkey project, full output 2024.", detailEn: "The Al-Zour refinery in southern Kuwait is the Middle East's largest, processing 615,000 b/d of crude. Sinopec Engineering (SEG), with Spanish and Hanwha partners, won a ~$4.24 billion turnkey contract (SEG ~40%, ~$1.696 billion), with units like Luoyang Engineering and No.5 Construction building the core; trial run in 2020, full output February 2024." },
  123: { descEn: "The world's largest integrated green hydrogen-ammonia-methanol project.", detailEn: "At Songyuan in Jilin, this plans 3 GW of renewables in phases producing ~800,000 tonnes/year of green synthetic ammonia and methanol; phase 1 started up in December 2025 — an important demonstration of scaled green hydrogen entering chemicals in China." },
  326: { descEn: "The core of JFK's $19 billion overhaul.", detailEn: "At ~$4.2 billion and ~112,000 m², serving ANA, Lufthansa, Cathay Pacific, JetBlue and 12+ airlines, the first six gates of the New Terminal One open in 2026 and the whole terminal completes in 2028." },
  362: { descEn: "East Africa's largest LNG project.", detailEn: "Led by Shell, Equinor and ExxonMobil, Tanzania LNG would use ~60 trillion cubic feet of deepwater Rovuma-basin gas for ~10 million tonnes/year at $42 billion total. A legal framework is targeted for H1 2026 with FID in 2028." },
  782: { descEn: "A 1.08 GW Scottish North Sea offshore wind farm, first power end-2026.", detailEn: "Off Scotland's east coast in the North Sea, Inch Cape (a Red Rock Renewables-ESB JV) is 1,080 MW; it reached financial close and started offshore works in early 2025, with the first giant monopiles delivered in October 2025, targeting first power by end-2026 and full operation in 2027." },
  804: { descEn: "New York's largest offshore wind under construction, restarting February 2026.", detailEn: "Off eastern New York, Orsted's wholly-owned Sunrise Wind (after buying Eversource's 50% in 2024) has 84 turbines and 924 MW; started in summer 2024 and ~45% done before a late-2025 stop order, a court ordered work to resume in February 2026, targeting 2027 to power ~600,000 homes." },
  1461: { descEn: "One of Central Asia's largest hydro plants; tripartite financing from 2026.", detailEn: "On the Naryn River in Kyrgyzstan, Kambarata-1 is 1,860 MW with a 256 m dam, 5.4 bcm reservoir and ~5.6 TWh a year, at ~$4.2 billion (Kyrgyzstan 34%, Uzbekistan and Kazakhstan 33% each). A ministerial deal was signed in June 2024, the EU and EIB pledged €900 million, and the three countries launch joint financing and construction in 2026 — a flagship for regional power security." },
  2501: { descEn: "A flagship Zambezi hydro plant jointly built by Zambia and Zimbabwe.", detailEn: "Below Victoria Falls on the Zambezi, this 2,400 MW plant (~1,200 MW each) is jointly built by Zambia and Zimbabwe; in late 2025 each pledged $220 million ($440 million total) to improve bankability, re-tendered as a PPP. Delayed by financing and tender disputes, it is in engineering studies and investor mobilisation, with main works not started by March 2026." },
  2703: { descEn: "A 1.6 GW wind cluster north of Juist in the German North Sea.", detailEn: "About 50 km north of Juist in the German North Sea, RWE leads a two-phase development — A (~660 MW, 2027) and B (~900 MW) — totalling 1.6 GW, one of Germany's largest recent offshore clusters, with large turbines and offshore substations supplying NRW industry." },
});

/* ===== 批次9：全库投资额 TOP（约 38–42 亿美元）===== */
Object.assign(window.ENERGY_EN, {
  2948: { descEn: "A 525 kV line from Las Vegas to Yerington connecting Nevada's north and south grids.", detailEn: "Greenlink Nevada's West line follows the US-95 corridor ~350 miles. EPC contractor MasTec has logged ~800,000 work-hours and ~150 towers; a section east of Beatty is delayed by test-range airspace limits, with the 120 kV portion of a substation online in October 2025." },
  3167: { descEn: "The world's first integrated wind-solar-storage base, with 1,680 MW closed-loop pumped hydro (~10.8 GWh).", detailEn: "Greenko's base at Pinnapuram in Kurnool, Andhra Pradesh is the world's first to integrate wind, solar and pumped hydro — ~3.5 GW of wind and solar plus 1,680 MW of closed-loop pumped hydro storing over 10,800 MWh, at ~$4.2 billion, with the pumped-hydro units coming online over 2025-2026 for multi-hour peaking." },
  3285: { descEn: "ONGC's MRPL drops refining expansion for ~$3.6-4.8 billion of petrochemicals.", detailEn: "MRPL, an ONGC subsidiary at Mangalore, Karnataka, has 15 million tonnes/year of refining and 905,000 tonnes of paraxylene. It cancelled a refining expansion in favour of ~$3.6-4.8 billion of new petrochemical units within 3-5 years, part of ONGC's plan to grow petrochemical capacity from 3.4 to 8 million tonnes by 2030." },
  3404: { descEn: "A 4.2 GW hydro plant on the upper Yellow River, aiming to start in the 15th Five-Year period.", detailEn: "On the Cihaxia reach of the Yellow River in Qinghai, with a normal pool level of 2,990 m and ~4.2 GW, this is one of the largest in the planned upper-Yellow-River cascade. Pre-feasibility and survey-design tenders launched in August 2025 with a land-use freeze notice issued, aiming for approval and start during the 15th Five-Year period." },
  3420: { descEn: "The world's largest wind-to-hydrogen green-methanol project, 500,000 t/year, first output October 2025.", detailEn: "In the Xing'an League development zone of Inner Mongolia, this pairs 2 GW of wind-to-hydrogen with corn-straw biomass carbon for 500,000 tonnes/year of green methanol at ~30 billion yuan. A 250,000-tonne phase 1 started up first, with phases 2-3 adding 13.1 billion yuan signed in October 2025 toward 1.45 million tonnes long term." },
  3421: { descEn: "A Songyuan 3 GW wind-solar plus 800,000-tonne green ammonia-methanol project, started September 2025.", detailEn: "At Songyuan in Jilin, using direct wind-solar supply, storage peaking, efficient electrolysis and dynamic synthesis, this plans 3 GW of renewables and 800,000 tonnes of green synthetic ammonia and methanol in phases — among the first large hydrogen-based-chemical demonstrations of 'Hydrogen-Powered Jilin', at ~29.6 billion yuan." },
  3455: { descEn: "A 15th-Five-Year HVDC carrying Ulan Buh desert-base power to Zhejiang.", detailEn: "From the Ulan Buh Desert base in Alxa, Inner Mongolia to Zhejiang, planned at ±800 kV and ~8 GW to export clean wind and solar; Inner Mongolia's 2026 plan lists the Ulan Buh-Zhejiang corridor as a project to approve as soon as possible." },
  3584: { descEn: "A 30-billion-yuan Maoming upgrade adding a million-tonne ethylene unit.", detailEn: "At Maoming in Guangdong, over 30 billion yuan retrofits refining without adding capacity, retiring the existing 360,000-tonne ethylene and building 1 million tonnes/year of ethylene plus downstream, using Sinopec's efficient low-energy cracking with 98.65% domestic equipment. Started in 2023, 59 of 112 main items are under way, targeting 2026-2027." },
  3586: { descEn: "A million-tonne ethylene at Tianjin Nangang, lifting Sinopec's Tianjin ethylene to 2.5 Mt.", detailEn: "In the Tianjin Nangang industrial zone, over 30 billion yuan builds a 1.2-million-tonne/year ethylene unit anchoring 13 plants (HDPE, LLDPE, alpha-olefins, UHMWPE). It started up successfully in November 2024, raising Sinopec's Tianjin ethylene to 2.5 million tonnes/year and pioneering ethylene-LNG cold-energy coupling, supplying 4 million tonnes of downstream feedstock a year." },
  3591: { descEn: "A 3,340 km gas trunkline from Wuqia to Zhongwei, fully online June 2025.", detailEn: "Running ~3,340 km from Wuqia in Xinjiang to Zhongwei in Ningxia, with 1,219 mm pipe and 15 bcm/year design capacity, this is another strategic Central Asia energy corridor after the West-East lines 1-3. Started in September 2023, the Xinjiang section came online in September 2024 and the Gansu-Ningxia section on 26 June 2025, completing the line; with the West-East lines 2-3 it lifts the network to 100 bcm/year." },
  1116: { descEn: "A new coastal high-speed line in the Shandong-Jiangsu section.", detailEn: "The Weisu high-speed railway runs ~399 km from Weifang North via Rizhao, Linyi and Xuzhou to Yanghe North in Suqian at 350 km/h. In 2025 the Jiangsu section's Grand Canal continuous beam and the 108.78 km Qingdao connection (23.7 billion yuan) advanced, with the Qingdao link fully girder-laid in August. Part of the national coastal corridor, it strengthens Shandong-Yangtze Delta links and fills a rail gap in southern Shandong and northern Jiangsu." },
  1121: { descEn: "The world's largest-span double-deck suspension bridge.", detailEn: "The Lion Ocean (Shiziyang) crossing runs ~35 km from Nansha in Guangzhou to Humen in Dongguan, double-deck with 16 lanes; its key Shiziyang Bridge crosses the river in a single 2,180 m main span, set to claim five world firsts (span, 342 m towers, 130 m anchorage diameter, 1.5 m main cable, lane count). Towers passed 200 m and the halfway point in 2025, with topping-out expected in 2026 — another mega-link across the Pearl River estuary in the Greater Bay Area." },
  101: { descEn: "Renewables for one of China's first desert-base export corridors.", detailEn: "In the Santanghu Gobi of Hami, Xinjiang, 10.2 GW of renewables (7 GW wind, 3 GW solar, 0.2 GW CSP) with 1.2 GW/4.8 GWh of storage is the first desert-base export-corridor renewable project, started in February 2024 and due fully online by end-2025, sending ~36 TWh of green power a year to Sichuan-Chongqing." },
  192: { descEn: "One of India's first competitively-bid HVDC links, exporting Gujarat renewables.", detailEn: "From the Khavda renewable base in Gujarat to Nagpur in Maharashtra, 1,200 km at ±800 kV/6,000 MW, built by a BHEL-Hitachi Energy consortium, targeting 2029." },
  541: { descEn: "Tencent's largest North China data-centre base, with China's first integrated wind-solar-storage microgrid.", detailEn: "Tencent's three campuses at Huailai in Hebei span ~1,050 mu, planned for ~1 million servers with over 71% green-power use; in 2024 it deployed China's first 'wind-solar-storage' data-centre microgrid — Tencent's core North China compute base." },
  1712: { descEn: "A second production system for the Atapu pre-salt field.", detailEn: "P-84 serves phase 2 of the Atapu field in the Santos Basin ~200 km off Rio in over 2,000 m of water, producing 225,000 b/d and processing 10 million m³/day of gas with ~30% lower per-barrel carbon. Bundled with P-85 in an $8.15 billion two-FPSO Seatrium contract, it started construction in Q1 2025 for first oil in 2029-2030." },
  4043: { descEn: "A flagship deep-water port on Bubiyan Island; a $4.1 billion CCCC EPC.", detailEn: "China Communications Construction signed the ~$4.1 billion (1.219 billion-dinar) phase-1 EPC for Mubarak Al-Kabeer Port on Bubiyan Island, Kuwait — ~1,161 hectares with eventually 24 berths and 8.1 million TEU a year, including quays, shore power and logistics. A Vision 2035 flagship, it is the first major Middle East port partly using Chinese standards." },
  4198: { descEn: "Tianqi holds ~22% of Chile's SQM, indirectly owning world-class Atacama lithium.", detailEn: "In 2018 Tianqi bought ~23.77% of SQM for $4.066 billion to become its second-largest shareholder, holding ~22% by early 2024 and ~21.90% (A shares) by early 2026. SQM operates the world's largest lithium resource at the Atacama salt flat; Chile's push for an SQM-Codelco public-private JV (effective from 2025) may affect Tianqi's returns." },
  289: { descEn: "Two new tranches totalling 1.2 GW after Singapore lifted its moratorium.", detailEn: "After lifting its 2019 data-centre moratorium, Singapore approved two tranches totalling 1.2 GW of hyperscale capacity, with AWS, Google and others cleared to expand, positioned as green, high-quality AI-load centres." },
  290: { descEn: "AWS's first South American (Chile) cloud region.", detailEn: "AWS is investing $4 billion in a three-availability-zone cloud region in Santiago, Chile, expected online by end-2026 for AI and machine learning — a milestone in AWS's Latin American digital-infrastructure push." },
  642: { descEn: "The world's largest underground copper mine adds its first open pit.", detailEn: "At Libertador in Chile, El Teniente is the world's largest underground copper mine, and Rajo Sur is its first open-pit supplement, begun in 2024 to offset declining underground grades toward 500,000+ tonnes a year. A July 2025 tunnel collapse cost 33,000 tonnes of copper, but construction continues." },
  785: { descEn: "A nearly 1 GW German Baltic project, permitted December 2025.", detailEn: "About 15 km north of the Fischland peninsula in the German Baltic, Skyborn Renewables' Gennaker is 976.5 MW with 63 15 MW-class turbines and ~4 TWh a year; it won a construction-and-operation permit in December 2025, with FID targeted for summer 2026 and operation in 2028 to power ~1 million people." },
  822: { descEn: "Phase 1 of Pakistan's largest planned hydro plant.", detailEn: "On the Indus in Khyber Pakhtunkhwa, Dasu is 2,160 MW in phase 1 (4,320 MW ultimately), with a $1.57 billion World Bank loan. Main-dam roller-compacted-concrete works start in Q2 2026, targeting power generation from late 2027, after repeated delays on terrain and security." },
  841: { descEn: "The UK's largest renewable power source; BECCS retrofit approved.", detailEn: "At Selby in North Yorkshire, Drax's four biomass units (~2.6 GW) provide ~4% of UK generation and ~9% of its renewable power. It won a record ~£1 billion biomass subsidy in 2025, and the government approved converting two units to BECCS (bioenergy with carbon capture and storage), able to capture ~8 million tonnes of CO₂ a year." },
  1010: { descEn: "The largest US battery plant, opened July 2025.", detailEn: "On a 300-acre site at the Astra business park in De Soto, Kansas, ~4.7 million sq ft, this is Panasonic's largest North American — and claimed world's largest — auto battery plant, making 2170 cylindrical cells with ~32 GWh planned rising to 59 GWh. It opened on 14 July 2025 with ~4,000 jobs at capacity, mainly for Tesla, a core local grid load, ramping to ~50% by early 2026 with a second wing under way." },
  1041: { descEn: "The first new US primary aluminium smelter in ~50 years, using low-carbon power.", detailEn: "Century Aluminum and the UAE's EGA are building the first new US primary aluminium smelter since 1980 at the Tulsa Port of Inola, Oklahoma — 750,000 tonnes a year, EGA 60% / Century 40%, with a $500 million DOE grant. Using dedicated low-carbon power for ~75% lower emissions, the JV was confirmed in January 2026, targeting a late-2026 start and end-of-decade production — a giant grid load." },
  1172: { descEn: "The first US deepwater floating LNG project.", detailEn: "Delfin Midstream's first US deepwater floating LNG export project off Louisiana uses existing subsea pipelines, planned as three FLNG vessels of ~4 million tonnes/year each. It won a MARAD deepwater-port licence in March 2025 and signed a first-vessel build letter of intent with Samsung Heavy in October, advancing toward FID." },
  1174: { descEn: "A Pacific-coast Mexican LNG export terminal.", detailEn: "Sempra is converting its existing import terminal at Ensenada, Mexico into an export terminal, with a ~3.25-million-tonne/year phase 1 for shorter-haul Asian markets. Over 95% complete by 2026 and in commissioning, satellite monitoring showed gas-in from April 2026 and flaring in May, with first LNG expected in 2026." },
  1219: { descEn: "A threefold expansion of a northeast Indian refinery.", detailEn: "At Numaligarh in Assam, NRL is raising refining from 3 to 9 million tonnes/year, with a 1,640 km crude pipeline from Paradip to Assam plus product lines. New units started up from the CDU in December 2025 and were ~85% complete by February 2026, greatly boosting northeast India's energy supply and refining self-sufficiency." },
  1297: { descEn: "A Sépia phase-2 FPSO, part of Seatrium's ~$8.2 billion two-vessel deal.", detailEn: "Petrobras and partners took FID on Sépia phase 2 in the Santos Basin pre-salt, building a fully electrified low-carbon FPSO of 225,000 b/d, part of the ~$8.2 billion two-FPSO Seatrium contract (with Atapu phase 2's P-85); construction began in Q1 2025 for delivery and start-up in 2029." },
  1298: { descEn: "An Atapu phase-2 FPSO with a fully electrified low-carbon design.", detailEn: "After FID on Atapu phase 2 in the Santos Basin pre-salt, this new FPSO produces 225,000 b/d and processes 10 million m³/day of gas, using full electrification, heat recovery and a closed flare. Part of the ~$8.2 billion two-FPSO Seatrium deal with Sépia phase 2's P-84, it started construction in Q1 2025 for 2029 delivery." },
  1305: { descEn: "A 355 km pre-salt gas pipeline from the Tupi field to Boaventura.", detailEn: "Petrobras's largest wholly-Brazilian-built gas pipeline, 355 km (307 km offshore, 48 km onshore) crossing 2,200 m of water from the Tupi field in the Santos Basin via Búzios north to the Boaventura plant at Itaboraí, carrying 18 million m³/day. The whole system came online in November 2024, with a second processing module in commercial operation in 2025." },
  1365: { descEn: "Abu Dhabi commits to 8 GW of battery storage.", detailEn: "In May 2026 Masdar and EWEC signed a framework to deploy 8 GW of battery storage in Abu Dhabi with 30 GW of solar, with a streamlined development process, supporting Abu Dhabi's 2035 target of 60% clean power — a further expansion after the 5.2 GW/19 GWh round-the-clock solar-plus-storage." },
  1376: { descEn: "Saudi Arabia's first full-process hydrogen-ready steel-plate mill.", detailEn: "BAP Al-Khair, a JV of China Baowu, Saudi Aramco and PIF (50:25:25) at Ras Al Khair Industrial City, uses gas-based direct reduced iron plus an electric arc furnace to make 1.5 million tonnes/year of heavy plate — Saudi Arabia's first full-process plate mill, with hydrogen-capable DRI for up to 90% future emissions cuts, at ~$4 billion." },
  1407: { descEn: "A Bahrain-Saudi road-and-rail causeway parallel to the King Fahd Causeway.", detailEn: "The King Hamad Causeway is a Bahrain-Saudi road-and-rail crossing at ~$4-5 billion with four road lanes and two rail tracks; a 57 km railway links a planned King Hamad station in Bahrain's Ramli area with the Dammam rail station, parallel to the existing King Fahd Causeway, on a 25-30-year PPP — a key link in GCC rail integration." },
  1427: { descEn: "An FCC and deep-conversion upgrade at the Basra refinery.", detailEn: "The Basra refinery (210,000 b/d) is being upgraded with a 34,500 b/d fluid catalytic cracker, 55,000 b/d vacuum distillation and 40,000 b/d diesel desulphurisation, lifting product output from 60,000 to 160,000 b/d. JGC builds it with Axens technology and JICA financing." },
  1526: { descEn: "A new Moscow metro line to the northwest suburbs.", detailEn: "The Rublyovo-Arkhangelskaya Line (Line 17), started in 2021, is 27.6 km with 12 stations from Moscow City across the MKAD toward Krasnogorsk. The first section, Delovoy Tsentr to Bulvar Generala Karbysheva (three new stations), is planned for 2026, with tunnels through and track and equipment being installed." },
  1555: { descEn: "A Far East coking-coal mine with Russia's longest private railway.", detailEn: "In Sakha (Yakutia), Elga produced 28.6 million tonnes of coal in 2024, targeting ~30-32 million in 2025 and 45 million after phase 2, served by the 531 km Pacific Railway (Russia's longest private railway) and Elga port. A second track began in April 2025, with 350 km built." },
  1628: { descEn: "Africa's longest crude pipeline; first export May 2024.", detailEn: "Led by CNPC and built by the China Petroleum Pipeline Bureau, the Niger-Benin crude export pipeline runs ~1,950 km from Niger's Agadem field to the Sèmè-Kraké offshore terminal in Benin at 90,000 b/d design — Africa's longest oil pipeline. Built over 2019-2023, it made its first export in May 2024 after China mediated a Niger-Benin border dispute; ~90% of Niger's oil exports depend on it." },
  1651: { descEn: "Europe's second-largest copper producer, targeting 500,000 t/year long term.", detailEn: "Comprising Zijin Bor Copper (63%) and the Timok (Čukaru Peki) copper-gold mine in Serbia. The upper zone started in 2021, producing 172,000 tonnes of copper and 5.18 tonnes of gold in 2025; total 2025 output of 296,000 tonnes of copper and 9.1 tonnes of gold ranks second in Europe. The lower zone, JM block caving and Bor upgrades advance, with a new plant targeted for June 2027 toward a long-term 500,000 tonnes a year to lead Europe." },
  1659: { descEn: "A ~28 billion-yuan deal to acquire three African gold mines in early 2026.", detailEn: "On 26 January 2026 Zijin Gold International announced the acquisition of all shares of Toronto/Nasdaq-listed Allied Gold at C$44 a share, ~28 billion yuan. Core assets include the producing Sadiola gold mine in Mali, the Bonikro and Agbaou complex in Côte d'Ivoire and Ethiopia's Kurmuk mine (due H2 2026); on completion Zijin Gold International will own 12 large gold mines in 12 countries." },
  1713: { descEn: "A second production system for the Sépia field.", detailEn: "P-85 serves Sépia phase 2 in the Santos Basin pre-salt in over 2,000 m of water, producing 225,000 b/d and processing 10 million m³/day of gas — among Brazil's most efficient FPSOs (30% lower per-barrel carbon). Built by Seatrium with P-84 (~$8.15 billion combined), its compression module is due in 2027 and first oil around 2030 — a main capacity addition in Petrobras's 2025-29 plan." },
  1750: { descEn: "An early-stage offshore wind project off Icaraí, Ceará.", detailEn: "Asa Branca off Icaraí in Ceará, 100% held by Eólica Brasil, is one of Brazil's earliest offshore wind environmental filings (2017), with a ~50-turbine first phase ~3 km offshore. It is in IBAMA's ~230+ GW pipeline, awaiting the first offshore auction; IBAMA plans dedicated guidelines and first permits in 2026." },
  1824: { descEn: "Brazil's third nuclear unit, awaiting a final decision on resumption.", detailEn: "Angra 3 is a 1,405 MW PWR, stalled for years. In October 2025 Eletronuclear submitted an updated techno-economic model to the CNPE; ~20-23 billion reais more is needed to finish. The government will decide on resumption or termination in mid-2026, with operation around 2031 if resumed, Tractebel leading the completion plan." },
  1836: { descEn: "An ~4,150 km east-west 56-inch gas trunkline expansion.", detailEn: "As phase 3 of the Master Gas System (an $8.8 billion 2023 deal), ~4,153 km of 56-inch east-west trunkline lifts network capacity to ~15.7 bcf/d (adding 0.315 bcf/d), extending in segments from EWPS-1 via Shedgum west to EWPS-10. Started in Q2 2024, it targets Q4 2028 to support gas-field output growth." },
  1838: { descEn: "A specialty-chemicals cluster at Jubail fed by Amiral feedstock.", detailEn: "Anchored by the Amiral complex (online 2027), this Jubail downstream park could unlock ~$4 billion of investment in carbon fibre, lubricants, drilling fluids, detergents, food additives, auto parts and tyres. INEOS will build a unit using Amiral propylene to make acrylonitrile (a carbon-fibre precursor); the investment ministry signed with SATORP in April 2026, with derivative units due 2027-2029." },
  2066: { descEn: "A West Java refinery upgrade with new petrochemical units.", detailEn: "The Balongan refinery (West Java) RDMP runs in three phases: phase 1 raised capacity to 150,000 b/d in 2022; phase 2 improves yields; phase 3 adds petrochemical units to cut imports, originally targeted around 2026. Indonesia's last large new refinery (1994), it is key to Pertamina cutting net petrochemical imports." },
  2098: { descEn: "A giant aluminium complex in Vietnam's Central Highlands.", detailEn: "In Lam Dong in Vietnam's Central Highlands, THACO plans ~50-103 trillion dong (~$4 billion) for 32,500 tonnes/year of beneficiation, 1.3 million tonnes of alumina and 300,000 tonnes of aluminium in three phases over ~10 years. Without formal investment approval by mid-2026, it aims for approval in 2026 and production in 2030." },
  2206: { descEn: "A trans-Mediterranean line carrying Egyptian green power to Europe.", detailEn: "The GREGY project would link Egypt with mainland Greece via a ~954 km HVDC subsea cable carrying up to 3,000 MW of renewable power, ~€3.57 billion (~$4 billion), driven by Greece's Copelouzos group with EU Global Gateway support. Added to the EU's PCI/PMI list in December 2025 with EU funding for studies, it targets FID by May 2028 and operation in 2031." },
  2254: { descEn: "Three new granulation lines at Jorf Lasfar plus a 4.2-million-tonne Mzinda complex.", detailEn: "Part of OCP's $13 billion green investment (2023-2027), this adds three 1-million-tonne granulation units at Jorf Lasfar and a 4.2-million-tonne new chemical complex at Mzinda, adding 8 million tonnes of fertiliser capacity by 2027, with desalination and green power, at $4.54 billion (2025), $5.25 billion (2026) and $4.25 billion (2027)." },
  2422: { descEn: "A $4 billion Kabaale refinery, 60,000 b/d, a UNOC-Alpha MBM JV.", detailEn: "At Kabaale in Hoima, Uganda, this ~$4 billion, 60,000 b/d refinery is a JV of Uganda's UNOC (40%) and the UAE's Alpha MBM Investments (60%), targeting 2028, also producing petrochemicals, fertiliser and gas. With Kabalega International Airport (~94% done) and the EACOP export pipeline, it forms an integrated Ugandan oil-and-gas hub." },
  2556: { descEn: "A strategic railway from the copper-cobalt belt to the Atlantic port of Lobito.", detailEn: "The Lobito Corridor links DR Congo's copper-cobalt belt via Zambia to the port of Lobito in Angola, with a ~315 km new spur in DRC tying into the Benguela railway. In December 2025 the Lobito Atlantic Railway won $553 million from the US DFC and $200 million from the DBSA, with ~$6 billion of total corridor investment (the US pledging $4 billion)." },
  2740: { descEn: "Google's major German data-centre investment through 2029.", detailEn: "Google announced ~€5.5 billion in Germany by 2029, building and expanding data centres (at Hanau and elsewhere) and cloud regions with renewable PPAs for German and European cloud and AI demand — one of its largest single-country investments in Europe." },
  2753: { descEn: "The Black Sea's largest gas development, a major new EU source.", detailEn: "In Romania's deep-water Black Sea EEZ, OMV Petrom and Romgaz develop ~100 bcm of recoverable gas peaking at ~10 bcm a year, at ~€4 billion — the largest Black Sea gas development, set to make Romania one of the EU's largest gas producers. Offshore drilling and completion advanced in 2025, targeting 2027." },
  2808: { descEn: "Europe's first NuScale small modular reactor project.", detailEn: "At the former Doicești coal plant in Romania, this uses US NuScale VOYGR SMRs (6×77 MW, 462 MW total) — Europe's first NuScale SMR project, advancing FEED and licensing in 2025, targeting around 2030." },
  2819: { descEn: "China's compact fusion experiment, due 2027.", detailEn: "On 'Science Island' in Hefei, Anhui, BEST (Burning Plasma Experimental Superconducting Tokamak) is China's next-generation compact fusion device; in 2025 it completed the 400-tonne cryostat base installation. Targeting 2027 completion and a fusion-power demonstration (lighting a bulb), it aims to lead global magnetic-confinement fusion engineering." },
  2828: { descEn: "The first US commercial non-light-water fast reactor, with molten-salt storage.", detailEn: "At a former coal plant in Kemmerer, Wyoming, Bill Gates's TerraPower is building the Natrium sodium-cooled fast reactor (345 MW) with molten-salt storage (briefly up to 500 MW). It won the NRC's first commercial non-light-water construction permit and broke ground in March 2026; Meta has contracted for up to eight Natrium units, leading the US advanced-nuclear revival." },
  2931: { descEn: "Holtec's twin SMR-300 units at the Palisades site, possibly among the first US SMRs.", detailEn: "Pioneer 1 and 2 are ~340 MW SMR-300 PWRs developed with Hyundai E&C and Mitsubishi Electric, with a $400 million DOE first-mover award. In January 2026 Holtec filed a partial construction permit with the NRC, planning site preparation after restarting and reconnecting Palisades, targeting the early 2030s." },
  3445: { descEn: "A national fusion research platform, fully built in 2025, supporting CFETR and BEST.", detailEn: "On Science Island in Hefei, Anhui, built by the CAS Hefei Institutes, Kuafu is the first major science facility of the Hefei comprehensive national science centre — the world's highest-parameter, most complete fusion research and test platform, providing key technology for the CFETR engineering reactor." },
  3453: { descEn: "A 15th-Five-Year HVDC carrying Kubuqi desert-base power to Jiangsu.", detailEn: "From the Kubuqi Desert base in Ordos, Inner Mongolia to the Jiangsu load centre, planned at ±800 kV and ~8 GW to support the Yangtze Delta; Inner Mongolia's 2026 plan lists it among export corridors to start as soon as possible." },
  3454: { descEn: "A 15th-Five-Year HVDC carrying Kubuqi desert-base power to Anhui.", detailEn: "From the Kubuqi Desert base in Inner Mongolia to Anhui, planned at ±800 kV and ~8 GW for the second Kubuqi desert-renewable export batch to East China; Inner Mongolia's 2026 plan lists it as a corridor to approve as soon as possible." },
  3457: { descEn: "China's largest 750 kV ring grid, around the Tarim Basin, fully closed July 2025.", detailEn: "Built over ~15 years from nine 750 kV transmission projects, with ~4,197 km of lines, nine substations and nearly 10,000 towers around five prefectures of southern Xinjiang. It closed the loop on 13 July 2025 with the Hotan-Minfeng-Qiemo-Ruoqiang section — China's largest 750 kV extra-high-voltage ring grid." },
  3575: { descEn: "Shanghai port's largest single automated terminal: 22 berths, 11.6 million TEU/year.", detailEn: "The Yangshan North zone builds 6,100 m of quay with seven 70,000-tonne and 15 20,000-tonne container berths, designed for 11.6 million TEU a year for sea-river and coastal feeder traffic, pioneering a caisson-breakwater foundation. Over 6 billion yuan was invested by end-2024 with 4+ billion more in 2025." },
  4224: { descEn: "Offshore compression for the world's largest gas field; a COOEC-Saipem win (>$800M share).", detailEn: "QatarEnergy's NFPS COMP5 is an offshore compression project for North Field production sustainability, with two compression platforms. COOEC and Italy's Saipem won the ~$4 billion EPCI as a consortium, with COOEC's share over $800 million and offshore installation in 2029-2030 over a ~5-year schedule." },
  4225: { descEn: "A Chinese firm's largest single Middle East offshore oil-and-gas contract; Qatar's Bul Hanine.", detailEn: "COOEC won the BH-EPIC1 and BH-EPIC2 lots of QatarEnergy's Bul Hanine field development, ~$4 billion (~28.6 billion yuan), covering subsea pipelines, cables and umbilicals and facilities — the largest offshore oil-and-gas contract a Chinese firm has won in the Middle East. The contract took effect in October 2025, due June 2031." },
  4295: { descEn: "A Chinalco-EGA 2-million-tonne alumina refinery in Boké, Guinea.", detailEn: "On 1 June 2024 Chinalco and the UAE's EGA signed a framework to develop an alumina refinery in Boké, Guinea, next to EGA's GAC bauxite and export facilities, designed for 2 million tonnes/year (1.2 million initially), targeting around September 2026 at ~$4 billion — a strategic tie-up between Chinalco and a Gulf aluminium major on Guinean bauxite value-add." },
  4380: { descEn: "Tianqi holds ~22% of SQM, whose Atacama lithium is being folded into an SQM-Codelco JV.", detailEn: "Tianqi bought ~23.8% of SQM for $4.1 billion in 2018 (now ~22%), indirectly holding Atacama salt-flat lithium. Over 2024-2025 Chile pushed an SQM-Codelco JV with Codelco controlling Atacama through 2060; Tianqi continues to contest governance and approvals as the ownership is restructured." },
  4387: { descEn: "A Huayou-led full mining-to-battery-recycling chain at the IPIP Pomalaa park, 20 GWh battery.", detailEn: "Huayou subsidiary HYD (Huayou 70%, EVE Energy and PT Daaz Bara Lestari 15% each) signed a framework with Indonesia's ANTAM and IBC to build a full chain at the IPIP park in Pomalaa, Kolaka, Southeast Sulawesi: 100,000 tonnes of pyrometallurgical plus 50,000 tonnes of hydrometallurgical nickel, 105,000 tonnes/year of precursor, 20 GWh of nickel batteries (7 GWh phase 1) and recycling — taking over the ~55.88 billion-yuan Indonesian battery-chain project an LG consortium exited." },
  903: { descEn: "China's first high-altitude UHV AC project, lifting the southwest grid to 1,000 kV.", detailEn: "In Sichuan-Chongqing, this builds four 1,000 kV substations (Garze, Tianfu South, Chengdu East, Tongliang) and 1,316 km of double-circuit lines with 24,000 MVA of capacity. It entered service on 27 December 2024, able to transmit up to 35 TWh a year to integrate southwest clean energy." },
  1200: { descEn: "A million-tonne ethylene at Yangpu, mid-completion July 2025.", detailEn: "In the Yangpu zone of Hainan, this Hainan-Sinopec project of over 28 billion yuan builds 1 million tonnes/year of ethylene plus a refining upgrade. On 2 July 2025 three main units (pygas hydrogenation, aromatics extraction, light-hydrocarbon recovery) and 14 supporting works reached mid-completion (>97% overall), entering start-up preparation; it would drive over 100 billion yuan of downstream industry for Hainan's free-trade port." },
  1211: { descEn: "Huainan coal-chemical phase 2, a 5.6-million-tonne methanol-to-olefins chain.", detailEn: "In the Huainan modern coal-chemical park, Anhui, built by Zhong'an United (a JV of Sinopec's Great Wall Energy & Chemical and Wanbei Coal-Electricity). Phase-1 1.7-million-tonne MTO runs steadily; phase 2's first stage builds 5.6 million tonnes/year of coal-to-methanol, 1.48 million tonnes of MTO and downstream for 2.77 million tonnes/year of PE, PP, EVA, SAP and other products. The methanol-distillation EPC was won by Hualu Engineering (227 million yuan) in July 2025." },
  2673: { descEn: "A high-grade FMG magnetite mine, 22 million tonnes of concentrate a year.", detailEn: "In the Pilbara of WA, the FMG-Formosa Plastics JV magnetite project makes ~22 million tonnes a year of high-grade (67%) magnetite concentrate at ~$3.9 billion, with first concentrate in 2023 and ramp-up through 2025, supplying higher-grade feed better suited to green steel." },
  1195: { descEn: "The UK's largest undeveloped oilfield, facing environmental litigation.", detailEn: "About 130 km northwest of Shetland, Rosebank is the UK's largest undeveloped oilfield, ~300 million barrels recoverable. In January 2025 an Edinburgh court ruled the original approval failed to assess downstream emissions and must be re-consented, but allowed construction to continue meanwhile. Equinor and Ithaca have invested over £2.2 billion and awarded many supply contracts, targeting 2026-2027 — a focus of the UK's North Sea oil-and-climate debate." },
  1615: { descEn: "State Grid's third UHVDC concession, Brazil's largest-ever transmission concession.", detailEn: "After Belo Monte phases 1 and 2, State Grid independently won a third ±800 kV UHVDC with a 30-year concession — 1,468 km of new line, converter stations at both ends and AC works, 5 GW rated, through Maranhão, Tocantins and Goiás to mainly supply the capital Brasília. China Electric Power Equipment supplies and builds it, targeting 2029." },
  2657: { descEn: "An offshore gas field backfilling Darwin LNG; first gas 2025.", detailEn: "About 300 km north of Darwin in the Northern Territory, Santos-led Barossa uses an FPSO and subsea pipeline to backfill the Darwin LNG plant, ~3.7 million tonnes/year of LNG at full capacity. First production gas came in October 2025, moving from construction to start-up — an important northern Australian gas source." },
});

/* ===== 批次10：全库投资额 TOP（约 32–38 亿美元）===== */
Object.assign(window.ENERGY_EN, {
  2720: { descEn: "Connecting Sicily, Sardinia and the mainland, setting a deepest-cable record.", detailEn: "Terna's bipolar HVDC subsea cable links Sicily, Sardinia and mainland Italy, ~970 km and 1,000 MW. In December 2025 Nexans completed laying 500 kV cable at 2,150 m depth — a world HVDC-cable depth record — with converter stations due by end-2028, boosting Mediterranean grid resilience and renewable integration." },
  3204: { descEn: "A JSW-JFE 50/50 JV adding 6 million tonnes at the Odisha Bhushan (BPSL) plant.", detailEn: "JSW Steel and Japan's JFE Steel formed a 50/50 JV (~320 billion rupees) to expand the Bhushan Power and Steel (BPSL) plant at Sambalpur, Odisha by 6 million tonnes/year — from ~4.5 to over 10 million tonnes — creating a large integrated steel hub in eastern India, with the JV signed on 24 April 2026." },
  3278: { descEn: "A Visakhapatnam refinery upgrade to 15 million tonnes/year.", detailEn: "HPCL's ~314 billion-rupee VRMP raises the Visakh refinery from 8.33 to 15 million tonnes/year, commissioning a 3.55-million-tonne residue upgrader in 2025 (the world's first LC-Max residue hydrocracker) that converts ~93% of residue into high-value products, with plans for 18 million tonnes within 3-4 years and 10,000 tonnes/year of SAF from 2027." },
  3452: { descEn: "A 15th-Five-Year HVDC carrying Gansu Hexi renewables to Sichuan.", detailEn: "From the Wuwei area of Gansu to inland Sichuan, planned at ±800 kV and 8 GW, bundling Hexi desert wind, solar and supporting thermal power for Sichuan-Chongqing; Gansu government documents aim for a 2025 start and source-grid completion mid-15th-Five-Year." },
  3500: { descEn: "A 12-inch automotive specialty-process phase 2 in Lingang, Shanghai, to 50,000 wafers/month.", detailEn: "JuTai Semiconductor's specialty-process line (35.9 billion yuan in two phases) has a ~27 billion-yuan phase 2 expanding 12-inch specialty processes to 50,000 wafers/month for automotive analog, power and display-driver chips; registered capital rose to 16.9 billion yuan with lithography tools installed." },
  4058: { descEn: "East Africa's flagship Mombasa-Nairobi standard-gauge railway, built and operated by CRBC.", detailEn: "China Road and Bridge built and operates Kenya's 472 km Mombasa-Nairobi standard-gauge railway, linking East Africa's largest port-city with the capital using Chinese standards, technology and management. Since opening in 2017 operations have improved (2023 passenger revenue +11.7%, freight +7.3%) — a Belt and Road flagship in East Africa." },
  402: { descEn: "The last large undeveloped coalfield in the Shanxi-Shaanxi-Inner Mongolia core.", detailEn: "In Ejin Horo Banner, Ordos, Inner Mongolia, this is the only undeveloped large coalfield in the Jin-Shaan-Meng core, ~15.3 billion tonnes of reserves, with two 8-million-tonne mines (16 million total) at 26.5 billion yuan, started in 2024 and due in 2029." },
  1203: { descEn: "China's first alpha-olefin park, completing by end-2025.", detailEn: "In the Xuwei New Area of Lianyungang, Jiangsu, this is China's first integrated alpha-olefin high-end-materials park at ~26.6 billion yuan. Phase 1 (~12.15 billion yuan) has two 100,000-tonne alpha-olefin and 900,000-tonne polyethylene units, started in June 2024, completing through end-2025 for early-2026 start-up; phase 2 adds three alpha-olefin and three 200,000-tonne POE units by end-2026, filling China's high-end polyolefin-elastomer gap." },
  1684: { descEn: "GEM's nickel core base in Indonesia, with multiple units online in 2025.", detailEn: "QMB at IMIP in Morowali, Sulawesi, is 55%-controlled by GEM with Tsingshan, Brunp (CATL), ECOPRO, Hanwa and Yibin Libao, ~$3.7 billion cumulative, with 150,000 tonnes/year of MHP nickel, 30,000 tonnes of electro-nickel, 50,000 tonnes of high-nickel precursor and 30,000 tonnes of cathode. Electro-nickel started in September 2025 and cathode in December, with Q3 nickel shipments near 36,000 tonnes." },
  1781: { descEn: "A new metro line linking Guarulhos with central São Paulo.", detailEn: "Line 19 runs 17.6 km from Bosque Maia in Guarulhos to Anhangabaú in central São Paulo with 15 stations, serving over 630,000 riders a day at ~20 billion reais. Using three large-diameter TBMs (including Brazil's first EPB+slurry dual-mode), excavating 5.7 million m³, with civil works in three lots, it targets a 2026 start and 2032 completion." },
  2084: { descEn: "The world's largest single-line copper smelter.", detailEn: "At the JIIPE industrial port in Gresik, East Java, this processes 1.7 million tonnes of copper concentrate for ~650,000 tonnes of cathode copper a year plus gold and silver. Commissioned in June 2024, damaged by an October 2024 fire and restarted in May 2025, it ramped to full capacity within 2025, anchoring Indonesia's copper downstream chain." },
  3296: { descEn: "Sinopec's 200,000 b/d export refinery at Hambantota, Sri Lanka's largest-ever FDI.", detailEn: "Sinopec plans a 200,000 b/d (~10-million-tonne/year) refinery at Hambantota at ~$3.7 billion, mostly for export — Sri Lanka's largest-ever FDI. After years of talks, an October 2025 Sinopec visit reached consensus to start immediately, with Sri Lanka raising the local-sales share to 40% to clear the main obstacle." },
  152: { descEn: "Taiwan's largest offshore wind under construction off Changhua, supplying TSMC.", detailEn: "Greater Changhua 2b (337 MW) and 4 (582 MW) total 920 MW off Changhua, with FID in 2023, offshore works from February 2025 and ~DKK 20 billion of financing in July; all power is contracted to TSMC under a long-term PPA, targeting full grid connection in 2026." },
  284: { descEn: "A hyperscale liquid-cooled AI data centre in Melbourne.", detailEn: "On a new site in northwest Melbourne, over 354 MW and over $3.6 billion, this uses liquid cooling for dense AI loads — a core project of AirTrunk's Australian expansion." },
  546: { descEn: "Shanghai Lingang's largest operator-grade compute centre.", detailEn: "China Telecom's Lingang phase 2 plans ~25 billion yuan for a ~300,000 m² supercompute centre supporting 300,000 GPUs ultimately; in March 2024 it delivered and commercialised China's first single-pool 10,000-GPU domestic liquid-cooled cluster, supporting trillion-parameter model training from 2025." },
  1163: { descEn: "Penang's first light rail, linking George Town and the airport area.", detailEn: "The Mutiara Line is Penang's first LRT, ~29.5 km with 22 stations running north-south along George Town's east coast to Jelutong, Sungai Nibong and the Bayan Lepas airport area, with a ~5 km sea bridge to Penang Sentral on the mainland, later extending to Silicon Island. PM Anwar broke ground on 11 January 2025 with main works from late July, at up to RM16 billion, targeting December 2031." },
  1232: { descEn: "Pecém's most advanced green-hydrogen project, with preliminary permits.", detailEn: "At the Pecém industrial port zone in Ceará, this phased project (phases 1-2 1,200 MW, phase 3 900 MW) would produce 168,000 tonnes of green hydrogen a year (using 2.1 GW of renewables), equivalent to ~946,000 tonnes of green ammonia for export. Conceptual engineering is done and a pre-contract signed with Pecém port." },
  2995: { descEn: "A 100 GWh 4680 cell and first Semi plant at the Sparks gigafactory.", detailEn: "In early 2025 Tesla confirmed ~$3.6 billion to expand its Nevada Gigafactory with a 100 GWh 4680 cell plant and its first high-volume Semi electric-truck plant, adding ~4 million sq ft. 4680 yields rose sharply in mid-2025, with over $330 million of Nevada tax incentives." },
  2996: { descEn: "Canada's first large battery plant, in production November 2025, pivoting to grid storage.", detailEn: "NextStar (formerly an LG-Stellantis JV) at Windsor, Ontario is Canada's first large battery plant, ~4.23 million sq ft and 49.5 GWh. Series production began in November 2025 with over a million cells made; it now makes only stationary-storage cells, with LG buying Stellantis's stake in early 2026 after Stellantis exited." },
  3192: { descEn: "India's first domestic semiconductor assembly-and-test (OSAT) mega-plant, at Jagiroad, Assam.", detailEn: "Tata Semiconductor Assembly & Test is investing ~2.7 trillion rupees in India's first domestic OSAT plant at Jagiroad in Morigaon, Assam, making 48 million chips a day at capacity using wire-bonding, flip-chip and home-grown ISP for automotive, EV and communications, creating ~15,000 direct jobs, with first lines due in 2026." },
  3426: { descEn: "China's first Hualong One base with a cooling tower; main works started November 2025.", detailEn: "At Zhangxing in Zhaoyuan, Yantai, Shandong, CGN-controlled, this plans six Hualong One units with two in phase 1, using a 203 m high-position natural-draft cooling tower to switch the conventional-island cooling source from sea to air — a Hualong One first in China; unit 1 was approved by the State Council in August 2024." },
  3428: { descEn: "CGN's Lufeng CAP1000 Gen-III phase 1, twin units started in 2025.", detailEn: "At Tianweishan in Jieshi, Lufeng, Shanwei, Guangdong, on the east shore of Jieshi Bay, the base plans six MW-class units (5-6 Hualong One); phase-1 units 1-2 use CAP1000 passive Gen-III technology, approved by the State Council in August 2024." },
  3429: { descEn: "SPIC's first nuclear plant in Guangxi, main works started late 2024.", detailEn: "At the southern tip of the Jiangshan Peninsula in Fangchenggang, Guangxi, SPIC plans two CAP1000 plus four Guohe One units totalling 8.62 GW; phase 1 builds the CAP1000s, approved by the State Council in August 2024." },
  3431: { descEn: "CGN's Fangchenggang Hongsha Hualong One phase 3, fully launched May 2025.", detailEn: "At the Hongsha base in Fangchenggang, Guangxi, CGN-controlled, phases 1-2's four units are in commercial operation; phase 3 builds Hualong One units 5-6 at 1.208 GW each (~20 TWh a year combined), approved by the State Council in April 2025." },
  3432: { descEn: "Taishan (home of the first EPR) switches to Hualong One for phase 2, approved April 2025.", detailEn: "At Yaogu in Chixi, Taishan, Jiangmen, Guangdong — where Taishan phase 1 is the world's first EPR — phase-2 units 3-4 use Hualong One at 1,200 MW each; CGN bought Taishan Second Nuclear for 1.2 billion yuan in January 2025." },
  3433: { descEn: "CGN's Huizhou Taipingling Hualong One demonstration base phase 2; unit 3 started June 2025.", detailEn: "At Longzi in Huangbu, Huidong, Huizhou, Guangdong, on the northwest shore of Honghai Bay, this is one of China's first Hualong One fusion demonstration bases, planned for six units; phase-2 units 3-4 are 1,209 MW each with over 95% domestic equipment, approved in December 2023." },
  3437: { descEn: "The largest China-Russia nuclear project; Xudabao Russian Gen-III units, online 2027-2028.", detailEn: "At Xudapu in Xingcheng, Huludao, Liaoning, developed by CNNC Liaoning, units 3-4 use Russian VVER-1200/V491 reactors at 1.2 GW each; construction was witnessed by Xi Jinping and Putin via video in May 2021." },
  3447: { descEn: "China's candidate first inland nuclear plant, with signs of renewed activity in 2025-26.", detailEn: "At Heyeshan in Zhanxi, Taojiang, Yiyang, Hunan, controlled by CNNC with China Yangtze Power and others, the site is planned for 4 GW (2 GW phase 1). Inland nuclear awaits a national policy go-ahead, with the project company maintaining the site and preparatory work." },
  3448: { descEn: "An expansion of the Huaneng Shidao Bay base with Hualong One; unit 2 started May 2025.", detailEn: "At Shidao Bay in Rongcheng, Weihai, Shandong (also home to a high-temperature-gas-reactor demonstration), developed by Huaneng, expansion phase 1 units 1-2 use Hualong One at 1.2 GW each, distinct from the existing Gen-IV HTGR demonstration." },
  3451: { descEn: "Reserved units 7-8 at the Haiyang base, tied to long-term cross-region nuclear heating.", detailEn: "At Haiyang in Yantai, Shandong, SPIC's Shandong Nuclear plans six MW-class units plus an integrated small reactor, with the site reserved for expansion units 7-8; Haiyang is also China's largest nuclear district-heating source." },
  1637: { descEn: "Peru's largest distribution utility, controlled and operated.", detailEn: "In 2020 Three Gorges-controlled China Yangtze Power acquired 83.6% of Peru's largest distributor Luz del Sur for ~$3.59 billion, serving 1.3 million-plus customers (~30% of Peru's regulated distribution). It has expanded into renewables — two Arequipa solar plants (44 MW, 2023) and two Ica wind farms (129 MW, 2024) — forming an integrated hydro-wind-solar clean distribution-and-retail system." },
  110: { descEn: "The world's tallest dam under construction (315 m rockfill).", detailEn: "On the upper Dadu River in Aba, Sichuan, Shuangjiangkou's 315 m rockfill dam is the world's tallest under construction, with 2 GW and a 1.9 bcm regulating reservoir. First impoundment finished in May 2025 and the first stator was lifted in November, targeting first units by end-2025." },
  141: { descEn: "Germany's largest North Sea offshore wind farm.", detailEn: "At 913 MW with 83 11 MW turbines, this Ørsted-Nuveen JV first connected in December 2025 with full operation in Q1 2026, pioneering a 66 kV direct-connect converter platform (no offshore substation), with 786 MW of corporate PPAs signed by Amazon, BASF and Google." },
  146: { descEn: "The largest clean-energy project for Connecticut and Rhode Island.", detailEn: "About 40 km off Massachusetts, Revolution Wind's 65 11 MW turbines total 704 MW; it began supplying the New England grid on 13 March 2026 after a late-2025 federal stop and legal battle, powering ~350,000 homes." },
  246: { descEn: "A GM-Samsung SDI battery plant in Indiana.", detailEn: "At New Carlisle, Indiana, the GM-Samsung SDI JV starts at 27 GWh expanding to 36 GWh with 1,600+ jobs; construction slowed on a design change in late 2025 but it still targets production before end-2027." },
  583: { descEn: "Microsoft building a data-centre cluster at three sites around Cologne.", detailEn: "Under a €3.2 billion German AI-and-cloud plan, Microsoft is building simultaneously at Bergheim, Bedburg and Elsdorf industrial parks in North Rhine-Westphalia, breaking ground at Bergheim in March 2026, all water-free cooled, coming online over 2026-2027." },
  1016: { descEn: "A French low-carbon battery plant, inaugurated December 2025.", detailEn: "French battery start-up Verkor's first low-carbon gigafactory at Bourbourg in Dunkirk was built in ~2 years; it starts at 16 GWh (50 GWh planned by 2030), mainly for the Renault Alpine A390, creating ~1,200 direct and 3,000 indirect jobs with over €3 billion raised — a landmark of French battery sovereignty, inaugurated before Macron on 11 December 2025." },
  1490: { descEn: "Seven new EV and auto-electronics plants in Kaliningrad.", detailEn: "Avtotor in Kaliningrad is building seven plants under an investment plan (~285 billion roubles) for EV and auto-electronics production, with a home-designed compact EV at 50,000 vehicles/year and deeply localised motors, inverters, gearboxes, controllers and batteries, while assembling Chinese brands like BAIC and SWM." },
  1638: { descEn: "Three Gorges is the largest shareholder of Portugal's EDP.", detailEn: "In 2011 Three Gorges took a 21.35% stake in Portugal's EDP for ~€2.7 billion, later raised to ~23.27% as the long-time largest single shareholder, deeply tied to its renewables arm EDPR's global wind and solar (~19.3 GW of renewables by end-2024, +3.8 GW that year) — the core of Three Gorges' strategic European holdings." },
  1688: { descEn: "Johor's largest LEED-certified hyperscale campus, directly linked to Singapore.", detailEn: "DayOne (formerly GDS International) is building a flagship hyperscale AI campus at Nusajaya Tech Park in Iskandar, Johor; with the Kempas campus, operating and under-construction capacity exceeds 478 MW toward 500 MW. In June 2025 it raised RM1.5 billion (~$3.5 billion) of dual-currency green Islamic financing — among Asia-Pacific's largest data-centre syndications — with a 500 MW CRESS green-power deal with TNB and over RM8.1 billion invested in Malaysia since 2022." },
  1714: { descEn: "A new platform reviving the Campos Basin Marlim field, tendered on a BOT basis.", detailEn: "P-86 serves the revitalization of the old Marlim Sul/Marlim Leste fields in the Campos Basin, producing ~180,000 b/d on a BOT model, with a tender invitation issued in 2024. Part of Petrobras's Campos revitalization (Marlim/Albacora/Barracuda, ~$22 billion through 2028), it targets around 2031." },
  1743: { descEn: "A gigawatt-scale green-ammonia export hub at the Port of Açu, Rio.", detailEn: "In early 2025 the UK's Yamna and the Port of Açu signed a 3 km² land-reservation deal for 1 million tonnes/year of green ammonia needing ~1.8 GW of electrolysers. Açu is Brazil's largest private deep-water port industrial zone, handling ~40% of national oil exports; FID is targeted for 2027 and first green molecules in 2030, mainly for Europe." },
  1966: { descEn: "Malaysia's largest-ever solar tender.", detailEn: "Malaysia's Energy Commission launched its fifth large-scale solar tender (LSS PETRA) at 2 GW (over twice the prior round), awarded in 2024 at an average RM0.1699/kWh. With LSS5+ and LSS6, ~RM15-18 billion of contracts will come over two years — the country's largest solar rollout — with local developers like Cypark, Malakoff, Solarvest and Sunview, connecting around 2026." },
  2017: { descEn: "VinFast's flagship vehicle base, targeting 950,000 units in 2026.", detailEn: "VinFast's 335-hectare vehicle complex in the Cat Hai Dinh Vu zone, Hai Phong, in production since 2019, is its flagship base targeting 950,000 vehicles/year in 2026; with a second Ha Tinh plant (~$231 million, 200,000 phase 1, online June 2025, 400,000 by 2027) it drives the group's million-vehicle goal." },
  2043: { descEn: "Vietnam's largest planned data centre, $3.5 billion and 300 MW in three phases.", detailEn: "Vietnam's largest private firm Vingroup signed an MoU with the UAE's Benya Technologies to invest $3.5 billion in a hyperscale data centre developed in three phases totalling 300 MW. Signed at a Vietnam-UAE business forum during PM Pham Minh Chinh's UAE visit, it would be one of Vietnam's largest data-centre projects, with a site to be decided." },
  2218: { descEn: "A $3.5 billion industrial cluster in the Suez Canal Economic Zone.", detailEn: "At the Ain Sokhna industrial zone in Egypt's Suez Canal Economic Zone, three projects totalling $3.5 billion are landing from a Kemet Industries-Al Qalaa Red Flag (UAE-China) agreement, including a 250,000-tonne/year seamless-steel-pipe plant to meet infrastructure demand and cut imports — a flagship of SCZONE's drive to build a manufacturing hub." },
  2304: { descEn: "A planned African-largest methanol and fertiliser complex on Brass Island, Bayelsa.", detailEn: "At Odioama on Brass Island in Bayelsa State, Nigeria, this would be Africa's largest methanol plant at up to 10,000 tonnes/day, a JV including Shell, TotalEnergies and Eni. A gas-supply deal of ~270 million cubic feet/day is signed, at ~$3.5 billion." },
  2462: { descEn: "One of the first gas plants in South Africa's IPP programme.", detailEn: "Nersa approved Eskom's 3,000 MW gas plant at Richards Bay, among the first in the IPP gas-procurement programme, with South Africa's first LNG import terminal (a phase-1 floating storage unit and onshore regasification, ~400 million scf/d). Environmental groups successfully challenged the EIA, forcing a re-do; LNG phase-1 FID is expected in 2026 and operation in 2028." },
  2994: { descEn: "Integrated cathode and anode materials at Camp Hall, with recycling from late 2025.", detailEn: "Redwood Materials is investing ~$3.5 billion in a battery-recycling, refining and cathode/anode-materials plant at Camp Hall in Berkeley County, South Carolina, planning 100 GWh/year of cathode active material and anode copper foil, reaching 100 GWh capacity by late 2025 and 500 GWh by 2030, partnering with Toyota, Ford and Panasonic." },
  3019: { descEn: "Rebuilding Newark's 2.5-mile automated people mover, serving the new Terminal A.", detailEn: "A 2.5-mile replacement of the aging AirTrain links terminals, parking, rail and rental cars, raising daily capacity from 33,000 to 50,000 and connecting directly to the new Terminal A. Tutor Perini won a $1.2 billion contract in 2024, with works from October 2025 and passengers expected in 2030." },
  3297: { descEn: "Bangladesh expanding the Eastern Refinery at Chittagong, adding 3 million tonnes to 4.5 million.", detailEn: "Eastern Refinery phase 2 (ERL modernisation and expansion) at Chittagong would add 3 million tonnes/year to reach 4.5 million making Euro-5 fuels, at ~429.7 billion taka; after failing to attract foreign investors, it shifted to government self-funding to keep 51% control, targeting 2030." },
  3414: { descEn: "Guangxi's first subsidy-free offshore wind demonstration, full capacity 2025, extending to Qinzhou deep-sea.", detailEn: "The A and F sites off Fangchenggang total 1.8 GW at ~24.5 billion yuan — China's first fully rock-socketed, zero-subsidy grid-parity offshore wind; the A site reached full capacity on 7 February 2025. Guangxi's 14th Five-Year aims to approve and start 7.5 GW, with Qinzhou deep-sea preparation advancing." },
  4044: { descEn: "A smart deep-water gateway to South America, built by CCCC's Fourth Harbor.", detailEn: "Built by a China Harbour-CCCC Fourth Harbor consortium for COSCO Shipping-controlled investment, Chancay Port in Huaral, Peru has four berths, breakwaters, yards and shore power, designed initially for 1 million TEU, 6 million tonnes of bulk and 160,000 vehicles a year. It opened on 14 November 2024 — a new gateway for China-South America trade and the first smart deep-water port." },
  4398: { descEn: "HQC's role in Hengyi's PMB phase-1 refinery (8 million tonnes/year) in Brunei.", detailEn: "Hengyi (Brunei) PMB on Pulau Muara Besar has a phase-1 design of 8 million tonnes/year of crude, making gasoline, diesel, jet fuel and paraxylene, at ~$3.45 billion, started in November 2019 — China's largest investment in Brunei. HQC took part in the design and engineering, with phase 2 (14-million-tonne refining + ethylene) advancing to extend downstream chemicals." },
  917: { descEn: "A clean-energy export line from the Qinghai-Tibet plateau to Guangxi.", detailEn: "Using ±800 kV UHV flexible HVDC from Qinghai to Guangxi, ~36.5 TWh a year; site leveling and corridor planning were done by end-2025, with feasibility and approval expected to advance in 2026." },
  1373: { descEn: "Saudi Arabia's first car plant, EV CKD/CBU.", detailEn: "At King Abdullah Economic City (KAEC) north of Jeddah, this is Saudi Arabia's first car-assembly plant and Lucid's first overseas factory; phase 1 reassembles Lucid Air kits (~5,000/year), shifting to full manufacturing toward 155,000 vehicles a year. PIF is the main shareholder, with ~$3.4 billion of Saudi government incentives and purchase commitments." },
  1534: { descEn: "Central Asia's first large gas-to-liquids plant, at full capacity in 2025.", detailEn: "The Uzbekistan GTL plant near Shurtan in Kashkadarya, using Sasol technology, started in 2021 and reached full design capacity in 2025, processing 3.6 bcm of gas a year for ~1.5 million tonnes of synthetic liquid fuels — over 307,000 tonnes of jet fuel, 724,000 tonnes of diesel, 437,000 tonnes of naphtha and 53,000 tonnes of LPG — Central Asia's first large GTL." },
  3271: { descEn: "Dhaka Metro Line 5 North, JICA-financed, started late 2023.", detailEn: "MRT-5 North began on 4 November 2023 at ~412.4 billion taka with JICA financing, targeting 2028; the ~17.2 km southern line would have a ~$4.5 billion package (ADB $3 billion, Korea $1.5 billion)." },
  911: { descEn: "A line carrying Badain Jaran desert-base clean power to Sichuan.", detailEn: "From the Badain Jaran desert renewable base in Jiuquan, Gansu to Ziyang in Sichuan, ~1,436 km and 8 GW rated; ~10% of equity opened to private firms in February 2026, with approval and start expected in 2026 and completion in 2028." },
  1119: { descEn: "The world's largest-span suspension bridge under construction.", detailEn: "The Zhangjinggao Yangtze River Bridge links Zhangjiagang, Jingjiang and Rugao, 7,859 m with a 2,300 m main span — mainland China's first suspension span over 2,000 m, with six world firsts and six world records. Works sped up in 2025 (south tower past 200 m in March, north tower closed to millimetre precision in December), with the world's largest diaphragm-wall anchorage due mid-2026; started in 2022, targeting 2028." },
  191: { descEn: "A new corridor exporting Brazil's northeast renewables to the central-south.", detailEn: "Linking Maranhão and Goiás via Tocantins, ~1,500 km and 4 GW, won in a 2023 national-grid auction; started on 30 June 2025 for 2029 completion to relieve large-scale northeast wind and solar." },
  944: { descEn: "A DC corridor from North Rhine to Baden-Württemberg, built on a retired nuclear site.", detailEn: "Ultranet runs 342 km linking North Rhine-Westphalia and Baden-Württemberg, with a converter station on the former Philippsburg nuclear site — Germany's first to convert a retired nuclear site into a DC converter station. Full planning approval came in October 2025, targeting operation by end-2026." },
  945: { descEn: "A DC corridor from Emden to North Rhine, carrying North Sea wind to the Ruhr.", detailEn: "A-Nord runs ~305 km from Emden in Lower Saxony to Osterath; Sumitomo Electric won a €500 million-plus cable contract, with 525 kV DC underground cable laying launched in July 2025, targeting 2027." },
  1166: { descEn: "New Zealand's largest-ever transport project, twin-track tunnels under the city.", detailEn: "The City Rail Link is New Zealand's largest transport project, a pair of 3.45 km twin tunnels linking the rebuilt Waitematā (Britomart) and Maungawhau (Mount Eden) stations plus two new underground stations (Te Waihorotiu and Karangahape), doubling Auckland's rail capacity. The first test train ran on 13 February 2025, with construction and testing due by end-June 2026 and public service in H2 2026." },
  1207: { descEn: "Coal-to-polyolefins phase 2 in Yulin, mid-completion and commissioning in 2026.", detailEn: "In the Yushen industrial zone of Yulin, Shaanxi, China Coal Shaanxi Energy & Chemical's project (~23.888 billion yuan) builds 2.2 million tonnes/year of methanol and 900,000 tonnes of polyolefins plus a phase-1 upgrade and a 250,000-tonne LDPE/EVA chain. ~53% complete by September 2025 with long-lead equipment in place, targeting mid-completion and start-up in 2026." },
  1632: { descEn: "Three Gorges' largest overseas acquisition, Brazil's second-largest private power firm.", detailEn: "In 2015 Three Gorges Brazil won 30-year concessions for the Jupiá (1,551 MW) and Ilha Solteira (3,444 MW) cascade hydro plants for ~23.4 billion yuan — its largest overseas acquisition. It controls and operates them, undertaking a ~10-year upgrade of 22 units; the first two batches of 12 upgraded units are complete and in commercial operation, anchoring its position as a clean-power backbone in southeast Brazil." },
  2264: { descEn: "Sonelgaz's first 3 GW of solar across 12 provinces and 20 plants.", detailEn: "Algeria's Sonelgaz is advancing the first 3,000-3,200 MW of solar (toward 15 GW by 2035) across 20 projects in 12 provinces under 19 contracts. First plants came online in 2025 (Tendla 200 MW in El Meghaier, El Ghrous 200 MW in Biskra), with winners including CSCEC (300 MW), Turkey's Ozgun (300 MW) and Cosider+Fimer (250 MW), built in two years with local-content rules." },
  2617: { descEn: "An 840 km North Queensland artery linking Townsville and Mount Isa.", detailEn: "Built by Powerlink, CopperString first builds ~840 km of new line from Townsville to Mount Isa, tying into a North Queensland mining and renewables corridor — one of Australia's largest new grid projects. The eastern section targets pre-2032, with the A$225 million Flinders substation winning infrastructure approval to start in December 2025." },
  3263: { descEn: "Chennai's second airport, a greenfield at Parandur, ~274 billion rupees.", detailEn: "Parandur airport is ~274 billion rupees, one of south India's largest aviation projects, needing 3,331.25 acres (~1,700 acquired by 2025), with phase 1 due late 2029/early 2030, though land-acquisition protests in villages like Ekanapuram continue." },
  3269: { descEn: "A ~169 km Dhaka-Jashore railway via the Padma Bridge, built by CRCC.", detailEn: "Linking Dhaka and Jashore over ~169 km (Dhaka-Gandaria, Gandaria-Mawa, Mawa-Bhanga, Bhanga-Jashore), at ~374 billion taka with a ~210.4 billion-taka China Exim Bank loan, built by China Railway Construction; the 82 km Dhaka-Bhanga section is already open." },
  3470: { descEn: "A Sichuan Panxi clean-energy export and Sichuan-Yunnan grid-strengthening project, approved 2025.", detailEn: "In Liangshan, Sichuan, this builds two 1,000 kV UHV AC substations and 1,006 km of 1,000 kV AC lines, approved by Sichuan's NDRC in October 2025 with construction by year-end, strengthening Panxi hydro-wind-solar export and the Sichuan-Chongqing main grid." },
  4220: { descEn: "An NGL fractionation plant for the Jafurah gas field; an SEG-Técnicas Reunidas win.", detailEn: "The Riyas NGL project serves Aramco's Jafurah unconventional gas field with 2×36,000 t/d of NGL fractionation. Sinopec Engineering (SEG) and Spain's Técnicas Reunidas formed a JV, signing over $3.3 billion of contracts in early 2024 (P1/P2 EPC ~$1.173 billion), with No.5 Construction handling mechanical-electrical installation — among the Middle East's largest single contracts." },
  151: { descEn: "The world's largest solar-plus-storage project under construction.", detailEn: "Spanning ~3,500 hectares in Bulacan and Nueva Ecija, the Philippines, this plans 3.5 GW of solar with 4.5 GWh of storage; phase 1 was unveiled in November 2024 and 1,288 MW was grid-connected by January 2026, making it the Philippines' largest operating solar plant, and the world's largest single solar-plus-storage project once complete." },
  292: { descEn: "Microsoft's largest single digital-infrastructure commitment in Spain.", detailEn: "Microsoft is investing €2.9 billion in a hyperscale data-centre campus at Zaragoza, Spain, part of its European AI-infrastructure expansion, powered by local renewables, with construction in 2025." },
  780: { descEn: "Scotland's largest offshore wind farm, fully operational April 2025.", detailEn: "In the Moray Firth off northeast Scotland, 60 Siemens Gamesa 14.7 MW turbines total 882 MW, operated by the EDPR-Engie JV Ocean Winds; first power came in July 2024 and full capacity in April 2025, covering about half of Scottish households." },
});

